INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-44021', 'gcn', 'GRB 260310A', '2026-03-15T16:12:58.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":18.5,"other_measurements":{"observation_band":"clear","observation_date":"2026-03-14.80913 UT","telescope_diameter":0.3,"telescope_focal_ratio":4},"ra":null,"redshift":null,"tables":[{"JD":2461114.30913,"UT":"2026-03-14.80913","m_CV":18.5,"m_CV_error":0.04}]},"authors":{"affiliations":["ABObservatory Rosarno","Università della Calabria","INAF - Osservatorio Astronomico di Palermo","INAF - Osservatorio Astronomico di Brera","INAF - Osservatorio Astronomico di Capodimonte","Osservatorio \"G. Galilei\", Liceo Scientifico Cariati"],"authors":["A. Brosio","M. A. Tripodi","S. Savaglio","S. Benatti","M. G. Guarcello","M. Basilicata","L. Cabona","M. Rainer","F. M. Zerbi","G. Bracco","P. Cianfarra","L. Sangaletti","S. Tosi","S. Zappatore","A. Di Dato","D. Liguori","S. Masiero","A. Nastasi","R. Nesci","L. Betti","E. Pace","R. Stanga","D. Ricci"],"institutions":["ABObservatory Rosarno","INAF - Osservatorio Astronomico di Palermo","INAF - Osservatorio Astronomico di Brera","INAF - Osservatorio Astronomico di Padova","Associazione Astronomica Antares APS di Foligno","GAL Hassin, Isnello"],"universities":["Università della Calabria","Università di Genova","Università di Firenze","INAF - Osservatorio Astronomico di Capodimonte","Osservatorio \"G. Galilei\", Liceo Scientifico Cariati"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["ABObservatory"],"telescopes":["0.30-m f/4 telescope at ABObservatory"]},"urls":[],"basic_data":{"author":{"email":"antonino.brosio@gmail.com","institution":"ABObservatory Rosarno","name":"A. Brosio"},"coordinates":{},"detectionTime":"1926-03-15T16:12:58.000Z","event":"GRB 260310A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 44021\nSUBJECT: GRB 260310A / AT2026fgk: ABObservatory and NOCTIS optical observations\nDATE: 26/03/15 16:12:58 GMT\nFROM: A. Brosio at ABObservatory Rosarno <antonino.brosio@gmail.com>\n\nA. Brosio (ABObservatory Rosarno), M. A. Tripodi (ABObservatory Rosarno), S. Savaglio (Università della Calabria), S. Benatti, M. G. Guarcello (INAF - Osservatorio Astronomico di Palermo), M. Basilicata, L. Cabona, M. Rainer, F. M. Zerbi (INAF - Osservatorio Astronomico di Brera), G. Bracco, P. Cianfarra, L. Sangaletti, S. Tosi, S. Zappatore (Università di Genova), A. Di Dato (INAF - Osservatorio Astronomico di Capodimonte), D. Liguori (Osservatorio \"G. Galilei\", Liceo Scientifico Cariati), S. Masiero, A. Nastasi (GAL Hassin, Isnello), R. Nesci (Associazione Astronomica Antares APS di Foligno), L. Betti, E. Pace, R. Stanga (Università di Firenze), D. Ricci (INAF - Osservatorio Astronomico di Padova) for the NOCTIS team report\n\nWe observed the transient AT 2026fgk, proposed as the likely optical counterpart of GRB 260310A (Konno et al., GCN 43974; Hamburg & Meegan,GCN 43975).\n\nObservations were carried out on 2026-03-14.80913 UT with the 0.30-m f/4 telescope at ABObservatory in clear band\n\nThe obtained photometry is:\n\n2026-03-14.80913 UT   JD 2461114.30913   m_CV = 18.50 +/- 0.04 mag\n\nThe measurement was calibrated against two APASS catalog stars,selected using Aladin. The reported magnitude is in the CV system.\n\nThis measurement confirms that the optical counterpart is still clearly detected about 4.6 days after the GRB trigger."}', 'A group of astronomers, including those from ABObservatory Rosarno and NOCTIS team, observed the optical counterpart of GRB 260310A (AT2026fgk) four days after the gamma-ray burst using a 0.30-m telescope. The obtained magnitude was 18.5, confirming the counterpart''s continued detection.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6728', 'gcn', 'GRB 070809', '2007-08-09T19:48:41.000Z', '{"measurements":{"dec":-22.134,"distance":null,"duration":2,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"UVOT Exposure Time":400,"UVOT Filter":"V","UVOT Observation Start Time":"19:23:42 UT","XRT Observation Start Time":"19:23:28 UT"},"ra":203.782,"redshift":null,"tables":[{"column_name":"RA","value":203.782},{"column_name":"Dec","value":-22.134},{"column_name":"Duration","value":2},{"column_name":"Peak Count Rate","value":2500},{"column_name":"Energy Range","value":"15-350 keV"},{"column_name":"XRT RA","value":203.7708},{"column_name":"XRT Dec","value":-22.1408},{"column_name":"XRT Uncertainty","value":4},{"column_name":"Distance from BAT Position","value":44.7}]},"authors":{"affiliations":["NASA/GSFC","PSU","PSU","NASA/UMBC","NASA/ORAU","CRESST/GSFC/USRA","Univ Bicocca&INAF-OAB","CRESST/GSFC/USRA","PSU","U Leicester","LANL","Univ. Bicocca & INAF-OAB","NASA/ORAU","GSFC/ISAS"],"authors":["F. E. Marshall","D. N. Burrows","M. M. Chester","J. R. Cummings","P. A. Evans","N. Gehrels","C. Guidorzi","S. T. Holland","J. A. Kennea","K. L. Page","D. M. Palmer","P. Romano","T. Sakamoto","G. Sato","B. Sbarufatti","M. Stamatikos","R. L. C. Starling"],"institutions":["NASA/UMBC","NASA/ORAU","CRESST/GSFC/USRA","INAF-IASFPA"],"universities":["PSU","U Leicester","NASA/GSFC","Univ Bicocca","INAF-OAB","USRA","ISAS"]},"telescopes":{"facilities":[],"instruments":["BAT"],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"palmer@lanl.gov","institution":"LANL","name":"David Palmer"},"coordinates":{"dec":2.0010505555555556},"detectionTime":"2007-08-09T19:48:41.000Z","event":"GRB 070809","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6728\nSUBJECT: GRB 070809: Swift detection of a short burst\nDATE: 07/08/09 19:48:41 GMT\nFROM: David Palmer at LANL  <palmer@lanl.gov>\n\nF. E. Marshall (NASA/GSFC), D. N. Burrows (PSU), M. M. Chester (PSU),\nJ. R. Cummings (NASA/UMBC), P. A. Evans (U Leicester),\nN. Gehrels (NASA/GSFC), C. Guidorzi (Univ Bicocca&INAF-OAB),\nS. T. Holland (CRESST/GSFC/USRA), J. A. Kennea (PSU),\nK. L. Page (U Leicester), D. M. Palmer (LANL),\nP. Romano (Univ. Bicocca & INAF-OAB), T. Sakamoto (NASA/ORAU),\nG. Sato (GSFC/ISAS), B. Sbarufatti (INAF-IASFPA),\nM. Stamatikos (NASA/ORAU) and R. L. C. Starling (U Leicester) report\non behalf of the Swift Team:\n\nAt 19:22:17 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 070809 (trigger=287344).  Swift slewed immediately to the burst. \nThe BAT on-board calculated location is \nRA, Dec 203.782, -22.134 which is \n   RA(J2000) = 13h 35m 08s\n   Dec(J2000) = -22d 08'' 01\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  The BAT light curve showed a single peak\nstructure with a duration of about 2 sec.  The peak count rate\nwas ~2500 counts/sec (15-350 keV), at ~0 sec after the trigger. \nIt is currently unclear from the spectral data if this is a short \nhard burst. \n\nThe XRT began observing the field at 19:23:28 UT, 71 seconds after the\nBAT trigger. Using prompt downlinked data, we found a fading X-ray source\nlocated at RA, Dec 203.7708, -22.1408 which is equivalent to\n   RA(J2000)  =  13h 35m 04.99s\n   Dec(J2000) = -22d 08'' 26.2\"\nwith an uncertainty of 4.0 arcseconds (radius, 90% containment). \nThis location is 44.7 arcseconds from the BAT on-board position,\ninside the BAT error circle. \n\nUVOT took a finding chart exposure of nominal 400 seconds with the V\nfilter starting 74 seconds after the BAT trigger. However, the 8''x8''\nregion for the list of sources generated on-board does not cover the\nground-generated XRT error circle, so no statement can be made\nregarding an optical counterpart. \n\nBurst Advocate for this burst is F. E. Marshall (marshall AT milkyway.gsfc.nasa.gov). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift satellite detected a short gamma-ray burst, GRB 070809, with a duration of approximately 2 seconds and a peak count rate of 2500 counts/sec in the 15-350 keV energy range. The X-ray Telescope (XRT) located a fading X-ray source 44.7 arcseconds from the BAT position, and the Ultraviolet/Optical Telescope (UVOT) began observing the field but did not find an optical counterpart. The exact nature of this burst, whether it is a short hard burst, is currently unclear.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6727', 'gcn', 'GRB 070808', '2007-08-09T16:43:13.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":[20.6,20.5],"other_measurements":{},"ra":null,"redshift":null,"tables":[{"Exposure(s)":960,"Filter":"R","M_lim":20.6,"Tstart(min)":2.35,"Tstop(min)":62.9},{"Exposure(s)":700,"Filter":"i''","M_lim":20.5,"Tstart(min)":5.55,"Tstop(min)":53.4}]},"authors":{"affiliations":["Liverpool JMU","Uni-Bicocca/INAF-OAB","Liverpool JMU"],"authors":["A. Melandri","C. Guidorzi","R.J. Smith","I.A. Steele","C.G. Mundell","M.J. Burgdorf","C.J. Mottram","M.F. Bode","S.N. Fraser","S. Kobayashi","D.F. Bersier","A. Gomboc","P. O''Brien","E. Rol","N. Bannister","N. Tanvir"],"institutions":["Liverpool John Moores U","Uni-Bicocca/INAF-OAB"],"universities":["Liverpool JMU","Uni-Bicocca","INAF-OAB"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Faulkes Telescope South"]},"urls":["https://gcn.gsfc.nasa.gov/gcn/gcn3_batch.msf?6718"],"basic_data":{"author":{"email":"axm@astro.livjm.ac.uk","institution":"Liverpool John Moores U","name":"Andrea Melandri"},"coordinates":{},"detectionTime":"2007-08-09T16:43:13.000Z","event":"GRB 070808","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6727\nSUBJECT: GRB 070808 : Faulkes Telescope South Observations\nDATE: 07/08/09 16:43:13 GMT\nFROM: Andrea Melandri at Liverpool John Moores U  <axm@astro.livjm.ac.uk>\n\nA. Melandri, (Liverpool JMU), C. Guidorzi (Uni-Bicocca/INAF-OAB),\nR.J. Smith, I.A. Steele, C.G. Mundell, M.J. Burgdorf, C.J. Mottram,\nM.F. Bode, S.N. Fraser, S. Kobayashi, D.F. Bersier (Liverpool JMU),\nA. Gomboc (Ljubljana), P. O''Brien, E. Rol, N. Bannister, N. Tanvir\n(U. Leicester) report on behalf of larger GRB collaboration :\n\n\nOn 2007 Aug 08 at 18:30:21 UT the Faulkes Telescope South automatically\nobserved the field of GRB 070808 (trigger=287260, Cummings et al.,\nGCN 6718).\n\nOn our coadded frames we do not detect any source inside the refined\nXRT error circle (Starling et al., GCN 6725) down to a limiting\nmagnitude of\n\n\nFilter  Tstart(min)  Tstop(min)    Exposure(s)   M_lim\n---------------------------------------------------------\n   R       2.35          62.9          960         20.6\n   i''      5.55          53.4          700         20.5\n---------------------------------------------------------\n\nMagnitudes are calibrated with respect to USNOB1 R2 in the R filter.\nFor the SDSS-i'' filter we used the magnitude derived from the\npre-burst calibration field of Cool et al. (GCN 6720)."}', 'The Faulkes Telescope South team reports non-detection of a source within the error circle of GRB 070808, with limiting magnitudes of 20.6 in the R filter and 20.5 in the i'' filter.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6726', 'gcn', 'GCN Swift XRT update position notices and enhanced position circulars', '2007-08-09T12:32:42.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"accuracy_time":{"unit":"hours","value":"2-3 hours"},"improvement_time":{"unit":"minutes","value":"15 minutes"},"position_error_radius":{"unit":"arcseconds","value":"<3.9\""}},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["U Leicester"],"authors":["J. P. Osborne","M. R. Goad","P. A. Evans","A. P. Beardmore","L. G. Tyler","D. N. Burrows","N. Gehrels","S. D. Barthelmy"],"institutions":["Swift Team","GSFC","PSU"],"universities":["U. of Leicester"]},"telescopes":{"facilities":["GSFC","PSU"],"instruments":["Swift XRT","UVOT"],"observatories":[],"telescopes":[]},"urls":["<http://www.swift.ac.uk/xrtpos.php>","http://www.swift.ac.uk/xrt_positions/index.php","http://www.swift.ac.uk/spertable.php","http://www.swift.ac.uk/xrt_positions/Goad.pdf","<http://www.swift.ac.uk/spertable.php>","<http://www.swift.ac.uk/xrt_positions/index.php>","http://www.swift.ac.uk/xrtpos.php","<http://gcn.gsfc.nasa.gov/gcn/sock_pkt_def_doc.html>","http://gcn.gsfc.nasa.gov/gcn/sock_pkt_def_doc.html","<http://www.swift.ac.uk/xrt_positions/Goad.pdf>"],"basic_data":{"author":{"email":"julo@star.le.ac.uk","institution":"U.of Leicester","name":"Julian Osborne"},"coordinates":{},"detectionTime":"2007-08-09T12:32:42.000Z","event":"GCN Swift XRT update position notices and enhanced position circulars","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6726\nSUBJECT: GCN Swift XRT update position notices and enhanced position circulars\nDATE: 07/08/09 12:32:42 GMT\nFROM: Julian Osborne at U.of Leicester  <julo@star.le.ac.uk>\n\nJ. P. Osborne (U Leicester), M. R. Goad (U Leicester), P. A. Evans (U \nLeicester), A. P. Beardmore (U Leicester), L. G. Tyler (U Leicester),\nD. N. Burrows (PSU), N. Gehrels (GSFC) and S. D. Barthelmy (GSFC), report on \nbehalf of the Swift Team:\n\nThe Swift XRT team will from now be providing better positions earlier for \nmost GRBs by automatically issuing: 1) an early position update notice \nbased on ground processing; 2) a circular giving an enhanced XRT position \nand error derived from a rectification of the UVOT field with USNO B1. See \nhttp://www.swift.ac.uk/xrtpos.php.\n\n1) Position Update Notices\n\nGCN Swift XRT position update notices will soon be routinely distributed.\nThe position and error will be based upon fully automated ground processing\nof SPER data (TDRSS-downlinked Single Pixel Event Report data in Photon\nCounting mode), fit using a PSF model with the dead columns to give a\nmore reliable position than is possible on-board. This position update notice\nwill typically be sent within 15 minutes of the start of the XRT observation.\nRobotic telescopes may want to adapt their reaction strategy.\n\nSPER data come only during the first snap-shot observation of a burst,\nit is distributed to the XRT team at ~5 minute intervals; the notice will be \ngenerated from the combined first and second SPER datasets, as this offers the \nbest position improvement for the shortest delay (notice distribution will be \nforced if a second SPER is not received within 9 minutes of the first).  If this \nis not the first XRT_Position notice for a burst then the notice UPDATE_FLAG \nkeyword is set, the email subject line will have ''UPDATE'' added, and in the \npackets to socket sites the 2^25 bit will be set in the PKT_MISC field \n(http://gcn.gsfc.nasa.gov/gcn/sock_pkt_def_doc.html).\n\nSubsequent SPER data may allow further improvement of the early position \ninformation. This will not be distributed by GCN notice, but will be \nimmediately available at http://www.swift.ac.uk/spertable.php.  A link from that \npage describes the derivation of positions from SPER data in detail.  Over 80% \nof bursts can have a position derived in this way; for these, the 90% position \nerror radius is <3.9\" half of the time.\n\n2) Enhanced Position Circulars\n\nGCN Swift XRT position circulars will soon be routinely distributed when a \nfirst UVOT-enhanced XRT position becomes available.  Use of the XRT-UVOT \nboresight alignment and the UVOT-USNO B1 astrometric registration for the \nbursts simultaneously covered by the XRT PC mode and UVOT V band gives more \nprecise and accurate XRT positions than those based on star tracker data \npreviously distributed.  Around 60% of XRT bursts can have their positions \nimproved by this method; such UVOT-enhanced XRT burst positions have a 90% \nconfidence error radius <2.1\" half of the time, and are typically available \nwithin 2-3 hours of the burst (Goad et al. A&A submitted, arXiv:0708.0986,\nhttp://www.swift.ac.uk/xrt_positions/Goad.pdf).  These rapidly available \nenhanced positions have an accuracy comparable to that obtainable in one to \nseveral days using serendipitous X-ray sources (eg Butler AJ 133, 1027, 2007).\n\nImprovement of a UVOT-enhanced XRT position is possible as more data become \navailable after the initial enhanced position circular.  Such subsequently \nimproved positions will not be announced via the GCN but will be immediately \navailable at http://www.swift.ac.uk/xrt_positions/index.php\n\nIt is not yet possible to enhance a larger fraction of positions due to the \nneed for simultaneous V band and XRT PC mode data when Swift is still and for \nat least 10 XRT counts. We hope to improve this in the future."}', 'Astronomical alert: GCN Swift XRT update position notices and enhanced position circulars', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6725', 'gcn', 'GRB 070808', '2007-08-09T06:15:49.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null},"authors":{"affiliations":["U. Leicester","NASA/UMBC"],"authors":["R. Starling","J.R. Cummings"],"institutions":["U of Leicester","NASA/UMBC"],"universities":["University of Leicester"]},"telescopes":{"facilities":[],"instruments":["Swift XRT","UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"rlcs1@star.le.ac.uk","institution":"U of Leicester","name":"Rhaana Starling"},"coordinates":{},"detectionTime":"2007-08-09T06:15:49.000Z","event":"GRB 070808","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6725\nSUBJECT: GRB 070808: Swift XRT refined analysis\nDATE: 07/08/09 06:15:49 GMT\nFROM: Rhaana Starling at U of Leicester  <rlcs1@star.le.ac.uk>\n\nR. Starling (U. Leicester) and J.R. Cummings (NASA/UMBC) report on behalf of \nthe Swift XRT team:\n\nWe have analysed the first orbit and part of the second orbit of Swift XRT\ndata for GRB 070808 (trigger=287260; Cummings et al., GCN Circ. 6718),\ncovering 114-7500 s since BAT trigger.\n\nUsing 799 s of overlapping XRT Photon Counting mode and UVOT V-band\ndata, we find an astrometrically corrected X-ray position (using the\nXRT-UVOT alignment and matching UVOT field sources to the USNO-B1 catalogue): \nRA, Dec (J2000) = 6.76402, 1.17635 deg, which is equivalent to:\nRA (J2000):  00h 27m 3.36s\nDec (J2000): +01d 10'' 34.8''''\nwith an uncertainty of 1.9 arcsec (radius, 90% confidence).\nThis is 4.7 arcsec from the initial XRT position (GCN Circ. 6718) and 16.7 \narcsec from the BAT refined position (Fenimore et al. 2007, GCN Circ. 6724).\n\nThe 0.3-10 keV lightcurve shows a smooth and somewhat curved decay, which can\nbe modelled with a broken power law with alpha_1=3.5 +0.7/-0.2, T_bk=234 \n+13/-20 s and alpha_2=1.06 +0.1/-0.08.\n\nThe PC mode spectrum from 500-7500 s since trigger can be modelled with an\nabsorbed power law with photon index Gamma=2.8 +/-0.5, and \nnH=(1.2 +0.5/-0.3)E22 cm^-2 in excess of the Galactic column of 3E20 \ncm^-2. The 0.3-10 keV observed (unabsorbed) flux is 2.4E-12 (1.0E-11) \nerg/cm^2/s corresponding to a count rate of 4.5E-2 count/s and a count \nrate to flux conversion of 1 count/s = 5E-11 erg/cm^2/s.\n\nAssuming the X-ray emission continues to decay with alpha=1.06, we predict a\ncount rate at T+24h of 9E-4 count/s.\n\nThis circular is an official product of the Swift XRT team."}', 'Astronomers from the University of Leicester and NASA/UMBC have refined the analysis of Swift XRT data for GRB 070808, finding a more accurate X-ray position and modeling the light curve and spectrum. The X-ray position is now determined to be (RA, Dec) = (00h 27m 3.36s, +01d 10'' 34.8'''') with an uncertainty of 1.9 arcsec. The 0.3-10 keV light curve is modeled with a broken power law, and the spectrum is modeled with an absorbed power law. The team predicts a count rate at T+24 hours of 9E-4 count/s.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6724', 'gcn', 'GRB 070808', '2007-08-09T03:38:55.000Z', '{"measurements":{"dec":"1d 10'' 47\"","distance":null,"duration":"32 +- 3 sec","energy":null,"fluence":"1.2 +- 0.1 x 10^-06 erg/cm2","magnitude":null,"other_measurements":{"peak_photon_flux":"2.0 +- 0.2 ph/cm2/sec","power_law_index":"1.47 +- 0.14"},"ra":"0h 27m 2.6s","redshift":null,"tables":[]},"authors":{"affiliations":["LANL","GSFC/Swift","GSFC","GSFC/UMBC","GSFC","GSFC/USRA","GSFC/UMD","LANL","GSFC","GSFC/ORAU","GSFC/ISAS","GSFC/ORAU","GSFC","GWU"],"authors":["E. Fenimore","L. Barbier","S. D. Barthelmy","J. Cummings","N. Gehrels","H. Krimm","C. Markwardt","D. Palmer","A. Parsons","T. Sakamoto","G. Sato","M. Stamatikos","J. Tueller","T. Ukwatta"],"institutions":["LANL","GSFC"],"universities":["UMBC","UMD","ISAS","GWU"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://milkyway.gsfc.nasa.gov"],"basic_data":{"author":{"email":"jayc@milkyway.gsfc.nasa.gov","institution":"NASA/GSFC/Swift","name":"Jay R. Cummings"},"coordinates":{},"detectionTime":"2007-08-09T03:38:55.000Z","event":"GRB 070808","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6724\nSUBJECT: GRB 070808, Swift-BAT refined analysis\nDATE: 07/08/09 03:38:55 GMT\nFROM: Jay R. Cummings at NASA/GSFC/Swift  <jayc@milkyway.gsfc.nasa.gov>\n\nE. Fenimore (LANL), L. Barbier (GSFC), S. D. Barthelmy (GSFC),\nJ. Cummings (GSFC/UMBC), N. Gehrels (GSFC), H. Krimm (GSFC/USRA), \nC. Markwardt (GSFC/UMD), D. Palmer (LANL), A. Parsons (GSFC),\nT. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS), M. Stamatikos (GSFC/ORAU),\nJ. Tueller (GSFC), T. Ukwatta (GWU)\n \nUsing the data set from T-120 to T+218 sec from the recent telemetry \ndownlink, we report further analysis of BAT GRB 070808 (trigger #287260)\n(Cummings, et al., GCN Circ. 6718).  The BAT ground-calculated position \nis RA, Dec = 6.761, 1.180 deg which is \n   RA(J2000) = 0h 27m 2.6s \n   Dec(J2000) = 1d 10'' 47\" \nwith an uncertainty of 1.2 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 47%.\n \nThe burst had a single FRED peak. T90 (15-350 keV) was 32 +- 3 sec \n(estimated error including systematics).\n \nThe time-averaged spectrum from T-0.7 to T+41.4 sec is best fit by a \nsimple power-law model.  The power law index of the time-averaged \nspectrum is 1.47 +- 0.14.  The fluence in the 15-150 keV band was \n1.2 +- 0.1 x 10^-06 erg/cm2. The 1-sec peak photon flux measured from \nT+0.73 sec in the 15-150 keV band was 2.0 +- 0.2 ph/cm2/sec.  All the \nquoted errors are at the 90% confidence level."}', 'Astronomers have refined their analysis of gamma-ray burst GRB 070808, reporting a single FRED peak with a duration of 32 seconds +- 3 seconds and a time-averaged power-law index of 1.47 +- 0.14. The fluence in the 15-150 keV band was 1.2 +- 0.1 x 10^-06 erg/cm2, and the 1-sec peak photon flux was 2.0 +- 0.2 ph/cm2/sec.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6723', 'gcn', 'GRB 070808', '2007-08-09T00:17:11.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":22,"other_measurements":{"observation_start_time":"2007-08-08 21:45:35 UT","time_since_burst":"3.3h"},"ra":null,"redshift":null,"tables":[{"R-limit":"22.0","t-t_0 (mid-exp)":"13229s","t_exp":"2700s"}]},"authors":{"affiliations":["MPE Garching, FORTH, Heraklion, NCAC, Torun"],"authors":["A. Stefanescu, S. Duscha, G. Kanbach, F. Schrey, A. Slowikowska, H. Steinle"],"institutions":["University of Crete, MPE, FORTH, Heraklion, NCAC, Torun"],"universities":["University of Crete"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["University of Crete, 1.3m Skinakas Observatory"],"telescopes":["1.3m Skinakas Observatory"]},"urls":[],"basic_data":{"author":{"email":"astefan@mpe.mpg.de","institution":"MPE","name":"Alexander Stefanescu"},"coordinates":{},"detectionTime":"2007-08-09T00:17:11.000Z","event":"GRB 070808","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6723\nSUBJECT: GRB 070808: OPTIMA-Burst optical upper limit\nDATE: 07/08/09 00:17:11 GMT\nFROM: Alexander Stefanescu at MPE  <astefan@mpe.mpg.de>\n\nA. Stefanescu (1), S. Duscha (1), G. Kanbach (1), F. Schrey (1), A.\nSlowikowska (2)(3), H. Steinle (1) ((1)=MPE Garching, (2)=FORTH,\nHeraklion (3)=NCAC, Torun) of the OPTIMA-Burst Team report the following:\n\nOPTIMA-Burst at the 1.3m Skinakas Observatory, of the University of\nCrete, Greece observed the location of the XRT error-circle of GRB\n070808 (GCN Circ 6718, J. R. Cummings et al.), starting at 2007-08-08\n21:45:35 UT (3.3h after the burst).\n\nWe did not detect any source inside the XRT error-circle in 3 co-added\n900s exposures in R-filter.\n\nOur limit is as follows:\n\nt-t_0 (mid-exp)       t_exp     R-limit\n13229s (i.e. 3.7h)    2700s     22.0"}', 'The OPTIMA-Burst team at the University of Crete''s 1.3m Skinakas Observatory did not detect any optical source within the X-ray error circle of GRB 070808, 3.3 hours after the burst. Their limit in the R-filter is a magnitude of 22.0 after 2700 seconds of exposure.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6722', 'gcn', 'GRB 070808', '2007-08-08T20:20:33.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":19.7,"other_measurements":{"mean_observation_time":"~330s","observation_duration":"115s","observation_start_time":"18:29:55"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["NAOC","EAFON"],"authors":["W.K. Zheng","Y.Q. Lou","X.F. Wang","L.P. Xin","M.Zhai","Y.L. Qiu","J.Y. Wei","J.Y. Hu","J.S. Deng","Y. Urata"],"institutions":["NAOC","EAFON"],"universities":["NAOC","BAO"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Xinglong TNT 80cm"]},"urls":[],"basic_data":{"author":{"email":"zwk@bao.ac.cn","institution":"NAOC","name":"W.K. Zheng"},"coordinates":{},"detectionTime":"2007-08-08T20:20:33.000Z","event":"GRB 070808","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6722\nSUBJECT: GRB 070808: Xinglong TNT optical Upper Limit\nDATE: 07/08/08 20:20:33 GMT\nFROM: W.K. Zheng at NAOC  <zwk@bao.ac.cn>\n\nY.Q. Lou, X.F. Wang, L.P. Xin, M.Zhai, Y.L. Qiu, J.Y. Wei, J.Y. Hu,\nJ.S. Deng, Y. Urata, and W.K. Zheng on behalf of EAFON report:\n\nWe have imaged the field of GRB 070808 (Cummings  et al., GCN 6718)\nwith the Xinglong TNT 80cm telescope. Observation started from\n18:29:55, 115s after the burst with White and R band. No new\nobject was seen in our combined image within XRT error circle.\nThe 3 sigam limit is ~19.7 in our co-added White image derived\nfrom USNO-A2.0, with mean time ~330s after the burst. Observation\nis on going. \n\nThis message may be cited."}', 'The Xinglong TNT 80cm telescope did not detect a new optical source within the error circle of GRB 070808, with a 3 sigma limit of ~19.7 magnitudes. The observation started 115 seconds after the burst and is ongoing.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6721', 'gcn', 'GRB070808', '2007-08-08T19:42:51.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":20.5,"other_measurements":{"exposure_time":"30 sec"},"ra":null,"redshift":null,"tables":[{"band":"Rc","limit_magnitude":20.5,"time":"18:29:53 UT 8 Aug."}]},"authors":{"affiliations":["Hiroshima Univ.","Kyoto Univ."],"authors":["M. Uemura","A. Arai","M. Sasada","M. Isogai","T. Uehara","D. Nogami"],"institutions":["Hiroshima University","Kyoto University"],"universities":["Hiroshima Univ.","Kyoto Univ."]},"telescopes":{"facilities":["KANATA"],"instruments":["TRISPEC"],"observatories":["Higashi-Hiroshima Observatory"],"telescopes":["KANATA 1.5-m telescope"]},"urls":[],"basic_data":{"author":{"email":"uemuram@hiroshima-u.ac.jp","institution":"Hiroshima U","name":"Makoto Uemura"},"coordinates":{},"detectionTime":"2007-08-08T19:42:51.000Z","event":"GRB070808","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6721\nSUBJECT: GRB070808: Optical observations with KANATA\nDATE: 07/08/08 19:42:51 GMT\nFROM: Makoto Uemura at Hiroshima U  <uemuram@hiroshima-u.ac.jp>\n\nM. Uemura, A. Arai, M. Sasada, M. Isogai, T. Uehara (Hiroshima Univ.),\nand D. Nogami (Kyoto Univ.) report on behalf of the KANATA GRB team:\n\n  We started optical imaging of the field of GRB070808 (GCN 6718) \nat 18:29:38 UT 8 Aug. using TRISPEC attached to the KANATA \n1.5-m telescope at Higashi-Hiroshima Observatory, Japan.  \nExposure times for Rc-band images are 30 sec.  \n\nNo new object was significantly detected.  \nIn our first image, a limit magnitude was estimated from \nneighbour USNO A2.0 stars as below:\n\n18:29:53 UT 8 Aug.  20.5  Rc  \n\nFollow-up observations are ongoing."}', 'The KANATA GRB team at Hiroshima and Kyoto Universities reported optical observations of GRB070808 using the KANATA 1.5-m telescope. No new object was detected, and a limit magnitude of 20.5 in the Rc band was measured.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6720', 'gcn', 'GRB070808', '2007-08-08T19:16:57.000Z', '{"measurements":{"dec":1.166,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"astrometric_precision":0.1,"nanomaggie_equivalence":0.000003631,"photometric_accuracy":2,"pixel_size":0.396,"unit_of_astrometric_precision":"arcsecond","unit_of_nanomaggie_equivalence":"Jy","unit_of_photometric_accuracy":"%","unit_of_pixel_size":"arcsec"},"ra":6.766,"redshift":null,"tables":[{"column_names":["Number of bright stars","Magnitude limit"],"values":[148,20.5]},{"column_names":["Number of detected objects","Faintest detection limit in r-band"],"values":[1167,23]},{"column_names":["Dust extinction coefficients","Band"],"values":[0.134,"u"]},{"column_names":["Dust extinction coefficients","Band"],"values":[0.098,"g"]},{"column_names":["Dust extinction coefficients","Band"],"values":[0.071,"r"]},{"column_names":["Dust extinction coefficients","Band"],"values":[0.054,"i"]},{"column_names":["Dust extinction coefficients","Band"],"values":[0.038,"z"]}]},"authors":{"affiliations":["University of Arizona/Steward Observatory","Arizona","New York University","New York University","Lawrence Berkeley National Laboratory","Apache Point Observatory","University of Chicago","Penn State University","Penn State University"],"authors":["Richard J. Cool","Daniel J. Eisenstein","David W. Hogg","Michael R. Blanton","David J. Schlegel","J. Brinkmann","Donald Q. Lamb","Donald P. Schneider","Daniel E. Vanden Berk"],"institutions":["Steward Observatory","New York University","Lawrence Berkeley National Laboratory","Apache Point Observatory","University of Chicago","Penn State University"],"universities":["University of Arizona","New York University","Lawrence Berkeley National Laboratory","Apache Point Observatory","University of Chicago","Penn State University"]},"telescopes":{"facilities":["Sloan Digital Sky Survey"],"instruments":[],"observatories":["Steward Observatory"],"telescopes":[]},"urls":["http://mizar.as.arizona.edu/~grb/public/GRB070808","http://www.sdss.org/dr5"],"basic_data":{"author":{"email":"rcool@as.arizona.edu","institution":"U.of AZ/Steward Obs","name":"Richard J. Cool"},"coordinates":{},"detectionTime":"2007-08-08T19:16:57.000Z","event":"GRB070808","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6720\nSUBJECT: GRB070808 - SDSS Pre-Burst Observations\nDATE: 07/08/08 19:16:57 GMT\nFROM: Richard J. Cool at U.of AZ/Steward Obs  <rcool@as.arizona.edu>\n\nRichard J. Cool (Arizona), Daniel J. Eisenstein (Arizona), David W. Hogg\n(NYU), Michael R. Blanton (NYU), David J. Schlegel (LBNL), J. Brinkmann\n(APO),\nDonald Q. Lamb (Chicago), Donald P. Schneider (PSU), and Daniel E. Vanden\nBerk\n(PSU) report:\n\nThe Sloan Digital Sky Survey (SDSS) imaged the field of burst GRB070808\nprior to the burst.  As these data should be useful as a pre-burst comparison\nand for calibrating photometry, we are supplying the images and photometry\nmeasurements for this GRB field to the community.\n\nData from the SDSS, including 5 FITS images, 3 JPGS, and\n3 files of photometry and astrometry, are being placed at\nhttp://mizar.as.arizona.edu/~grb/public/GRB070808\n\nWe supply FITS images in each of the 5 SDSS bands of a 8''x8'' region centered\non the GRB position (ra=6.76600 (00:27:03.8), dec=1.16600 (01:09:57.6);\nSwift-BAT TRIGGER 287260), as well as 3 gri color-composite JPGs (with\ndifferent stretches). The units in the FITS images are nanomaggies per pixel.\nA pixel is 0.396 arcsec on a side. A nanomaggie is a flux-density unit equal\nto 10^-9 of a magnitude 0 source or, to the extent that SDSS is an AB system,\n3.631e-6 Jy.  The FITS images have WCS astrometric information.\n\nIn the file GRB070808_sdss.calstar.dat, we report photometry and astrometry\nof 148 bright stars (r<20.5) within 15'' of the burst location.  The\nmagnitudes\npresented in this file are asinh magnitudes as are standard in the SDSS\n(Lupton\n1999, AJ, 118, 1406). Beware that some of these stars are not well-detected\nin the u-band; use the errors and object flags to monitor data quality.\n\nIn the files GRB070808_sdss.objects_flux.dat and\nGRB070808_sdss.objects_magnitudes.dat, we report photometry of 1167\nobjects detected within 6'' of the GRB position.  We have removed saturated\nobjects and objects with model magnitudes fainter than 23.0 in the r-band.\nThe fluxes listed in GRB070808_sdss.objects_flux.dat are in nanomaggies\nwhile the magnitudes listed in GRB070808_sdss.objects_magnitudes.dat are\nasinh magnitudes.\n\nAll quantities reported are standard SDSS photometry, meaning that they are\nvery close to AB zeropoints and magnitudes are quoted in asinh magnitudes.\nPhotometric zeropoints are known to about 2% rms.  None of the photometry\nis corrected for dust extinction.  The Schlegel, Finkbeiner, and Davis\n(1998) predictions for this region are A_U=0.134 mag, A_g=0.098 mag, A_r =\n0.071 mag, A_i=0.054 mag, and A_z=0.038 mag.\n\nThe file GRB070808_sdss.spectro.dat contains a list of the 21 objects with\nSDSS spectroscopy within 6 arcminutes of the GRB position.  In addition to\nthe redshift and 1-sigma error for each object, this file also lists the\nobject spectroscopic classification.\n\nSDSS astrometry is generally better than 0.1 arcsecond per coordinate.\nUsers requiring high precision astrometry should take note that the SDSS\nastrometric system can differ from other systems such as those used in other\nnotices; we have not checked the offsets in this region.\n\nMore detailed information pertaining to our SDSS GRB releases can be found\nin our initial data release paper (Cool et al. 2006, PASP 118, 733).  See the\nSDSS DR4 documentation for more details: http://www.sdss.org/dr5.\n\nThese data have been reduced using a slightly different pipeline than that\nused for SDSS public data releases.  We cannot guarantee that the values here\nwill exactly match those in the data release in which these data are\nincluded.\nIn particular, we expect the photometric calibrations to differ by of order\n0.01 mag.\n\nThis note may be cited, but please also cite the SDSS data release paper,\nAdelman-McCarthy et al. (2006, ApJS, 162, 38), when using the data or\nreferring to the technical documentation."}', 'The Sloan Digital Sky Survey (SDSS) has released pre-burst observations of gamma-ray burst (GRB) 070808, including 5 FITS images, 3 JPG color composites, and photometry measurements for stars and objects within the field. The data, available at <http://mizar.as.arizona.edu/~grb/public/GRB070808>, can be used for comparison and calibration purposes.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-672', 'gcn', 'GRB000519', '2000-05-19T21:12:03.000Z', '{"measurements":{"dec":"1 o 10 '' 16.67 \"","distance":null,"duration":"15 s","energy":null,"fluence":"3x10^-6 erg/cm^2","magnitude":null,"other_measurements":{},"ra":"23 h  4 m 38.55 s","redshift":null,"tables":[{"DEC(2000)":"1 o 10 '' 16.67 \"","RA(2000)":"23 h  4 m 38.55 s"},{"DEC(2000)":"1 o 12 '' 58.16 \"","RA(2000)":"23 h  5 m  9.33 s"},{"DEC(2000)":"1 o  2 '' 54.25 \"","RA(2000)":"23 h  4 m 25.46 s"},{"DEC(2000)":"1 o 17 '' 39.60 \"","RA(2000)":"23 h  4 m 51.59 s"},{"DEC(2000)":"1 o  7 '' 35.67 \"","RA(2000)":"23 h  4 m  7.73 s"}]},"authors":{"affiliations":["UCBerkeley/SSL","GCN","BeppoSAX GRBM","NEAR"],"authors":["K. Hurley","S. Barthelmy","F. Frontera","C. Guidorzi","E. Montanari","T. Cline"],"institutions":["Ulysses GRB Team","GCN GRB team","BeppoSAX GRBM team","NEAR GRB team"],"universities":["UC Berkeley"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Ulysses","BATSE","BeppoSAX","NEAR"]},"urls":["<khurley@sunspot.ssl.berkeley.edu>"],"basic_data":{"author":{"email":"khurley@sunspot.ssl.berkeley.edu","institution":"UCBerkeley/SSL","name":"Kevin Hurley"},"coordinates":{},"detectionTime":"2000-05-19T21:12:03.000Z","event":"GRB000519","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 672\nSUBJECT: IPN triangulation of GRB000519\nDATE: 00/05/19 21:12:03 GMT\nFROM: Kevin Hurley at UCBerkeley/SSL  <khurley@sunspot.ssl.berkeley.edu>\n\nK. Hurley, on behalf of the Ulysses GRB Team, S. Barthelmy, on behalf\nof the GCN GRB team, F. Frontera, C. Guidorzi and E. Montanari, on\nbehalf of the BeppoSAX GRBM team, and T. Cline, on behalf of the NEAR\nGRB team, report:\n\nUlysses, BATSE, the BeppoSAX GRBM, and NEAR observed this burst at\n29885 s UT.  (BATSE Trigger #8111).  As observed by Ulysses, it\nhad a duration ~15 s, and a 25-100 keV fluence 3x10^-6 erg/cm^2.\nWe have triangulated it to a preliminary 100 sq. arcmin. error\nbox whose 3 sigma coordinates are:\n\n    RA(2000)                 DEC(2000)\n 23 h  4 m 38.55 s      1 o 10 ''  16.67 \"  (CENTER)\n 23 h  5 m  9.33 s      1 o 12 ''  58.16 \"  (CORNER)\n 23 h  4 m 25.46 s      1 o  2 ''  54.25 \"  (CORNER)\n 23 h  4 m 51.59 s      1 o 17 ''  39.60 \"  (CORNER)\n 23 h  4 m  7.73 s      1 o  7 ''  35.67 \"  (CORNER)\n\nThis error box can be refined."}', 'An astronomical alert was issued regarding GRB000519, a gamma-ray burst observed by Ulysses, BATSE, BeppoSAX GRBM, and NEAR. The burst had a duration of approximately 15 seconds and a 25-100 keV fluence of 3x10^-6 erg/cm^2. The preliminary error box for the location of the burst has a 100 sq. arcmin. area and was triangulated to the following coordinates: RA(2000) = 23 h 4 m 38.55 s, DEC(2000) = 1 o 10'' 16.67". This error box can be refined.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6719', 'gcn', 'GRB 070808', '2007-08-08T19:12:22.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":16.2,"other_measurements":{"individual_image_limiting_magnitude_range":"16.2-17.6","time_since_burst_for_first_image":"29.0 s"},"ra":null,"redshift":null,"tables":[{"Coadd?":"N","end UT":"18:28:34.6","mlim":16.2,"start UT":"18:28:29.6","t_exp(s)":5,"t_start-tGRB(s)":29}]},"authors":{"affiliations":["Louisiana State","University of Michigan"],"authors":["B. E. Schaefer","H. Swan","E.S. Rykoff","F. Yuan"],"institutions":["ROTSE collaboration"],"universities":["Louisiana State University","University of Michigan"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Siding Spring Observatory"],"telescopes":["ROTSE-IIIa"]},"urls":["<http://grb.phys.lsu.edu>"],"basic_data":{"author":{"email":"schaefer@grb.phys.lsu.edu","institution":"LSU","name":"Brad Schaefer"},"coordinates":{},"detectionTime":"2007-08-08T19:12:22.000Z","event":"GRB 070808","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6719\nSUBJECT: GRB 070808: ROTSE-III Optical Limits\nDATE: 07/08/08 19:12:22 GMT\nFROM: Brad Schaefer at LSU  <schaefer@grb.phys.lsu.edu>\n\nB. E. Schaefer (Louisiana State), H. Swan (U Mich), E.S. Rykoff (U Mich),\nF. Yuan (U Mich), report on behalf of the ROTSE collaboration:\n\nROTSE-IIIa, located at Siding Spring Observatory, Australia, responded to\nGRB 070808 (Swift trigger 287260; J. R. Cummings et al., GCN 6718),\nproducing images beginning 7.6 s after the GCN notice time. An automated\nresponse took the first image at 18:28:29.6 UT, 29.0 s after the burst,\nunder excellent conditions. We took 10 5-sec, 10 20-sec and 10 60-sec\nexposures, with further exposures ongoing. These unfiltered images are\ncalibrated relative to USNO A2.0 (R). Imaging is on going.\n\nComparison to the DSS (second epoch) reveals no new sources within the \n3-sigma Swift/BAT error circle or the XRT error circle; the field is not \ncrowded. Individual images have limiting magnitudes ranging from \n16.2-17.6; we set the following specific limits.\n\nstart UT       end UT      t_exp(s)   mlim   t_start-tGRB(s)  Coadd?\n--------------------------------------------------------------------\n18:28:29.6   18:28:34.6         5     16.2           29.0       N"}', 'The ROTSE-III collaboration at Siding Spring Observatory in Australia took optical images of GRB 070808 beginning 7.6 seconds after the gamma-ray burst, with the first image captured 29 seconds after the burst. No new sources were detected within the error circles, and individual images had limiting magnitudes ranging from 16.2-17.6.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6718', 'gcn', 'GRB 070808', '2007-08-08T18:50:12.000Z', '{"measurements":{"dec":"+01d 09'' 59\"","distance":null,"duration":"10 sec","energy":null,"fluence":null,"magnitude":18.5,"other_measurements":{"UVOT_exposure_duration":"100 seconds","XRT_start_time":"18:29:54 UT","expected_extinction_E_B_V":"0.02 mag","peak_count_rate":"~2000 counts/sec (15-350 keV)","typical_3_sigma_upper_limit":"18.5 mag"},"ra":"00h 27m 04s","redshift":null,"tables":[{"column_name":"RA(J2000)","value":"00h 27m 04s"},{"column_name":"Dec(J2000)","value":"+01d 09'' 59\""},{"column_name":"Uncertainty","value":"3 arcmin"},{"column_name":"RA(J2000)","value":"00 27 03.08"},{"column_name":"Dec(J2000)","value":"+01 10 32.7"},{"column_name":"Uncertainty","value":"4.5 arcsec"}]},"authors":{"affiliations":["NASA/UMBC","GSFC","U Leicester","CRESST/GSFC/USRA","NASA/ORAU","NASA/GSFC","INAF-IASFPA","NASA/GSFC/USRA","GSFC/ISAS","NASA/ORAU"],"authors":["J. R. Cummings","S. D. Barthelmy","P. A. Evans","N. Gehrels","S. T. Holland","J. A. Kennea","H. A. Krimm","V. Mangano","F. E. Marshall","K. L. Page","D. M. Palmer","P. Romano","G. Sato","M. Stamatikos","R. L. C. Starling","E. Troja","T. N. Ukwatta","D. E. Vanden Berk"],"institutions":["NASA/UMBC","GSFC","U Leicester","CRESST/GSFC/USRA","NASA/ORAU"],"universities":["UMBC","PSU","GSFC","LANL","Bicocca","INAF-IASFPA","ORAU"]},"telescopes":{"facilities":["Swift Team"],"instruments":["BAT"],"observatories":["Swift"],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{"dec":0.45085555555555556},"detectionTime":"2007-08-08T18:50:12.000Z","event":"GRB 070808","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6718\nSUBJECT: GRB 070808: Swift detection of a burst\nDATE: 07/08/08 18:50:12 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nJ. R. Cummings (NASA/UMBC), S. D. Barthelmy (GSFC),\nP. A. Evans (U Leicester), N. Gehrels (NASA/GSFC),\nS. T. Holland (CRESST/GSFC/USRA), J. A. Kennea (PSU),\nH. A. Krimm (GSFC/USRA), V. Mangano (INAF-IASFPA),\nF. E. Marshall (NASA/GSFC), K. L. Page (U Leicester),\nD. M. Palmer (LANL), P. Romano (Univ. Bicocca & INAF-OAB),\nG. Sato (GSFC/ISAS), M. Stamatikos (NASA/ORAU),\nR. L. C. Starling (U Leicester), E. Troja (INAF-IASFPA),\nT. N. Ukwatta (GSFC/GWU) and D. E. Vanden Berk (PSU) report on behalf\nof the Swift Team:\n\nAt 18:28:00 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 070808 (trigger=287260).  Swift slewed immediately to the burst. \nThe BAT on-board calculated location is \nRA, Dec 6.766, +1.166 which is \n   RA(J2000)  =  00h 27m 04s\n   Dec(J2000) = +01d 09'' 59\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  The BAT light curve showed a single FRED peak\nstructure with a duration of about 10 sec.  The peak count rate\nwas ~2000 counts/sec (15-350 keV), at ~0 sec after the trigger. \n\nThe XRT began taking data at 18:29:54 UT, 114 seconds after the BAT\ntrigger. Using prompt downlinked data, we find a fading, uncatalogued\nX-ray source located at RA, Dec: 6.7628, 1.1758 which is\n   RA(J2000)  = 00 27 03.08\n   Dec(J2000) = +01 10 32.7\nwith an uncertainty of 4.5 arcsec (radius, 90% containment). \nThis location is 36 arcseconds from the BAT on-board position, within \nthe BAT error circle. \n\nUVOT took a finding chart exposure of 100 seconds with the White (160-650 nm)\nfilter starting 118 seconds after the BAT trigger. No afterglow candidate has\nbeen found in the initial data products. The 2.7'' x 2.7'' sub-image covers 100%\nof the XRT error circle. The typical 3-sigma upper limit has been about 18.5 mag. \nNo correction has been made for the expected extinction corresponding\nto E(B-V) of 0.02 mag. \n\nBurst Advocate for this burst is J. R. Cummings (jayc AT milkyway.gsfc.nasa.gov). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift satellite detected a gamma-ray burst (GRB 070808) at 18:28:00 UT on August 8, 2007. The burst was located with an uncertainty of 3 arcmin and had a peak count rate of ~2000 counts/sec (15-350 keV). The X-ray Telescope (XRT) identified a fading X-ray source 36 arcseconds from the BAT position, within the error circle. No optical afterglow was detected by the Ultraviolet/Optical Telescope (UVOT) with a typical 3-sigma upper limit of 18.5 mag.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6717', 'gcn', 'GRB061121A', '2007-08-08T13:56:13.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"i_prime":19.2,"r_prime":17.2,"z_prime":18.6},"other_measurements":{"observation_mean_time_i_prime":"16.3 hours after the burst","observation_mean_time_r_prime":"14.7 hours after the burst","observation_mean_time_z_prime":"16.4 hours after the burst","observation_start_time_r_prime":"14.5 hours after the burst"},"ra":null,"redshift":null,"tables":[{"calibration_stars":13,"exposure_time":"10 x 80 sec","filter":"r''","limiting_magnitude":17.2},{"calibration_stars":14,"exposure_time":"75 x 80 sec","filter":"i''","limiting_magnitude":19.2},{"calibration_stars":21,"exposure_time":"65 x 80 sec","filter":"z''","limiting_magnitude":18.6}]},"authors":{"affiliations":["UNC/PROMPT"],"authors":["M. Schubel, C. Weaver, T. Brennan, J. Styblova, J. Haislip, D. Reichart, M. Nysewander, A. LaCluyze, K. Ivarsen, J. A. Crain, A. Foster, A. Trotter"],"institutions":["UNC/PROMPT"],"universities":["UNC"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["CTIO"],"telescopes":["16\" PROMPT telescopes"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.html?id=6717"],"basic_data":{"author":{"email":"mschubel@physics.unc.edu","institution":"UNC/PROMPT","name":"Mark Schubel"},"coordinates":{},"detectionTime":"2007-08-08T13:56:13.000Z","event":"GRB061121A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6717\nSUBJECT: GRB061121A: PROMPT Observations\nDATE: 07/08/08 13:56:13 GMT\nFROM: Mark Schubel at UNC/PROMPT  <mschubel@physics.unc.edu>\n\nM. Schubel, C. Weaver, T. Brennan, J. Styblova, J. Haislip, D. Reichart, M. \nNysewander, A. LaCluyze, K. Ivarsen, J. A. Crain, A. Foster, and A. Trotter \nreport:\n\nSkynet observed the localization of GRB 061121A (Page et al., GCN 5823) \nwith two of the 16\" PROMPT telescopes at CTIO beginning 14.5 hours after \nthe burst in r''i''z''.\n\nWe do not detect the afterglow (Page et al., GCN 5823) to 3-sigma limiting \nmagnitudes of r'' = 17.2 mag at a mean time of 14.7 hours after the burst \n(10 x 80 sec, calibrated to 13 stars), i'' = 19.2 mag at a mean time of 16.3 \nhours after the burst (75 x 80 sec, calibrated to 14 stars), and z'' = 18.6 \n(65 x 80 sec, calibrated to 21 stars) at a mean time of 16.4 hours after \nthe burst.\n\nLimiting magnitudes are calibrated to USNO B1.0 and NOMAD stars using the \ntransformation equations of Smith et al. 2002, AJ, 123, 2121."}', 'Astronomical alert: GRB061121A: PROMPT Observations', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6716', 'gcn', 'GRB070805', '2007-08-07T22:04:03.000Z', '{"measurements":{"dec":-59.959657,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":20.1,"other_measurements":{"magnitude_uncertainty":0.2,"unabsorbed_flux":3.4e-13,"unabsorbed_flux_unit":"erg/s/cm2","uvot_uncertainty":0.7,"uvot_uncertainty_unit":"arcseconds"},"ra":245.01175,"redshift":null,"tables":[{"distance_from_bat_position":82,"error_radius":4,"exposure_time":2.3,"flux":3.4e-13},{"error_radius":4.7,"exposure_time":7.7,"flux":1.13e-13}]},"authors":{"affiliations":["Swift team, IFC-INAF, Italy"],"authors":["V. La Parola, P. Schady, F.E. Marshall, S. T. Holland, A. M. Parsons, E. Troja, J. Kennea"],"institutions":["INAF-IASPA"],"universities":["IFC-INAF, Italy"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift XRT, Swift UVOT"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.msf?is_archive=0&is_alert=1&start_time=2007-08-07T22:04:03&end_time=2007-08-07T22:04:03"],"basic_data":{"author":{"email":"laparola@ifc.inaf.it","institution":"INAF-IASPA","name":"Valentina La Parola"},"coordinates":{},"detectionTime":"2007-08-07T22:04:03.000Z","event":"GRB070805","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6716\nSUBJECT: GRB070805 XRT and UVOT afterglow candidate\nDATE: 07/08/07 22:04:03 GMT\nFROM: Valentina La Parola at INAF-IASPA  <laparola@ifc.inaf.it>\n\nV. La Parola, P. Schady, F.E. Marshall, S. T. Holland and \nA. M. Parsons, E. Troja, J. Kennea\nreport on behalf of the Swift team\n\nWe have analysed the XRT and UVOT observations of \nGRB070805 (Parsons et al., GCN 6708).\n\nThe XRT observed the BAT position twice, with 2.3 and 7.7 \nksec exposure times.\nWe find a faint source (estimated unabsorbed flux: 3.4e-13 \nerg/s/cm2) within the BAT error circle, at\nRA= 16 20 02.8 (245.01175)\nDec= -59 57 34.8 (-59.959657)\n(4 arcsec error radius, 90% confidence)\nthat is 82 arcsec from the BAT position (Stamatikos et al, \nGCN 6711)\nThis source does not show any sign of decay, its count \nrate being consistent between the two observations.\nThe source is too faint to allow for any detailed spectral \nor temporal analysis.\n\nA second, fainter source is detected only in the second \nobservation, at\nRA= 16 20 16.8 (245.069937)\nDec= -59 57 12.7 (-59.95352)\n(4.7 arcsec error radius, 90% confidence)\nThe estimated unabsorbed flux is 1.13e-13 erg/s/cm2.\n\nAt present, neither of these sources can be confidently \nassociated with the GRB afterglow.\n\nOn further inspection of the UVOT observations, an \nuncatalogued source is detected at the position of the \nfirst XRT source. This source was initially unidentified \n(GCN Circ. 6712) due to the density of the field and size \nof the BAT error circle. The source is detected in the \nwhite band filter at more than 3 sigma with an estimated \nmagnitude of 20.1+/-0.2, and is marginally detected in the \nV, B and U filters. The refined UVOT coordinates of this \nsource are\nRA = 16 20 03.11 (245.0131)\nDec = -59 57 34.9 (-59.9597)\nwith an uncertainty of 0.7 arcseconds. There is little \nevidence for variability in the limited data currently \navailable. Observations are ongoing.\n\nI.A.S.F.   INAF   Mailing System\nOutgoing mail is certified Virus Free.\nChecked by McAfee anti-virus system"}', 'The Swift team reports the detection of two faint sources within the error circle of GRB070805 using XRT and UVOT observations. The first source, with an estimated unabsorbed flux of 3.4e-13 erg/s/cm2, does not show any sign of decay and is associated with an uncatalogued UVOT source. The second source is only detected in the second observation and has an estimated unabsorbed flux of 1.13e-13 erg/s/cm2. Neither source can be confidently associated with the GRB afterglow at this time.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6715', 'gcn', 'Swift trigger on 4U 1700-377 while star tracker loss-of-lock', '2007-08-07T21:14:31.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"time":"21:01:01 UT","trigger_number":287221},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["NASA/UMBC","GSFC","PSU","INAF-IASFPA","LANL","GSFC/UMD","GSFC/ISAS","INAF-OAB","NASA/ORAU"],"authors":["J. Cummings","S. D. Barthelmy","M. M. Chester","N. Gehrels","C. Guidorzi","J. A. Kennea","V. La Parola","V. Mangano","C. B. Markwardt","D. M. Palmer","G. Sato","B. Sbarufatti","M. Stamatikos","E. Troja","T. N. Ukwatta","D. E. Vanden Berk","S. D. Vergani"],"institutions":["NASA/UMBC","GSFC","PSU","INAF-IASFPA","LANL","DIAS-DCU","CRESST"],"universities":["NASA/UMBC","PSU","UMD","GSFC","INAF-IASFPA","LANL","DIAS-DCU"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://lheamail.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-08-07T21:14:31.000Z","event":"Swift trigger on 4U 1700-377 while star tracker loss-of-lock","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6715\nSUBJECT: Swift trigger on 4U 1700-377 while star tracker loss-of-lock\nDATE: 07/08/07 21:14:31 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nJ. Cummings (NASA/UMBC), S. D. Barthelmy (GSFC),\nM. M. Chester (PSU), N. Gehrels (NASA/GSFC),\nC. Guidorzi (Univ Bicocca&INAF-OAB), J. A. Kennea (PSU),\nV. La Parola (INAF-IASFPA), V. Mangano (INAF-IASFPA),\nC. B. Markwardt (CRESST/GSFC/UMD), D. M. Palmer (LANL),\nG. Sato (GSFC/ISAS), B. Sbarufatti (INAF-IASFPA),\nM. Stamatikos (NASA/ORAU), E. Troja (INAF-IASFPA),\nT. N. Ukwatta (GSFC/GWU), D. E. Vanden Berk (PSU) and\nS. D. Vergani (DIAS-DCU) report on behalf of the Swift Team:\n\nAt 21:01:01 UT, the Swift Burst Alert Telescope (BAT) triggered\non the 4U 1700-377 source while the Star Tracker had lost lock\n(trigger #287221).  This is not a GRB, nor is it anything \nastrophysically interesting."}', 'The Swift Burst Alert Telescope (BAT) triggered on the 4U 1700-377 source at 21:01:01 UT despite a loss of lock by the Star Tracker. The event was not a gamma-ray burst or astrophysically interesting.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6714', 'gcn', 'GRB070612A', '2007-08-07T05:39:00.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"end_time_mjd":54305.26,"end_time_utc":"2007 Jul24 06:12:36","flux_density_upper_limit":"109 +/- 64 micro Jy","observation_frequency":"1280 MHz","start_time_mjd":54305.08,"start_time_utc":"2007 Jul24 01:55:21","time_after_burst_days":"41.97-42.15 days"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["National Centre for Radio Astrophysics of the Tata Institute of Fundamental Research"],"authors":["Sabyasachi Pal","C.H. Ishwara-Chandra","Dipankar Bhattacharya","Atish P. Kamble"],"institutions":["National Centre for Radio Astrophysics"],"universities":["Tata Institute of Fundamental Research"]},"telescopes":{"facilities":["National Centre for Radio Astrophysics"],"instruments":[],"observatories":[],"telescopes":["Giant Meterwave Radio Telescope"]},"urls":["http://www.openprotect.com"],"basic_data":{"author":{"email":"dipankar@iucaa.ernet.in","institution":"IUCAA","name":"Dipankar Bhattacharya"},"coordinates":{},"detectionTime":"2007-08-07T05:39:00.000Z","event":"GRB070612A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6714\nSUBJECT: GRB070612A: Radio upper limit from GMRT\nDATE: 07/08/07 05:39:00 GMT\nFROM: Dipankar Bhattacharya at IUCAA  <dipankar@iucaa.ernet.in>\n\nSabyasachi Pal, C.H. Ishwara-Chandra, Dipankar Bhattacharya and\nAtish P. Kamble report on behalf of a larger collaboration:\n\nWe observed the field of GRB 070612A (Grupe et al, GCN 6509) at\n1280 MHz, using the Giant Meterwave Radio Telescope, from\nMJD 54305.08 to 54305.26 (UT 2007 Jul24 01:55:21 to 06:12:36).\nThis interval corresponds to 41.97-42.15 days after the burst.\nThe afterglow was not detected. The formal flux density at the\nposition of the optical afterglow (Cenko et al, GCN 6525)\nwas 109 +/- 64 micro Jy (1-sigma).\n\nWe thank the GMRT staff who made this observation possible.\nGMRT is run by the National Centre for Radio Astrophysics of\nthe Tata Institute of Fundamental Research.\n\nThis message may be cited.\n\n\n-- \nThis message has been scanned for viruses and\ndangerous content by OpenProtect(http://www.openprotect.com), and is\nbelieved to be clean."}', 'A team of researchers led by Sabyasachi Pal, C.H. Ishwara-Chandra, Dipankar Bhattacharya, and Atish P. Kamble reported that they did not detect the afterglow of GRB 070612A using the Giant Meterwave Radio Telescope at a frequency of 1280 MHz between July 24, 2007, 01:55:21 and 06:12:36 UTC, which corresponds to 41.97-42.15 days after the burst. The upper limit on the flux density at the position of the optical afterglow was 109 +/- 64 micro Jy.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6713', 'gcn', 'GRB 070721B', '2007-08-06T14:34:46.000Z', '{"measurements":{"dec":"-02:11:40.4","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"error":"0.5\"","offset_from_uvot_position":"0.4\""},"ra":"02:12:32.97","redshift":"3.626","tables":[]},"authors":{"affiliations":["Niels Bohr Inst,Dark Cosmology Center"],"authors":["Daniele Malesani"],"institutions":["Dark Cosmology Center"],"universities":["Niels Bohr Inst,Dark Cosmology Center"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Dark Cosmology Center"],"telescopes":["NOT","VLT"]},"urls":["http://www.astro.ku.dk/~malesani/GRB/070721B/"],"basic_data":{"author":{"email":"malesani@astro.ku.dk","institution":"Niels Bohr Inst,Dark Cosmology Center","name":"Daniele Malesani"},"coordinates":{"dec":2.2091583333333333},"detectionTime":"2007-08-06T14:34:46.000Z","event":"GRB 070721B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6713\nSUBJECT: GRB 070721B: correct afterglow position\nDATE: 07/08/06 14:34:46 GMT\nFROM: Daniele Malesani at Niels Bohr Inst,Dark Cosmology Center  <malesani@astro.ku.dk>\n\nD. Malesani (DARK) reports:\n\nI have looked again at the NOT and VLT images of GRB 070721B (Ziaeepour \net al., GCN 6640), and realized there has been some confusion in what \nreported in our GCNs 6651 and 6655.\n\nThe correct afterglow position is (J2000):\n\nRA = 02:12:32.97\nDec = -02:11:40.4\n\nwith an estimated error of 0.5\". This position is within 0.4\" of and \nconsistent with the UVOT afterglow position as reported by Schady (GCN \n6641). In the finding chart (Malesani et al., GCN 6651) posted at\n\nhttp://www.astro.ku.dk/~malesani/GRB/070721B/\n\nthe afterglow corresponds to object #1, and not #2 as written in GCN \n6655 (Fynbo et al.). Object #2 (RA = 02:12:33.03, Dec = -02:11:40.6) is \na closeby, real object, likely unrelated to the GRB. The redshift \nz=3.626 reported in GCN 6651 correctly refers to the afterglow.\n\nI apologize for any confusion this may have created."}', 'Astronomer Daniele Malesani at Niels Bohr Inst, Dark Cosmology Center has corrected the reported position of the afterglow for GRB 070721B. The correct position is RA: 02:12:32.97, Dec: -02:11:40.4 with an estimated error of 0.5". This position is consistent with the UVOT afterglow position and within 0.4" of the previously reported position. Object #2 in the finding chart, previously mistakenly identified as the afterglow, is a separate, unrelated object.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6712', 'gcn', 'GRB070805', '2007-08-06T12:06:28.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"b":"> 19.5","u":"> 19.2","uvm2":"> 18.8","uvw1":"> 19.0","uvw2":"> 19.4","v":"> 18.5","white":"> 20.2"},"other_measurements":{},"ra":null,"redshift":null,"tables":[{"Exposure":333,"Filter":"white","Magnitude":"> 20.2","Tmid":3267},{"Exposure":274,"Filter":"v","Magnitude":"> 18.5","Tmid":2825},{"Exposure":274,"Filter":"b","Magnitude":"> 19.5","Tmid":3441},{"Exposure":274,"Filter":"u","Magnitude":"> 19.2","Tmid":3287},{"Exposure":274,"Filter":"uvw1","Magnitude":"> 19.0","Tmid":3133},{"Exposure":274,"Filter":"uvm2","Magnitude":"> 18.8","Tmid":2979},{"Exposure":452,"Filter":"uvw2","Magnitude":"> 19.4","Tmid":3384}]},"authors":{"affiliations":["MSSL/Swift","GSFC"],"authors":["P. Schady","A.M. Parsons"],"institutions":["MSSL (Mullard Space Science Laboratory)","GSFC (Goddard Space Flight Center)"],"universities":["University College London","NASA Goddard Space Flight Center"]},"telescopes":{"facilities":[],"instruments":["Swift/UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["http://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.html?id=6712"],"basic_data":{"author":{"email":"ps@mssl.ucl.ac.uk","institution":"MSSL/Swift","name":"Patricia Schady"},"coordinates":{},"detectionTime":"2007-08-06T12:06:28.000Z","event":"GRB070805","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6712\nSUBJECT: Swift/UVOT observations of GRB070805\nDATE: 07/08/06 12:06:28 GMT\nFROM: Patricia Schady at MSSL/Swift  <ps@mssl.ucl.ac.uk>\n\nP. Schady and A.M. Parsons (GSFC) report on behalf of the Swift UVOT team\n\nThe Swift/UVOT observed the field of GRB070805 (trigger=287088) starting \n33 minutes after the BAT trigger (Parsons et al. 2007, GCN Circ.6708). We \ndo not find any new source in the UVOT observations within the BAT error \ncircle or in the whole of the UVOT field of view, which we note is a very \ncrowded field.\n\nThe 5-sigma upper limits in the co-added frames are listed below:\n\nFilter   Tmid   Exposure   Magnitude\n          (s)    (s)        (5-sigma UL)\nwhite    3267   333         > 20.2\nv        2825   274         > 18.5\nb        3441   274         > 19.5\nu        3287   274         > 19.2\nuvw1     3133   274         > 19.0\nuvm2     2979   274         > 18.8\nuvw2     3384   452         > 19.4\n\nwhere Tmid is the weighted mean team of the coadded exposure. The values \nquoted above are not corrected for the expected Galactic extinction \ncorresponding to a reddening of E(B-V) = 0.202 mag in the direction of the \nburst (Schlegel et al. 1998)."}', 'The Swift/UVOT team reported no new source detection within the error circle or the UVOT field of view for GRB070805, a gamma-ray burst observed by Swift. They provided 5-sigma upper limits for magnitudes in various filters, which were not corrected for Galactic extinction.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6711', 'gcn', 'GRB 070805', '2007-08-06T03:47:45.000Z', '{"measurements":{"dec":"-59.957","distance":null,"duration":"31.0 +- 1.0 sec","energy":null,"fluence":"7.2 +- 0.8 x 10^-7 erg/cm2","magnitude":null,"other_measurements":{"partial_coding":"60%","peak_photon_flux":"0.7 +- 0.2 ph/cm2/sec","power_law_index":"1.84 +- 0.20"},"ra":"245.057","redshift":null,"tables":[]},"authors":{"affiliations":["GSFC/ORAU","GSFC","GSFC","GSFC/UMBC","LANL","GSFC","GSFC/USRA","GSFC/UMD","LANL","GSFC","GSFC/ISAS","GSFC","GSFC"],"authors":["M. Stamatikos","L. Barbier","S. D. Barthelmy","J. Cummings","E. Fenimore","N. Gehrels","H. Krimm","C. Markwardt","D. Palmer","A. Parsons","T. Sakamoto","G. Sato","J. Tueller","T. Ukwatta"],"institutions":["NASA/GSFC","ORAU","GSFC/ORAU","GSFC/UMBC","GSFC","LANL","GSFC/USRA","GSFC/UMD"],"universities":["GSFC","UMBC","LANL","UMD","ISAS"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-08-06T03:47:45.000Z","event":"GRB 070805","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6711\nSUBJECT: GRB 070805, Swift-BAT refined analysis\nDATE: 07/08/06 03:47:45 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nM. Stamatikos (GSFC/ORAU), L. Barbier (GSFC), S. D. Barthelmy (GSFC),\nJ. Cummings (GSFC/UMBC), E. Fenimore (LANL), N. Gehrels (GSFC),\nH. Krimm (GSFC/USRA), C. Markwardt (GSFC/UMD), D. Palmer (LANL),\nA. Parsons (GSFC), T. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS),\nJ. Tueller (GSFC), T. Ukwatta (GWU)\n(i.e. the Swift-BAT team):\n \nUsing the data set from T-120 to T+182 sec from the recent telemetry downlink,\nwe report further analysis of BAT GRB 070805 (trigger #287088)\n(Parsons, et al., GCN Circ. 6708).  The BAT ground-calculated position is\nRA, Dec = 245.057, -59.957 deg, which is \n   RA(J2000)  =  16h 20m 13.8s \n   Dec(J2000) = -59d 57'' 26\" \nwith an uncertainty of 1.5 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 60%.\n \nThe mask-weighted light curve shows two overlapping FRED-like peaks,\nthe first starting at ~T_zero and the second ending at ~T+35 sec.\nWe note that the spacecraft slewed to a pre-planned target at T+135 sec.\nDuring the slew the burst location left the BAT FOV at T+182 sec, and as such,\nwe can not determine if there as any burst activity beyond T+182 sec.\nT90 (15-350 keV) is 31.0 +- 1.0 sec (estimated error including systematics).\n \nThe time-averaged spectrum from T-0.6 to T+35.7 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n1.84 +- 0.20.  The fluence in the 15-150 keV band is 7.2 +- 0.8 x 10^-7 erg/cm2.\nThe 1-sec peak photon flux measured from T+3.23 sec in the 15-150 keV band\nis 0.7 +- 0.2 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel."}', 'The Swift-BAT team reported a refined analysis of GRB 070805 (trigger #287088), with a ground-calculated position and uncertainty, two FRED-like peaks, a duration of 31.0 +- 1.0 sec, and a time-averaged spectrum best fit by a simple power-law model with an index of 1.84 +- 0.20. The fluence in the 15-150 keV band is 7.2 +- 0.8 x 10^-7 erg/cm2, and the 1-sec peak photon flux is 0.7 +- 0.2 ph/cm2/sec.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6710', 'gcn', 'GRB 070805', '2007-08-06T03:47:39.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"2.3 ks","energy":"2.4e-13 erg/s/cm2","fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["I.A.S.F. (Istituto di Astrofisica Spaziale e Fisica Applicata) - INAF (Istituto Nazionale di Astrofisica)","Swift team"],"authors":["V. La Parola","J. Kennea","E. Troja","V. Mangano","B.","Sbarufatti"],"institutions":["I.A.S.F.","INAF","Swift team"],"universities":["I.A.S.F.","INAF"]},"telescopes":{"facilities":[],"instruments":["Swift XRT"],"observatories":[],"telescopes":[]},"urls":[""],"basic_data":{"author":{"email":"laparola@ifc.inaf.it","institution":"INAF-IASPA","name":"Valentina La Parola"},"coordinates":{},"detectionTime":"2007-08-06T03:47:39.000Z","event":"GRB 070805","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6710\nSUBJECT: GRB 070805: Swift XRT initial analysis.\nDATE: 07/08/06 03:47:39 GMT\nFROM: Valentina La Parola at INAF-IASPA  <laparola@ifc.inaf.it>\n\nV. La Parola, J. Kennea, E. Troja, V. Mangano, B. \nSbarufatti on behalf of the\nSwift team.\n\nWe have analysed the first 2.3 ks of the XRT observation \nof GRB070805 (Parsons et al., GCN 6708).\nDue to Earth limb constraint the XRT began observing the \nGRB location 33 min after the trigger, at 20:28:48 UT.\nNo sources are visible in this first orbit of data, with \nan upper limit to the unabsorbed flux of 2.4e-13 \nerg/s/cm2.\nWe are waiting for more data for further analysis.\n\nThis is an official product of the Swift-XRT team\n  \nI.A.S.F.   INAF   Mailing System\nOutgoing mail is certified Virus Free.\nChecked by McAfee anti-virus system"}', 'The Swift XRT team has analyzed the first 2.3 ks of data from their observation of GRB070805 and have not detected any sources with an upper limit to the unabsorbed flux of 2.4e-13 erg/s/cm2. The team is waiting for more data for further analysis.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-671', 'gcn', 'GRB000516', '2000-05-17T00:11:03.000Z', '{"measurements":{"dec":"-14:50:14.33","distance":null,"duration":"7 s","energy":null,"fluence":"3.5 x 10^-6 erg/cm^2","magnitude":null,"other_measurements":{},"ra":"2:20:16.13","redshift":null,"tables":[{"DEC(2000)":"-14 o 50 '' 14.33 \"","RA(2000)":"2 h 20 m 16.13 s"},{"DEC(2000)":"-14 o 46 '' 56.89 \"","RA(2000)":"2 h 20 m 15.19 s"},{"DEC(2000)":"-14 o 37 '' 01.35 \"","RA(2000)":"2 h 20 m 43.02 s"},{"DEC(2000)":"-15 o 03 '' 28.23 \"","RA(2000)":"2 h 19 m 49.16 s"},{"DEC(2000)":"-14 o 53 '' 31.81 \"","RA(2000)":"2 h 20 m 17.07 s"}]},"authors":{"affiliations":["UCBerkeley/SSL"],"authors":["K. Hurley","T. Cline","E. Mazets","F. Frontera","C. Guidorzi","E. Montanari"],"institutions":["Ulysses GRB team","Konus-WIND GRB team","NEAR GRB team","BeppoSAX GRBM team"],"universities":["UC Berkeley","SSL"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Ulysses","Konus-WIND","NEAR","SAX"]},"urls":[],"basic_data":{"author":{"email":"khurley@sunspot.ssl.berkeley.edu","institution":"UCBerkeley/SSL","name":"Kevin Hurley"},"coordinates":{},"detectionTime":"2000-05-17T00:11:03.000Z","event":"GRB000516","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 671\nSUBJECT: IPN triangulation of GRB000516\nDATE: 00/05/17 00:11:03 GMT\nFROM: Kevin Hurley at UCBerkeley/SSL  <khurley@sunspot.ssl.berkeley.edu>\n\nK. Hurley, on behalf of the Ulysses GRB team, T. Cline and E.\nMazets, on behalf of the Konus-WIND and NEAR GRB teams, and F.\nFrontera, C. Guidorzi and E. Montanari, on behalf of the\nBeppoSAX GRBM team, report:\n\nUlysses, Konus, NEAR, and SAX observed this burst at\n33960 UT.  As observed by Ulysses, it had a duration of \n~7 s and a 25-100 keV fluence of 3.5 x 10^-6 erg/cm^2.\nWe have triangulated it to a preliminary error\nbox whose 3 sigma area is ~50 sq. arcmin. and whose coordinates\nare:\n\n    RA(2000)                 DEC(2000)\n  2 h 20 m 16.13 s    -14 o 50 ''  14.33 \"  (CENTER)\n  2 h 20 m 15.19 s    -14 o 46 ''  56.89 \"  (CORNER)\n  2 h 20 m 43.02 s    -14 o 37 ''  01.35 \"  (CORNER)\n  2 h 19 m 49.16 s    -15 o 03 ''  28.23 \"  (CORNER)\n  2 h 20 m 17.07 s    -14 o 53 ''  31.81 \"  (CORNER)\n\nThis error box can be improved."}', 'Astronomical alert: IPN triangulation of GRB000516', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6709', 'gcn', 'GRB 070805', '2007-08-05T21:19:21.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"bat_error_circle_coverage":{"unit":"%","value":100},"exposure_time":{"unit":"seconds","value":100},"region_size":{"unit":"''","value":8},"time_after_trigger":{"unit":"seconds","value":1977}},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["PSU","MSSL","NASA/GSFC"],"authors":["D. E. Vanden Berk","P. Kuin","F. E. Marshall","A. M. Parsons"],"institutions":["PSU/Swift","MSSL"],"universities":["Penn State University","University of London"]},"telescopes":{"facilities":[],"instruments":["Swift/UVOT"],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"danvb@astro.psu.edu","institution":"PSU/Swift","name":"Daniel E. Vanden Berk"},"coordinates":{},"detectionTime":"2007-08-05T21:19:21.000Z","event":"GRB 070805","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6709\nSUBJECT: GRB 070805: Swift/UVOT initial analysis\nDATE: 07/08/05 21:19:21 GMT\nFROM: Daniel E. Vanden Berk at PSU/Swift  <danvb@astro.psu.edu>\n\nD. E. Vanden Berk (PSU), P. Kuin (MSSL), F. E. Marshall (NASA/GSFC),\nand A. M. Parsons (GSFC) report on behalf of the Swift-UVOT team:\n\nUVOT took a finding chart exposure of 100 seconds with the White (160-650\nnm) filter starting 1977 seconds after the BAT trigger.  No afterglow\ncandidate has been found in the initial data products. The overlap of the\nsub-image and the BAT error circle is uncertain at this time. The 8''x8''\nregion for the list of sources generated on-board covers 100% of the\nBAT error circle.  Because of the density of catalogued stars, further\nanalysis is required to report an upper limit for any afterglow in the\nregion. No correction has been made for the extinction of E(B-V)=0.202."}', 'An initial analysis of GRB 070805 by the Swift/UVOT team reports no afterglow candidate found within 100 seconds of UVOT data using the White filter. Further analysis is required due to the high density of catalogued stars in the region. No correction for extinction was made.', 0.85, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6708', 'gcn', 'GRB 070805', '2007-08-05T20:08:02.000Z', '{"measurements":{"dec":"-59d 56'' 40\"","distance":null,"duration":{"first_peak":"5 sec","second_peak":"broad and weak ending around T+40 sec"},"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"peak_count_rate":"~500 counts/sec (15-350 keV)","time_of_peak_count_rate":"~2 sec after the trigger"},"ra":"16h 20m 10s","redshift":null,"tables":[]},"authors":{"affiliations":["GSFC","PSU","INAF-IASFPA","CRESST/GSFC/UMD","LANL","NASA/ORAU","U Leicester","DIAS-DCU"],"authors":["A. M. Parsons","S. D. Barthelmy","N. Gehrels","J. A. Kennea","V. La Parola","C. B. Markwardt","D. M. Palmer","M. Stamatikos","R. L. C. Starling","E. Troja","T. N. Ukwatta","D. E. Vanden Berk","S. D. Vergani","H. Ziaeepour"],"institutions":["NASA/GSFC","PSU","INAF-IASFPA","CRESST/GSFC/UMD","LANL","NASA/ORAU","U Leicester","DIAS-DCU"],"universities":["NASA/GSFC","PSU","INAF-IASFPA","UMD","LANL","NASA/ORAU","U Leicester","INAF-IASFPA","GSFC/GWU","PSU","DIAS-DCU","UCL-MSSL"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{"dec":2.0680675},"detectionTime":"2007-08-05T20:08:02.000Z","event":"GRB 070805","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6708\nSUBJECT: GRB 070805: Swift detection of a burst\nDATE: 07/08/05 20:08:02 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nA. M. Parsons (GSFC), S. D. Barthelmy (GSFC), N. Gehrels (NASA/GSFC),\nJ. A. Kennea (PSU), V. La Parola (INAF-IASFPA),\nC. B. Markwardt (CRESST/GSFC/UMD), D. M. Palmer (LANL),\nM. Stamatikos (NASA/ORAU), R. L. C. Starling (U Leicester),\nE. Troja (INAF-IASFPA), T. N. Ukwatta (GSFC/GWU),\nD. E. Vanden Berk (PSU), S. D. Vergani (DIAS-DCU) and\nH. Ziaeepour (UCL-MSSL) report on behalf of the Swift Team:\n\nAt 19:55:45 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 070805 (trigger=287088). \nThe BAT on-board calculated location is \nRA, Dec 245.043, -59.945 which is \n   RA(J2000)  =  16h 20m 10s\n   Dec(J2000) = -59d 56'' 40\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  The BAT light curve shows two peaks, the first\nis ~5 sec in duration and the second peak is broader and weaker\nending around T+40 sec.  The peak count rate\nwas ~500 counts/sec (15-350 keV), at ~2 sec after the trigger. \n\nBecause of an Earth limb constraint, the spacecraft did not slew promptly\nto the BAT position, and so there are no immediate XRT or UVOT data products\nto analyze.  The burst will come out of constraint at T+31 minutes. \n\nBurst Advocate for this burst is A. M. Parsons (parsons AT milkyway.gsfc.nasa.gov). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift Burst Alert Telescope (BAT) detected a gamma-ray burst (GRB 070805) at 19:55:45 UT with a peak count rate of ~500 counts/sec (15-350 keV) and a location of RA: 16h 20m 10s, Dec: -59d 56'' 40'''', with an uncertainty of 3 arcmin. The burst had two peaks, the first lasting 5 seconds and the second broader and weaker ending around T+40 sec. The Swift team reports that the spacecraft did not slew promptly to the BAT position due to an Earth limb constraint, and no immediate XRT or UVOT data products are available. The burst will come out of constraint at T+31 minutes.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6707', 'gcn', 'UVOT observations of SAXJ1810.8-2609', '2007-08-05T17:31:16.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"b":"> 18.90","u":"> 19.11","uvm2":"> 18.32","uvw1":"> 18.65","uvw2":"> 18.76","v":"> 19.75","white":[19.25,20.32]},"other_measurements":{},"ra":null,"redshift":null,"tables":[{"Exposure":98,"Filter":"white","Magnitude":19.25,"Tmid":119},{"Exposure":98,"Filter":"white","Magnitude":20.32,"Tmid":915},{"Exposure":435,"Filter":"v","Magnitude":"> 19.75","Tmid":585},{"Exposure":19,"Filter":"b","Magnitude":"> 18.90","Tmid":737},{"Exposure":39,"Filter":"u","Magnitude":"> 19.11","Tmid":717},{"Exposure":39,"Filter":"uvw1","Magnitude":"> 18.65","Tmid":693},{"Exposure":39,"Filter":"uvm2","Magnitude":"> 18.32","Tmid":668},{"Exposure":39,"Filter":"uvw2","Magnitude":"> 18.76","Tmid":772}]},"authors":{"affiliations":["MSSL-UCL","GSFC"],"authors":["P. Schady","A.M. Parsons"],"institutions":["MSSL","Swift"],"universities":["MSSL-UCL","GSFC"]},"telescopes":{"facilities":["Swift"],"instruments":["UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"ps@mssl.ucl.ac.uk","institution":"MSSL/Swift","name":"Patricia Schady"},"coordinates":{},"detectionTime":"2007-08-05T17:31:16.000Z","event":"UVOT observations of SAXJ1810.8-2609","eventType":"EP","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6707\nSUBJECT: UVOT observations of SAXJ1810.8-2609\nDATE: 07/08/05 17:31:16 GMT\nFROM: Patricia Schady at MSSL/Swift  <ps@mssl.ucl.ac.uk>\n\nP. Schady (MSSL-UCL) and A.M. Parsons (GSFC) report on behalf of the \nSwift-UVOT team:\n\nThe Swift/UVOT observed the field of SAXJ1810.8-2609 (trigger=287042) \nstarting 70 s after the BAT trigger (Parsons et al. 2007, GCN Circ.6706). \nOn refined analysis of the UVOT data, a fading source is detected in the \nwhite-band filter at the position of SAX J1810.8-2610. The source is not \ndetected in any other of the filters, in either single or coadded \nexposures.\n\nThe white band magnitude and 3-sigma upper limits in the other UVOT \nfilters are as follows:\n\nFilter  Tmid   Exposure\tMagnitude\n         (s)    (s)\nwhite\t119    98       19.25+/-0.12\n         915    98       20.32+/-0.28\nv       585    435      > 19.75\nb       737    19       > 18.90\nu       717    39       > 19.11\nuvw1    693    39       > 18.65\nuvm2    668    39       > 18.32\nuvw2    772    39       > 18.76\n\nwhere Tmid is the weighted mean time of the coadded exposures. The values \nquoted above are not corrected for the expected Galactic extinction \ncorresponding to a reddening of E_{B-V} = 0.95 mag in the direction of the \nburst (Schlegel et al. 1998)."}', 'The Swift/UVOT team reports the detection of a fading source in the white-band filter of SAXJ1810.8-2609, a previously unidentified X-ray source. The source was not detected in any other filters, with 3-sigma upper limits ranging from 18.32 to 19.75 in the other UVOT filters. This detection suggests that the source underwent a significant change in emission, potentially indicating a transient astronomical event.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6706', 'gcn', 'Swift detection of a outburst from SAX J1810.8-2609', '2007-08-05T12:11:10.000Z', '{"measurements":{"dec":-26.153,"distance":null,"duration":5,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"bat_peak_count_rate":"~600 counts/sec (15-350 keV)","xrt_initial_flux":"4.9e-09 erg/cm2/s (0.2-10 keV)"},"ra":272.651,"redshift":null,"tables":[{"column_name":"initial_flux","value":"4.9e-09 erg/cm2/s"},{"column_name":"extinction","value":"E(B-V)=0.95"}]},"authors":{"affiliations":["GSFC","INAF-OAB","NASA/GSFC/USRA","LANL","CRESST/GSFC/UMD"],"authors":["A. M. Parsons","S. D. Barthelmy","N. Gehrels","C. Guidorzi","H. A. Krimm","V. La Parola","V. Mangano","C. B. Markwardt","F. E. Marshall","D. M. Palmer","P. Romano","G. Sato","B. Sbarufatti","R. L. C. Starling","E. Troja","D. E. Vanden Berk","H. Ziaeepour"],"institutions":["NASA/GSFC","INAF-OAB","NASA/GSFC/USRA","LANL","CRESST/GSFC/UMD"],"universities":["University of Bicocca","INAF-IASFPA","University of Leicester","PSU","UMD","ISAS"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{"dec":2.1174127611111113},"detectionTime":"2007-08-05T12:11:10.000Z","event":"Swift detection of a outburst from SAX J1810.8-2609","eventType":"EP","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6706\nSUBJECT: Swift detection of a outburst from SAX J1810.8-2609\nDATE: 07/08/05 12:11:10 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nA. M. Parsons (GSFC), S. D. Barthelmy (GSFC), N. Gehrels (NASA/GSFC),\nC. Guidorzi (Univ Bicocca&INAF-OAB), H. A. Krimm (GSFC/USRA),\nV. La Parola (INAF-IASFPA), V. Mangano (INAF-IASFPA),\nC. B. Markwardt (CRESST/GSFC/UMD), F. E. Marshall (NASA/GSFC),\nD. M. Palmer (LANL), P. Romano (Univ. Bicocca & INAF-OAB),\nG. Sato (GSFC/ISAS), B. Sbarufatti (INAF-IASFPA),\nR. L. C. Starling (U Leicester), E. Troja (INAF-IASFPA),\nD. E. Vanden Berk (PSU) and H. Ziaeepour (UCL-MSSL) report on behalf\nof the Swift Team:\n\nAt 2007-08-05 11:27:26 UT, the Swift Burst Alert Telescope (BAT) \ntriggered on a burst source not in its onboard catalog (trigger=287042).  \nSwift slewed immediately to the burst. \nThe BAT on-board calculated location is \nRA, Dec = 272.651, -26.153 which is \n   RA(J2000)  =  18h 10m 36s\n   Dec(J2000) = -26d 09'' 10\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  This source location is consistent (1.8 arcmin)\nwith the known Low Mass X-ray Binary V* V4722 Sgr (=SAX J1810.8-2609). \nThe BAT light curve shows a single peak with a duration of roughly 5 sec.  \nThe peak count rate was ~600 counts/sec (15-350 keV), at ~0 sec after \nthe trigger. \n\nThe XRT began observing the field at 11:28:25 UT, 59 seconds after the\nBAT trigger. XRT found a bright, variable X-ray source\nwhose position, determined from downlinked data, \nis RA, Dec 272.68594, -26.15055 which is\n   RA(J2000)  =  18h 10m 44.63s\n   Dec(J2000) = -26d 09'' 02.0\"\nwith an uncertainty of 4.5 arcseconds (radius, 90% containment). \nThis location is 112 arcseconds from the BAT on-board position,\nwithin the BAT error circle. The initial flux in the 2.5s image\nwas 4.9e-09 erg/cm2/s (0.2-10 keV). \nThe position is 3.69 arcseconds from the LMXB V* V4722 Sgr. \n\nUVOT took a finding chart exposure of 100 seconds with the White\n(160-650 nm) filter starting 70 seconds after the BAT trigger. \nNo afterglow candidate has been found in the initial data products. \nThere is a high density of sources in the image.  The extinction\ntoward the field is high, with E(B-V)=0.95. \n\nBurst Advocate for this burst is A. M. Parsons (parsons AT milkyway.gsfc.nasa.gov). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift Burst Alert Telescope (BAT) detected a new X-ray burst from SAX J1810.8-2609, a known Low Mass X-ray Binary (LMXB), on August 5, 2007. The burst had a peak count rate of ~600 counts/sec (15-350 keV) and a duration of approximately 5 seconds. The Swift X-Ray Telescope (XRT) and Ultraviolet/Optical Telescope (UVOT) subsequently observed the source, confirming its position and measuring an initial X-ray flux of 4.9e-09 erg/cm2/s (0.2-10 keV). No optical afterglow was detected in the UVOT data.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6705', 'gcn', 'GRB 070721B', '2007-08-04T02:25:07.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"frequency":"8.46 GHz","rms":"29 uJy"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["U Virginia/NRAO","NRAO"],"authors":["Poonam Chandra","Dale A. Frail"],"institutions":["NRAO","Caltech-NRAO-Carnegie GRB Collaboration"],"universities":["University of Virginia","Caltech","Carnegie"]},"telescopes":{"facilities":["National Radio Astronomy Observatory"],"instruments":[],"observatories":[],"telescopes":["Very Large Array"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.msf?id=6705"],"basic_data":{"author":{"email":"pc8s@virginia.edu","institution":"U Virginia/NRAO","name":"Poonam Chandra"},"coordinates":{},"detectionTime":"2007-08-04T02:25:07.000Z","event":"GRB 070721B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6705\nSUBJECT: VLA non-detection of GRB 070721B\nDATE: 07/08/04 02:25:07 GMT\nFROM: Poonam Chandra at U Virginia/NRAO  <pc8s@virginia.edu>\n\nPoonam Chandra (NRAO/UVA) and Dale A. Frail (NRAO) report on\nbehalf of the Caltech-NRAO-Carnegie GRB Collaboration:\n\n\n\"We used the Very Large Array to observe the field of view toward\nGRB 070721B (GCN 6640) at a frequency of 8.46 GHz on 2007 Aug 3rd\nat 10.42 UT. The radio afterglow of the GRB is undetected either at\nSwift-XRT position (GCN 6646) or at ESO-VLT position (GCN 6651). \nThe map rms is 29 uJy.\n\n\nThe National Radio Astronomy Observatory is a facility of the National\nScience Foundation operated under cooperative agreement by Associated\nUniversities, Inc.\""}', 'The Very Large Array (VLA) at the National Radio Astronomy Observatory did not detect the radio afterglow of GRB 070721B at a frequency of 8.46 GHz on August 3, 2007. The non-detection was reported by Poonam Chandra (U Virginia/NRAO) and Dale A. Frail (NRAO) on behalf of the Caltech-NRAO-Carnegie GRB Collaboration.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6704', 'gcn', 'GRB 070802', '2007-08-03T13:54:30.000Z', '{"measurements":{"dec":null,"distance":null,"duration":40,"energy":null,"fluence":null,"magnitude":17,"other_measurements":{"observation_start_time":"07:17:44 UT","time_after_burst":"about 10 minutes","time_after_swift_alert":"52 sec"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["IASF/CNR"],"authors":["E.Palazzi, S. Covino, L.A. Antonelli, L. Calzoletti, S. Campana, G. Chincarini, M.L. Conciatore, S. Cutini, P. D''Avanzo, V. D''Elia, F. Dalessio, F. Fiore, D. Fugazza, P. Goldoni, D. Guetta, C. Guidorzi, G.L. Israel, D. Malesani, N. Masetti, A. Melandri, E. Meurs, L. Nicastro, E. Pian, S. Piranomonte, D. Rizzuto, L. Stella, G. Stratta, G. Tagliaferri, G. Tosti, V. Testa, S.D. Vergani, F. Vitali"],"institutions":["IASF/CNR"],"universities":["IASF/CNR, Bologna"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["La Silla (Chile)"],"telescopes":["REM telescope"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"palazzi@iasfbo.inaf.it","institution":"IASF/CNR,Bologna","name":"Eliana Palazzi"},"coordinates":{},"detectionTime":"2007-08-03T13:54:30.000Z","event":"GRB 070802","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6704\nSUBJECT: GRB 070802: REM optical observations\nDATE: 07/08/03 13:54:30 GMT\nFROM: Eliana Palazzi at IASF/CNR,Bologna  <palazzi@iasfbo.inaf.it>\n\nE.Palazzi, S. Covino, L.A. Antonelli, L. Calzoletti, \nS. Campana, G.  Chincarini, M.L. Conciatore, S. Cutini, P. \nD''Avanzo,   V. D''Elia, F. Dalessio, F.  Fiore, D. Fugazza, P. \nGoldoni, D. Guetta,  C. Guidorzi, G.L. Israel,  D. Malesani, N. \nMasetti, A. Melandri, E. Meurs, L. Nicastro, E. Pian, S. Piranomonte, D. \nRizzuto,  L.  Stella, G.  Stratta, G. Tagliaferri, G. Tosti, V. \nTesta, S.D. Vergani,  F. Vitali   report on behalf of the REM team:\n\n\"We observed the field of the GRB 070802 (S. D. Barthelmy et al., GCN \n6692)  with the robotic 60-cm REM telescope located at La Silla (Chile).\nA set of observations was performed automatically in the R optical filter \nstarting at 07:17:44 UT (52 sec after the Swift alert; about 10 minutes \nafter the burst) and lasted about 40 minutes.\n\nThe analysis of the first 15 minutes exposures do not show \nthe optical/NIR afterglow candidate reported by J. Greiner et al (GCN \n6694), E. Berger et al (GCN. 6695), D. Malesani et al (GCN. 6696). \nThe 3-sigma limiting magnitude in the stacked images is R~17.0\""}', 'The REM team reported observing the field of GRB 070802 using the 60-cm REM telescope located at La Silla, Chile, 52 seconds after the Swift alert and about 10 minutes after the burst. After analyzing the first 15 minutes of exposures, they did not find an optical/NIR afterglow candidate and set a 3-sigma limiting magnitude of R~17.0.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6703', 'gcn', 'GRB 070724B', '2007-08-03T09:02:34.000Z', '{"measurements":{"dec":"+57 40 34.3","distance":null,"duration":"16.5 ks","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"light_curve_slope":"1.19+0.23-0.19","offset_from_initial_position":"4.6 arcmin","uncertainty":"3.9 arcsec"},"ra":"01 09 56.34","redshift":null,"tables":[]},"authors":{"affiliations":["Uni-Bicocca and OAB","OAB"],"authors":["P. Romano","C. Guidorzi","A. Moretti"],"institutions":["OAB"],"universities":["Uni-Bicocca"]},"telescopes":{"facilities":[],"instruments":["Swift-XRT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars/6675/6675.gcn3.fits","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars/6668/6668.gcn3.fits"],"basic_data":{"author":{"email":"patrizia.romano@brera.inaf.it","institution":"OAB-Swift","name":"Pat Romano"},"coordinates":{"dec":1.1656499999999999},"detectionTime":"2007-08-03T09:02:34.000Z","event":"GRB 070724B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6703\nSUBJECT: GRB 070724B: Swift-XRT afterglow confirmation\nDATE: 07/08/03 09:02:34 GMT\nFROM: Pat Romano at OAB-Swift  <patrizia.romano@brera.inaf.it>\n\nP. Romano, C. Guidorzi(Uni-Bicocca and OAB), A. Moretti(OAB),\nreport on behalf of the Swift-XRT team:\n\nUsing all data collected by Swift/XRT obtained for GRB 070724B\ndetected by SuperAGILE (Feroci et al., GCN Circ. 6668),\nfor a total of 16.5 ks (between T+19.1 hours and T+7.5 days),\nwe can now confirm that the candidate proposed in GCN Circ. 6675\n(Romano et al.) is the afterglow of GRB 070724B.\nIts final position is RA,DEC(J2000)=17.48477,57.67620, which is\n\nRA(J2000)  =  01 09 56.34\nDec(J2000) = +57 40 34.3\n\nwith an uncertainty of 3.9 arcsec (radius, 90% containment).\nThis is 0.4 arcsec from the X-ray position given in Romano et\nal., GCN Circ. 6675) and 4.6 arcmin from the initial SuperAGILE\nposition (Feroci et al., GCN Circ. 6668).\nThe light curve can be fit with a power-law power-law with\nslope of 1.19+0.23-0.19 (90% cl).\nNo further observations with Swift are planned.\n\nThis circular is an official product of the Swift XRT team."}', 'Swift-XRT team confirms GRB 070724B afterglow with a final position of RA: 01 09 56.34, Dec: +57 40 34.3, and a light curve that can be fit with a power-law. The uncertainty in position is 3.9 arcsec and it is 4.6 arcmin from the initial position. No further Swift observations are planned.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6702', 'gcn', 'GRB 070802', '2007-08-02T19:48:18.000Z', '{"measurements":{"dec":"-55 31 38.4","distance":null,"duration":"3.4 ks","energy":"0.3-10.0 keV","fluence":null,"magnitude":null,"other_measurements":{"absorbed_flux":"(3.9 +/- 0.8)e-12 ergs cm^-2 s^-1","column_density":"2.9e20 cm^-2","count_rate_prediction":"3e-2 count s^-1","flux_prediction":"1.4e-12 ergs cm^-2 s^-1","photon_index":"1.9 +/- 0.3","slope_1":"-2.0 +/- 0.2","slope_2":"-0.25 +/- 0.08","unabsorbed_flux":"(4.6 +/- 0.8)e-12 ergs cm^-2 s^-1","uncertainty":"2.1 arcsec"},"ra":"02 27 35.76","redshift":null,"tables":[]},"authors":{"affiliations":["INAF-IASF PA","U. Leicester","GSFC"],"authors":["V. Mangano","B. Sbarufatti","V. La Parola","E. Troja","P. Evans","S. Immler"],"institutions":["INAF-IASF PA","U. Leicester","GSFC"],"universities":["INAF-IASF PA","U. Leicester","GSFC"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"vanessa@ifc.inaf.it","institution":"INAF-IASFPA","name":"Vanessa Mangano"},"coordinates":{"dec":2.4599333333333333},"detectionTime":"2007-08-02T19:48:18.000Z","event":"GRB 070802","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6702\nSUBJECT: GRB 070802: Swift-XRT refined analysis\nDATE: 07/08/02 19:48:18 GMT\nFROM: Vanessa Mangano at INAF-IASFPA  <vanessa@ifc.inaf.it>\n\nV. Mangano, B. Sbarufatti, V. La Parola, E. Troja (INAF-IASF PA),\nP. Evans (U. Leicester) and S. Immler (GSFC)\nreport on behalf of the Swift-XRT team:\n\nWe have analysed the first three orbits of Swift-XRT data obtained for\nGRB 070802 (Barthelmy et al, GCN Circ. 6692), which include 3.4 ks of\nPhoton Counting (PC) data.\n\nUsing 599 s of overlapping XRT Photon Counting mode and UVOT V-band\ndata, we find an astrometrically corrected X-ray position (using the\nXRT-UVOT alignment and matching UVOT field sources to the USNO-B1\ncatalogue): RA, Dec = 36.89899, -55.52733 which is equivalent to:\n\nRA (J2000):  02 27 35.76\nDec (J2000): -55 31 38.4\n\nwith an uncertainty of 2.1 arcsec (radius, 90% confidence).\nThis is 4.9 arcsec from the initial XRT position (Evans and Mangano,\nGCN Circ. 6697) and 38 arcsec from the BAT ground-calculated position\n(Cummings et al, GCN Circ. 6699). It is also 0.7 arcsec from the\noptical position of Malesani et al. (GCN Circ. 6696) and 1.4 arcsec\nfrom the I band position of Berger and Murphy (GCN Circ. 6695).\n\nThe XRT light-curve decays with slope -2.0+/-0.2 up to about T+500 s,\nthen flattens to slope -0.25+/-0.08. We do not see a further break up\nto T+17 ks.\n\nThe spectrum can be fit with an absorbed power law with\na photon index of 1.9+/-0.3 and a column density consistent\nwith the Galactic value (2.9e20 cm^-2).\nThe absorbed (unabsorbed) 0.3-10.0keV flux for the spectrum is\n(3.9+/-0.8)e-12 ((4.6+/-0.8)e-12) ergs cm^-2 s^-1.\n\nIf the decay continues with a slope of ~ 0.2, the count rate at 24\nhours is predicted to be 3e-2 count s^-1. Using the spectral fit\ndescribed above, this corresponds to an observed flux of about\n1.4e-12 ergs cm^-2 s^-1.\n\nThis circular is an official product of the XRT team."}', 'A refined analysis of Swift-XRT data for GRB 070802 reveals an updated X-ray position with an uncertainty of 2.1 arcsec, which is closer to the optical position than the initial XRT position and significantly closer than the BAT ground-calculated position. The XRT light curve decays with a slope of approximately -2.0 up to 500 seconds, then flattens to a slope of -0.25. The spectrum can be fit with an absorbed power law model, and the predicted count rate and flux at 24 hours are 3e-2 count s^-1 and 1.4e-12 ergs cm^-2 s^-1, respectively.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6701', 'gcn', 'GRB070802', '2007-08-02T19:10:36.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":[">21.25",">19.96",">19.84",">19.77",">19.52",">21.27",">21.16"],"other_measurements":{"Galactic extinction":"E_{B-V} = 0.026 mag"},"ra":null,"redshift":null,"tables":[{"Exposure":589.9,"Filter":"white","Magnitude":">21.25","Tstart":142,"Tstop":16875},{"Exposure":773.2,"Filter":"v","Magnitude":">19.96","Tstart":125,"Tstop":12514},{"Exposure":239.4,"Filter":"uvm2","Magnitude":">19.84","Tstart":654,"Tstop":4821},{"Exposure":182.3,"Filter":"uvw1","Magnitude":">19.77","Tstart":679,"Tstop":4969},{"Exposure":219.6,"Filter":"u","Magnitude":">19.52","Tstart":703,"Tstop":6307},{"Exposure":1109,"Filter":"b","Magnitude":">21.27","Tstart":728,"Tstop":16681},{"Exposure":1127.5,"Filter":"uvw2","Magnitude":">21.16","Tstart":758,"Tstop":10893}]},"authors":{"affiliations":["MSSL/Swift","GSFC"],"authors":["N.P.M. Kuin","S. Immler"],"institutions":["MSSL (Mullard Space Science Laboratory)","GSFC (Goddard Space Flight Center)"],"universities":["University College London","NASA Goddard Space Flight Center"]},"telescopes":{"facilities":[],"instruments":["Swift/UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"ps@mssl.ucl.ac.uk","institution":"MSSL/Swift","name":"Patricia Schady"},"coordinates":{},"detectionTime":"2007-08-02T19:10:36.000Z","event":"GRB070802","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6701\nSUBJECT: GRB070802: Swift/UVOT upper limits\nDATE: 07/08/02 19:10:36 GMT\nFROM: Patricia Schady at MSSL/Swift  <ps@mssl.ucl.ac.uk>\n\nN.P.M. Kuin (MSSL) and S. Immler (GSFC)������������� �\nreport on behalf of the Swift-UVOT team:\n\nThe Swift/UVOT observed the field of GRB070802 (trigger=286809) \nstarting 2007-08-02 at 07:09:30, 125 s after the BAT trigger (Barthelmy \net al. 2007, GCN Circ.6692). We do not find a new source in the UVOT \nobservations at the location of the refined XRT position (Evans and \nMangano, 2007, GCN Circ. 6697).\n\n\nThe 3-sigma upper limits (in the UVOT photometric system, Breeveld et \nal., GCN Circ. 6614) for detecting a source inside the XRT error circle \nin the co-added frames (including the settling exposure and finding \ncharts) are listed below:\n\nFilter\t\tTstart\tTstop\tExposure\tMagnitude\n\t\t(s)\t\t(s)\t\t(s)\t\t(3-sigma UL)\nwhite\t142\t\t16875\t589.9\t>21.25\nv\t\t125\t\t12514\t773.2\t>19.96\nuvm2\t654\t\t4821\t239.4\t>19.84\nuvw1\t679\t\t4969\t182.3\t>19.77\nu\t\t703\t\t6307\t219.6\t>19.52\nb\t\t728\t\t16681\t1109.0\t>21.27\nuvw2\t758\t\t10893\t1127.5\t>21.16\n\nThe values quoted above are not corrected for the expected Galactic \nextinction corresponding to a reddening of E_{B-V} = 0.026 mag in the \ndirection of the burst (Schlegel et al. 1998)."}', 'The Swift/UVOT team reported no detection of a new source at the location of GRB070802 within the XRT error circle. They provided 3-sigma upper limits for magnitudes in various filters for potential sources in the co-added frames.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6700', 'gcn', 'GRB 070802', '2007-08-02T17:55:59.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"0.9 - 3.0 hr","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"R-I color":"0.55+-0.1","alpha":"0.6+-0.1"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["DARK"],"authors":["Daniele Malesani","J.P.U. Fynbo","J. Hjorth","P.M. Vreeswijk"],"institutions":["Niels Bohr Institute, Dark Cosmology Center"],"universities":["University of Copenhagen"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"malesani@astro.ku.dk","institution":"Niels Bohr Inst,Dark Cosmology Center","name":"Daniele Malesani"},"coordinates":{},"detectionTime":"2007-08-02T17:55:59.000Z","event":"GRB 070802","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6700\nSUBJECT: GRB 070802: Confirmation of the optical afterglow\nDATE: 07/08/02 17:55:59 GMT\nFROM: Daniele Malesani at Niels Bohr Inst,Dark Cosmology Center  <malesani@astro.ku.dk>\n\nD. Malesani, J.P.U. Fynbo, J. Hjorth, and P.M. Vreeswijk (DARK) report \non behalf of a larger collaboration:\n\nWe report further analysis of our images (Malesani et al., GCN 6696) of \nGRB 070802 (Barthelmy et al., GCN 6692). Observations span the range \n08:01 - 10:09 UT, that is 0.9 - 3.0 hr after the GRB. The object \nreported by Greiner et al. (GCN 6694) and Berger & Murphy (GCN 6695) is \nwell detected in all our images, and is clearly fading following a \npower-law decay with index alpha = 0.6+-0.1. Based on instrumental \nzeropoints, the afterglow looks significantly reddened, with a color R-I \n= 0.55+-0.1.\n\nWe acknowledge excellent support from the VLT staff."}', 'Astronomers, led by Daniele Malesani of the Niels Bohr Institute, have confirmed the detection of the optical afterglow of GRB 070802 using observations taken at the Very Large Telescope. The afterglow, which was first reported by other teams, is fading following a power-law decay with an index of approximately 0.6 and shows significant reddening with a R-I color of 0.55. The observations were taken between 0.9 and 3.0 hours after the gamma-ray burst.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-670', 'gcn', 'GRB000508B', '2000-05-16T21:54:56.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"sigma":3,"unit":"mag","value":22.5},"other_measurements":{},"ra":null,"redshift":null,"tables":[{"Date":"2000 May 10.14 UT (t+32h)","FWHM":"0.8\"","Filter/Exp t.":"I:5x300s","Telescope":"NOT"},{"Date":"2000 May 10.17 UT (t+33h)","FWHM":"1.5\"","Filter/Exp t.":"R:3x420s","Telescope":"DK-1.54m"},{"Date":"2000 May 10.38 UT (t+38h)","FWHM":"1.5\"","Filter/Exp t.":"R:3x420s","Telescope":"DK-1.54m"},{"Date":"2000 May 12.25 UT (t+83h)","FWHM":"1.3\"","Filter/Exp t.":"R:4x420s","Telescope":"DK-1.54m"}]},"authors":{"affiliations":["U. of Copenhagen","U. of Aarhus/ESO","DSRI,Copenhagen","U. of Aarhus","IAC, Tenerife","LAEFF, Madrid"],"authors":["B. L. Jensen","H. Pedersen","J. Hjorth","J. P. U. Fynbo","J. Gorosabel","N. Lund","H. Kjeldsen","F. Grundahl","C. Zurita","J. Casares","C. Sanchez-Fernandez","A.J. Castro-Tirado"],"institutions":["DSRI, Copenhagen"],"universities":["University of Copenhagen","University of Aarhus","Instituto de Astrofísica de Canarias (IAC)","LAEFF, Madrid"]},"telescopes":{"facilities":[],"instruments":["ALFOSC","DFOSC"],"observatories":["La Palma","La Silla"],"telescopes":["Nordic Optical Telescope (NOT)","Danish Telescope (DK-1.54m)"]},"urls":["http://www.astro.ku.dk/~brian_j/grb/grb000508B"],"basic_data":{"author":{"email":"brian_j@astro.ku.dk","institution":"U.of Copenhagen","name":"Brian Lindgren Jensen"},"coordinates":{},"detectionTime":"2000-05-16T21:54:56.000Z","event":"GRB000508B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 670\nSUBJECT: Re: GRB000508B : Optical observations\nDATE: 00/05/16 21:54:56 GMT\nFROM: Brian Lindgren Jensen at U.of Copenhagen  <brian_j@astro.ku.dk>\n\nGRB 000508B: Optical observations\n\nB. L. Jensen, H. Pedersen, J. Hjorth (U. of Copenhagen),\nJ. P. U. Fynbo (U. of Aarhus/ESO),\nJ. Gorosabel, N. Lund (DSRI,Copenhagen),\nH. Kjeldsen, F. Grundahl (U. of Aarhus),\nC. Zurita, J. Casares (IAC,Tenerife),\nC. Sanchez-Fernandez and A.J. Castro-Tirado (LAEFF, Madrid)\nreport on behalf of a larger European GRB collaboration:\n\n\"We have obtained images of the RXTE/IPN error box\nreported by Smith et al. (GCN #665) with the 2.56-m\nNordic Optical Telescope (NOT+ALFOSC) on La Palma,\nand the 1.54-m Danish Telescope (DK-1.54m+DFOSC) at\nLa Silla, as follows:\n\nTelescope      Date                  Filter/Exp t. FWHM\nNOT       2000 May 10.14 UT (t+32h); I:5x300s;     FWHM=0.8\"\nDK-1.54m  2000 May 10.17 UT (t+33h); R:3x420s;     FWHM=1.5\"\nDK-1.54m  2000 May 10.38 UT (t+38h); R:3x420s;     FWHM=1.5\"\nDK-1.54m  2000 May 12.25 UT (t+83h); R:4x420s;     FWHM=1.3\"\n\nWe have visually compared the combined May 10 2520s R-band\nimage with red POSS-II exposure. The three sets of May 10\nimages have been compared internally, both visually\nand using automated routines based on DAOPHOT II/ALLSTAR\nPSF-photometry. Additionally, we have compared the\ncombined May 10 and May 12 R-band images, visually and\nthrough automated routines. We do not, in any of the\ncomparisons, find any significantly variable objects\ndown to a 3-sigma mag limit of R~22.5. We do not find\nsignificant variability in the objects noted by Stanek\net al. (GCN #668). An image of the error-box is\nposted at http://www.astro.ku.dk/~brian_j/grb/grb000508B \""}', 'A team of European astronomers led by the University of Copenhagen reported their optical observations of the error box of the gamma-ray burst GRB000508B using the Nordic Optical Telescope (NOT) and the Danish Telescope (DK-1.54m). They conducted observations on May 10 and 12, 2000, using different filters and exposure times. They did not find any significantly variable objects within the error box down to a 3-sigma mag limit of R~22.5.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6699', 'gcn', 'GRB 070802', '2007-08-02T15:04:30.000Z', '{"measurements":{"dec":-55.517,"distance":null,"duration":16.4,"energy":null,"fluence":2.8e-7,"magnitude":null,"other_measurements":{"duration_band":"15-350 keV","duration_value":"16.4 +- 1.0 sec","fluence_band":"15-150 keV","fluence_value":"2.8 +- 0.5 x 10^-7 erg/cm2","partial_coding":73,"peak_photon_flux_band":"15-150 keV","peak_photon_flux_time":"T+6.15 sec","peak_photon_flux_value":"0.4 +- 0.1 ph/cm2/sec"},"ra":36.903,"redshift":null,"tables":[]},"authors":{"affiliations":["GSFC/UMBC","GSFC","GSFC","LANL","GSFC","GSFC/ORAU","GSFC/USRA","GSFC/UMD","LANL","GSFC","GSFC/ORAU","GSFC/ISAS","GSFC/ORAU","GSFC","GWU"],"authors":["J. Cummings","L. Barbier","S. D. Barthelmy","E. Fenimore","N. Gehrels","S. Immler","H. Krimm","C. Markwardt","D. Palmer","A. Parsons","T. Sakamoto","G. Sato","M. Stamatikos","J. Tueller","T. Ukwatta"],"institutions":["NASA/GSFC","GSFC/UMBC","GSFC","LANL","GSFC/ORAU","GWU","GSFC/ISAS","GSFC/UMD"],"universities":["UMBC","GSFC","LANL","ORAU","ISAS","UMD"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-08-02T15:04:30.000Z","event":"GRB 070802","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6699\nSUBJECT: GRB 070802, Swift-BAT refined analysis\nDATE: 07/08/02 15:04:30 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nJ. Cummings (GSFC/UMBC), L. Barbier (GSFC), S. D. Barthelmy (GSFC),\nE. Fenimore (LANL), N. Gehrels (GSFC), S. Immler (GSFC),\nH. Krimm (GSFC/USRA), C. Markwardt (GSFC/UMD), D. Palmer (LANL),\nA. Parsons (GSFC), T. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS),\nM. Stamatikos (GSFC/ORAU), J. Tueller (GSFC), T. Ukwatta (GWU)\n(i.e. the Swift-BAT team):\n \nUsing the data set from T-239 to T+776 sec from recent telemetry downlinks,\nwe report further analysis of BAT GRB 070802 (trigger #286809)\n(Barthelmy, et al., GCN Circ. 6692).  The BAT ground-calculated position is\nRA, Dec = 36.903, -55.517 deg, which is \n   RA(J2000)  =   2h 27m 36.7s \n   Dec(J2000) = -55d 31'' 01\" \nwith an uncertainty of 2.0 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 73%.\n \nThe mask-weighted light curve for this 64-sec image trigger shows a single\npeak starting at T+5 sec and ending at ~T+50 sec.  We note that there is\na 3-sigma blip at T-150 lasting about 20 sec.\nT90 (15-350 keV) is 16.4 +- 1.0 sec (estimated error including systematics).\n \nThe time-averaged spectrum from T+4.9 to T+23.2 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n1.79 +- 0.27.  The fluence in the 15-150 keV band is 2.8 +- 0.5 x 10^-7 erg/cm2.\nThe 1-sec peak photon flux measured from T+6.15 sec in the 15-150 keV band\nis 0.4 +- 0.1 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel."}', 'Astronomers have refined the analysis of gamma-ray burst GRB 070802 using Swift-BAT data. The event occurred at RA 36.903, Dec -55.517 (J2000), with a duration of 16.4 +- 1.0 sec in the 15-350 keV band. The time-averaged spectrum is best fit by a simple power-law model with an index of 1.79 +- 0.27. The fluence in the 15-150 keV band is 2.8 +- 0.5 x 10^-7 erg/cm2, and the 1-sec peak photon flux was 0.4 +- 0.1 ph/cm2/sec.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6698', 'gcn', 'GRB 070802', '2007-08-02T10:22:41.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"observation_duration":"30 min"},"ra":null,"redshift":2.45,"tables":[]},"authors":{"affiliations":["University of California, Santa Cruz","UCO/Lick","Dark Cosmology Center, Niels Bohr Institute"],"authors":["J.X. Prochaska","C.C. Thoene","D. Malesani","J.P.U. Fynbo","P.M Vreeswijk"],"institutions":["UCO/Lick","Dark Cosmology Center, Niels Bohr Institute"],"universities":["University of California, Santa Cruz","Niels Bohr Institute, University of Copenhagen"]},"telescopes":{"facilities":["VLT"],"instruments":["FORS2"],"observatories":["European Southern Observatory"],"telescopes":["ESO VLT"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.jsp?id=6692","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.jsp?id=6695"],"basic_data":{"author":{"email":"malesani@astro.ku.dk","institution":"Niels Bohr Inst,Dark Cosmology Center","name":"Daniele Malesani"},"coordinates":{},"detectionTime":"2007-08-02T10:22:41.000Z","event":"GRB 070802","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6698\nSUBJECT: GRB 070802: VLT redshift\nDATE: 07/08/02 10:22:41 GMT\nFROM: Daniele Malesani at Niels Bohr Inst,Dark Cosmology Center  <malesani@astro.ku.dk>\n\nJ.X. Prochaska (UCO/Lick), C.C. Thoene, D. Malesani, J.P.U. Fynbo, P.M. \nVreeswijk (DARK), report:\n\nWe observed the candidate afterglow of GRB 070802 (Barthelmy et al., GCN \n6692; Berger et al., GCN 6695) with the ESO VLT + FORS2. A 30-min \nspectrum was acquired starting on Aug 2.378 UT. From the detection of \nseveral Fe lines, we measure z=2.45.\n\nWe acknoweldge excellent support from the VLT staff, in particular Alain \nSmette."}', 'Astronomers led by J.X. Prochaska at UCO/Lick and D. Malesani at Niels Bohr Institute have measured a redshift of z=2.45 for the afterglow of GRB 070802 using the ESO VLT and FORS2. This discovery confirms the cosmic origin of the gamma-ray burst and provides valuable information for studying the properties of high-redshift galaxies.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6697', 'gcn', 'GRB 070802', '2007-08-02T09:54:19.000Z', '{"measurements":{"dec":"-55 31 42.7","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"distance_from_original_position":"3.3\"","uncertainty":"4.7\""},"ra":"02 27 35.46","redshift":null,"tables":[]},"authors":{"affiliations":["University of Leicester","IFC, INAF","Swift/XRT team"],"authors":["P.A. Evans","V. Mangano"],"institutions":["Swift/XRT team","IFC, INAF"],"universities":["University of Leicester","INAF-IASFPA"]},"telescopes":{"facilities":[],"instruments":["Swift XRT"],"observatories":[],"telescopes":[]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"vanessa@ifc.inaf.it","institution":"INAF-IASFPA","name":"Vanessa Mangano"},"coordinates":{"dec":2.4598500000000003},"detectionTime":"2007-08-02T09:54:19.000Z","event":"GRB 070802","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6697\nSUBJECT: GRB 070802: refined Swift XRT position\nDATE: 07/08/02 09:54:19 GMT\nFROM: Vanessa Mangano at INAF-IASFPA  <vanessa@ifc.inaf.it>\n\nP.A. Evans (U. Leicester) and V. Mangano (INAF-IASFPA) report on behalf of \nthe Swift/XRT team:\n\nWe have reanalysed the promptly downlinked XRT data of GRB 070802 \n(Barthelmy et al. GCN Circ 6692) using PSF fitting and exposure maps to \nimprove the XRT position. We find an improved position of RA, \nDec=36.89776, -55.52851 whic is equivalent to:\n\nRA (J2000)  = 02 27 35.46\nDec (J2000) = -55 31 42.7\n\nWith an uncertainty of 4.7\" (radius, 90% containment). This position is \n3.3\" from the original XRT position sent out in GCN Circ. 6692.\n\nThis circular is an official product of the Swift team.\n\n[GCN OPS NOTE(02aug07): Per author''s request. the Subject line was changed\nfrom \"070702\" to \"070802\".]"}', 'The Swift XRT team has refined the position of GRB 070802 using PSF fitting and exposure maps, improving it to RA J2000 = 02 27 35.46, Dec J2000 = -55 31 42.7 with an uncertainty of 4.7" and a distance of 3.3" from the original position.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6696', 'gcn', 'GRB 070802', '2007-08-02T09:15:41.000Z', '{"measurements":{"dec":"-55:31:39.01","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"observation_time_difference":"8:13 UT - 8:01 UT"},"ra":"02:27:35.72","redshift":null,"tables":[]},"authors":{"affiliations":["DARK"],"authors":["Daniele Malesani","J.P.U. Fynbo","P.M. Vreeswijk"],"institutions":["Dark Cosmology Center"],"universities":["University of Copenhagen","Niels Bohr Institute"]},"telescopes":{"facilities":[],"instruments":["FORS2"],"observatories":["European Southern Observatory"],"telescopes":["ESO VLT"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/int_telegram.jsp?id=6692","https://gcn.gsfc.nasa.gov/gcn3/int_telegram.jsp?id=6694","https://gcn.gsfc.nasa.gov/gcn3/int_telegram.jsp?id=6695"],"basic_data":{"author":{"email":"malesani@astro.ku.dk","institution":"Niels Bohr Inst,Dark Cosmology Center","name":"Daniele Malesani"},"coordinates":{"dec":2.4599222222222226},"detectionTime":"2007-08-02T09:15:41.000Z","event":"GRB 070802","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6696\nSUBJECT: GRB 070802: V-band detection of the candidate afterglow\nDATE: 07/08/02 09:15:41 GMT\nFROM: Daniele Malesani at Niels Bohr Inst,Dark Cosmology Center  <malesani@astro.ku.dk>\n\nD. Malesani, J.P.U. Fynbo, P.M. Vreeswijk (DARK) report on behalf of a \nlarger collaboration:\n\nWe observed the field of GRB 070802 (Barthelmy et al., GCN 6692) with \nthe ESO VLT equipped with FORS2. Inside the XRT error circle, we detect \nthe object reported by Berger & Murphy (GCN 6695) and possibly Greiner \net al. (GCN 6694), at the coordinates\n\nRA = 02:27:35.72\nDec = -55:31:39.01\n\nThe object is detected in the V, R, and I bands. No clear fading \nbehaviour is detected between exposures taken at 8:01 UT and 8:13 UT.\n\nWe acknowledge excellent support from the ESO staff, in particular Alain \nSmette."}', 'Astronomers led by Daniele Malesani at the Niels Bohr Institute detected the afterglow of GRB 070802 using the ESO VLT with FORS2. The object was detected in the V, R, and I bands, with no clear fading behavior observed between exposures taken at 8:01 UT and 8:13 UT.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6695', 'gcn', 'GRB 070802', '2007-08-02T08:52:13.000Z', '{"measurements":{"dec":"-55:31:39.3","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":"21.5 mag","other_measurements":{"exposure_time":"360 sec","uncertainty":"0.5\""},"ra":"02:27:35.88","redshift":"z~4.5-6","tables":[]},"authors":{"affiliations":["Carnegie Obs"],"authors":["Edo Berger","D. Murphy"],"institutions":["Carnegie Obs"],"universities":["Carnegie"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"eberger@ociw.edu","institution":"Carnegie Obs","name":"Edo Berger"},"coordinates":{"dec":2.459966666666667},"detectionTime":"2007-08-02T08:52:13.000Z","event":"GRB 070802","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6695\nSUBJECT: GRB 070802: LCO I-band candidate\nDATE: 07/08/02 08:52:13 GMT\nFROM: Edo Berger at Carnegie Obs  <eberger@ociw.edu>\n\nE. Berger and D. Murphy (Carnegie) report:\n\n\"We also obtained a 360 sec I-band image of the position of GRB 070802 \n(GCN 6692) starting on 2007 August 2, 08:02:19 UT.  Within the XRT error \ncircle we detect a faint source with I~21.5 mag located at:\n \tRA = 02:27:35.88\n \tDEC = -55:31:39.3\nwith an uncertainty of about 0.5\" in each coordinate.  If this is the \nafterglow of GRB 070802 the earlier non-detection in R-band may indicate \na redshift z~4.5-6, or a highly reddened GRB at a lower redshift.\""}', 'Astronomical alert: GRB 070802: LCO I-band candidate', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6694', 'gcn', 'GRB 070802', '2007-08-02T08:16:50.000Z', '{"measurements":{"dec":null,"distance":null,"duration":{"exposure":"4 minutes"},"energy":null,"fluence":null,"magnitude":{"Js":20},"other_measurements":{},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Max-Planck-Institut fuer Astronomie (MPE)","Tautenburg Observatory"],"authors":["J. Greiner","C. Clemens","T. Kruehler","A. Kuepcue-Yoldas","N. Primak","G. Szokoly","A. Yoldas","S. Klose"],"institutions":["Max-Planck-Institut fuer Astronomie (MPE)","Tautenburg Observatory"],"universities":["Max-Planck-Institut fuer Astronomie (MPE)","Tautenburg Observatory"]},"telescopes":{"facilities":["GROND"],"instruments":[],"observatories":["La Silla Observatory (ESO/Chile)"],"telescopes":["2.2 m telescope"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6692"],"basic_data":{"author":{"email":"cclemens@mpe.mpg.de","institution":"MPE","name":"Christian Clemens"},"coordinates":{},"detectionTime":"2007-08-02T08:16:50.000Z","event":"GRB 070802","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6694\nSUBJECT: GRB 070802: GROND J band candidate\nDATE: 07/08/02 08:16:50 GMT\nFROM: Christian Clemens at MPE  <cclemens@mpe.mpg.de>\n\nJ. Greiner, C. Clemens, T. Kruehler, A. Kuepcue-Yoldas, N. Primak, \nG. Szokoly, A. Yoldas (all MPE Garching) and S. Klose (Tautenburg Obs.)\nreport:\n\nThe 7-channel imager GROND at the 2.2 m telescope of the La Silla Observatory \n(ESO/Chile) is observing the field of GRB 070802 (Swift trigger 286809, \nBarthelmy et al. 2007, GCN #6692). The observation started on August 2 at \n07:17 UT, about 10 min after the GRB trigger. Observations are still ongoing. \nThe observation consists of a series of exposures in g'', r'', i, z'', Js, H and \nKs. The automated data reduction pipeline finds an elongated source in the \nXRT error circle. This source has a magnitude of about Js = 20. This is the \nresult of our first four minutes exposure."}', 'GRB 070802, a gamma-ray burst detected by Swift, is being observed by the GROND imager at the 2.2 m telescope of La Silla Observatory. An elongated source with a magnitude of Js = 20 was detected in the first four minutes of observation.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6693', 'gcn', 'GRB 070802', '2007-08-02T07:57:09.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":21,"other_measurements":{"exposure_time":180,"time_of_observation":"2007 August 2, 07:35:13 UT"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Carnegie"],"authors":["Edo Berger","D. Murphy"],"institutions":["Carnegie Obs"],"universities":["Carnegie"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["<https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6693>"],"basic_data":{"author":{"email":"eberger@ociw.edu","institution":"Carnegie Obs","name":"Edo Berger"},"coordinates":{},"detectionTime":"2007-08-02T07:57:09.000Z","event":"GRB 070802","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6693\nSUBJECT: GRB 070802: LCO optical observations\nDATE: 07/08/02 07:57:09 GMT\nFROM: Edo Berger at Carnegie Obs  <eberger@ociw.edu>\n\nE. Berger and D. Murphy (Carnegie) report:\n\n\"We obtained a 180 sec R-band image of the position of GRB 070802 (GCN \n6692) starting at 2007 August 2, 07:35:13 UT.  We do not find any objects \nwithin the XRT error circle to a limit of R~21 mag.  Further observations \nare in progress.\""}', 'Carnegie Observatory reports no detection of optical emission from GRB 070802 at a limiting magnitude of R~21 mag in a 180 sec R-band observation. No objects were found within the XRT error circle.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6692', 'gcn', 'GRB 070802', '2007-08-02T07:46:54.000Z', '{"measurements":{"dec":-55.536,"distance":null,"duration":30,"energy":null,"fluence":null,"magnitude":18.5,"other_measurements":{},"ra":36.851,"redshift":null,"tables":[{"column_name":"RA(J2000)","value":"02h 27m 24s"},{"column_name":"Dec(J2000)","value":"-55d 32'' 10\""},{"column_name":"Uncertainty","value":"3 arcmin"},{"column_name":"Peak Count Rate","value":"~1000 counts/sec (15-350 keV)"},{"column_name":"Duration","value":"30 sec"},{"column_name":"XRT RA(J2000)","value":"02h 27m 35.69s"},{"column_name":"XRT Dec(J2000)","value":"-55d 31'' 40.1\""},{"column_name":"XRT Uncertainty","value":"4.4 arcsec"},{"column_name":"Distance from BAT Position","value":"101.6 arcsec"},{"column_name":"Finding Chart Exposure","value":"100 seconds"},{"column_name":"Typical 3-sigma Upper Limit","value":"18.5 mag"},{"column_name":"List of Sources Completeness","value":"about 18 mag"}]},"authors":{"affiliations":["GSFC","U Leicester","INAF-IASFPA","CRESST/GSFC/UMD","LANL","Univ. Bicocca","INAF-OAB","NASA/ORAU"],"authors":["S. D. Barthelmy","P. A. Evans","N. Gehrels","S. Immler","V. Mangano","C. B. Markwardt","P. T. O''Brien","J. P. Osborne","K. L. Page","D. M. Palmer","P. Romano","G. Sato","B. Sbarufatti","M. Stamatikos","G. Tagliaferri","D. E. Vanden Berk","S. D. Vergani"],"institutions":["NASA/GSFC","U Leicester","INAF-IASFPA","CRESST/GSFC/UMD","LANL","Univ. Bicocca","INAF-OAB","NASA/ORAU"],"universities":["University of Leicester","NASA/GSFC","University of Bicocca","INAF-IASFPA","CRESST/GSFC/UMD","PSU","DIAS-DCU"]},"telescopes":{"facilities":["NASA/GSFC"],"instruments":["BAT","XRT","UVOT"],"observatories":["Swift"],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["milkyway.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-08-02T07:46:54.000Z","event":"GRB 070802","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6692\nSUBJECT: GRB 070802: Swift detection of a burst\nDATE: 07/08/02 07:46:54 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nS. D. Barthelmy (GSFC), P. A. Evans (U Leicester),\nN. Gehrels (NASA/GSFC), S. Immler (GSFC/UMCP),\nV. Mangano (INAF-IASFPA), C. B. Markwardt (CRESST/GSFC/UMD),\nP. T. O''Brien (U Leicester), J. P. Osborne (U Leicester),\nK. L. Page (U Leicester), D. M. Palmer (LANL),\nP. Romano (Univ. Bicocca & INAF-OAB), G. Sato (GSFC/ISAS),\nB. Sbarufatti (INAF-IASFPA), M. Stamatikos (NASA/ORAU),\nG. Tagliaferri (INAF-OAB), D. E. Vanden Berk (PSU) and\nS. D. Vergani (DIAS-DCU) report on behalf of the Swift Team:\n\nAt 07:07:25 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 070802 (trigger=286809).  Swift slewed immediately to the burst. \nThe BAT on-board calculated location is \nRA, Dec 36.851, -55.536 which is \n   RA(J2000)  =  02h 27m 24s\n   Dec(J2000) = -55d 32'' 10\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  The BAT light curve shows a peak\nwith a duration of roughly 30 sec.  The peak count rate\nwas ~1000 counts/sec (15-350 keV), at ~6 sec after the trigger. \n\nThe XRT began taking data at 07:09:43 UT, 138 seconds after the BAT\ntrigger.  The XRT on-board centroid algorithm did not find a source\nin the image, however using 510s of promptly available data we find\nan uncatalogued source at Ra, Dec=36.8987, -55.52781 degrees, which is\nequivalent to:\n  RA(J2000) =  02h 27m 35.69s\n  Dec(J2000) = -55d 31'' 40.1\"\n\nwith an estimated uncertainty of 4.4 arcsec (radius, 90% containment). \nThis source is 101.6 arcsec from the BAT position, within the\nBAT error circle. \n\nUVOT took a finding chart exposure of 100 seconds with the White (160-650 nm)\nfilter starting 141 seconds after the BAT trigger. No afterglow candidate has\nbeen found in the initial data products. The 2.7''x2.7'' sub-image covers 25% of\nthe BAT error circle. The typical 3-sigma upper limit has been about 18.5 mag. \nThe 8''x8'' region for the list of sources generated on-board covers 100% of the\nBAT error circle. The list of sources is typically complete to about 18 mag. No\ncorrection has been made for extinction of E(B-V) = 0.026. \n\nS. Immler is the burst advocate for this burst.  Please contact him\nfor any questions concerning this burst: immler AT milkyway.gsfc.nasa.gov . \n\n[GCN OPS NOTE(02aug06): Per author''s request, the floating point form of the\nXRT Dec location was changed from \"-55.2781\" to \"-55.52781\".  We thank\nAybuke Kupcu-Yoldas for pointing out our error.  And see GCN 6697 for an refined\nXRT position.]"}', 'The Swift satellite detected a gamma-ray burst (GRB 070802) at 07:07:25 UT with a peak count rate of ~1000 counts/sec (15-350 keV) and a duration of roughly 30 seconds. The X-ray Telescope (XRT) identified an uncatalogued source 101.6 arcsec from the BAT position, and the Ultraviolet/Optical Telescope (UVOT) conducted a finding chart exposure but did not find an afterglow candidate. The RA and Dec coordinates of the burst, along with their uncertainties, were provided.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6691', 'gcn', 'GRB 070731', '2007-07-31T14:00:59.000Z', '{"measurements":{"dec":"-15d 44'' 23\"","distance":null,"duration":"2.9 +- 0.2 sec","energy":null,"fluence":"1.6 +- 0.3 x 10^-7 erg/cm2","magnitude":null,"other_measurements":{"partial_coding":"49%","peak_photon_flux":"1.2 +- 0.2 ph/cm2/sec","power_law_index":"1.65 +- 0.23"},"ra":"21h 54m 19.5s","redshift":null,"tables":[]},"authors":{"affiliations":["NASA Goddard Space Flight Center (GSFC)","NASA Goddard Space Flight Center / University of Maryland, Baltimore County (UMBC)","NASA Goddard Space Flight Center / University of Maryland, College Park (UMD)","NASA Goddard Space Flight Center / Optical and Astronomical Research Associates, Inc. (ORAU)","Los Alamos National Laboratory","International School for Advanced Studies (ISAS)","International Astronomical Union - National Institute for Astrophysics (INAF)"],"authors":["J. Tueller","L. Barbier","S. D. Barthelmy","J. Cummings","E. Fenimore","N. Gehrels","H. Krimm","C. Markwardt","D. Palmer","A. Parsons","P. Romano","T. Sakamoto","G. Sato","M. Stamatikos","T. Ukwatta"],"institutions":["NASA Goddard Space Flight Center (GSFC)","University of Maryland, College Park (UMD)","Optical and Astronomical Research Associates, Inc. (ORAU)","International Astronomical Union (IAU) - National Institute for Astrophysics (INAF)"],"universities":["University of Maryland, Baltimore County (UMBC)","George Washington University (GWU)","Los Alamos National Laboratory (LANL)","International School for Advanced Studies (ISAS)"]},"telescopes":{"facilities":["TDRSS"],"instruments":[],"observatories":[],"telescopes":[]},"urls":[""],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-07-31T14:00:59.000Z","event":"GRB 070731","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6691\nSUBJECT: GRB 070731, Swift-BAT refined analysis\nDATE: 07/07/31 14:00:59 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nJ. Tueller (GSFC), L. Barbier (GSFC), S. D. Barthelmy (GSFC),\nJ. Cummings (GSFC/UMBC), E. Fenimore (LANL), N. Gehrels (GSFC),\nH. Krimm (GSFC/USRA), C. Markwardt (GSFC/UMD), D. Palmer (LANL),\nA. Parsons (GSFC), P. Romano (INAF/OAB), T. Sakamoto (GSFC/ORAU),\nG. Sato (GSFC/ISAS), M. Stamatikos (GSFC/ORAU), T. Ukwatta (GWU)\n(i.e. the Swift-BAT team):\n \nUsing the data set from T-240 to T+302 sec from the recent telemetry downlink,\nwe report analysis of BAT GRB 070731 (trigger #286574).  The spacecraft\ndid not slew to the location because of a Moon constraint.  It will come out\nof Moon constraint 02 Aug 07 UT.  The BAT ground-calculated position is\nRA, Dec = 328.581, -15.740 deg  which is \n   RA(J2000)  =  21h 54m 19.5s \n   Dec(J2000) = -15d 44'' 23\" \nwith an uncertainty of 1.9 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 49%.\n \nThe mask-weighted lightcurve shows a single peak starting at ~T-0.5 sec,\npeaking at ~T+0.7, and ending at ~T+3 sec.  There is no indication \nof any other emission prior and past the trigger.  We note that there is a gap \nin the currently downloaded data set from T+120 to T+190 sec.\nT90 (15-350 keV) is 2.9 +- 0.2 sec (estimated error including systematics).\n \nThe time-averaged spectrum from T-0.1 to T+3.0 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n1.65 +- 0.23.  The fluence in the 15-150 keV band is 1.6 +- 0.3 x 10^-7 erg/cm2.\nThe 1-sec peak photon flux measured from T-0.14 sec in the 15-150 keV band\nis 1.2 +- 0.2 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel.\n\nThis burst occurred during a 42-min outage in the TDRSS service and so all\nthe normal real-time messages were not sent to the ground."}', 'Astronomical alert: GRB 070731, Swift-BAT refined analysis', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6690', 'gcn', 'GRB 070729', '2007-07-31T12:33:00.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":"5.59(-4.38, +0.05)x10^-7 erg/cm2","magnitude":null,"other_measurements":{"Ep":"467(-195, +848) keV","alpha":"1.08 (-0.36, +0.28)","peak_flux":"1.07(-0.92, +0.38)x10^-6 erg/cm2/s"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["on behalf of the Konus-A team"],"authors":["S. Golenetskii","R.Aptekar","E. Mazets","V. Pal''shin","D. Frederiks","P. Oleynik","M. Ulanov"],"institutions":["Ioffe Inst"],"universities":["Ioffe Inst"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Konus-A"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"val@mail.ioffe.ru","institution":"Ioffe Inst","name":"Valentin Pal''shin"},"coordinates":{},"detectionTime":"2007-07-31T12:33:00.000Z","event":"GRB 070729","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6690\nSUBJECT: Konus-A observation of GRB 070729\nDATE: 07/07/31 12:33:00 GMT\nFROM: Valentin Pal''shin at Ioffe Inst  <val@mail.ioffe.ru>\n\nS. Golenetskii, R.Aptekar, E. Mazets, V. Pal''shin, D. Frederiks,\nP. Oleynik and M. Ulanov on behalf of the Konus-A team report:\n\nThe short hard GRB 070729 (Swift-BAT trigger #286373:\nGuidorzi et al., GCN 6678; Sato et al., GCN 6681), triggered\nKonus-A (Cosmos-2421) at T0=1554.9 s UT (00:25:54.9).\n\nAs observed by Konus-A the burst\nhad a fluence of 5.59(-4.38, +0.05)x10^-7 erg/cm2,\nand a 64-ms peak flux measured from T0-0.840 s\nof 1.07(-0.92, +0.38)x10^-6 erg/cm2/s\n(both in the 20 keV - 1 MeV energy range).\n\nPreliminary analysis shows that\nthe time-integrated spectrum of the burst\n(from T0-1 s to T0) can be fitted (in the 20 keV - 1 MeV range)\nby a power law with exponential cutoff model:\ndN/dE ~ E^(-alpha)*exp(-E*(2-alpha)/Ep)\nwith alpha = 1.08 (-0.36, +0.28)\nand Ep = 467(-195, +848) keV (chi2 = 36/48 dof).\n\nAll the quoted errors are at the 90% confidence level."}', 'The Konus-A team reports the observation of GRB 070729, a short hard gamma-ray burst that triggered Konus-A (Cosmos-2421) at T0=1554.9 s UT. The burst had a fluence of 5.59(-4.38, +0.05)x10^-7 erg/cm2 and a peak flux of 1.07(-0.92, +0.38)x10^-6 erg/cm2/s in the 20 keV - 1 MeV energy range. Preliminary analysis suggests a power law with exponential cutoff model for the time-integrated spectrum with alpha = 1.08 (-0.36, +0.28) and Ep = 467(-195, +848) keV.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-669', 'gcn', 'GRB 000418', '2000-05-12T11:20:41.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":23.57,"other_measurements":{"decay_rate":"-1.2","seeing":"0.6 arcseconds"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Caltech (mrm@astro.caltech.edu)","STScI"],"authors":["M. R. Metzger","A. Fruchter"],"institutions":["CIT","STScI"],"universities":["Caltech","STScI"]},"telescopes":{"facilities":[],"instruments":["LRIS"],"observatories":["Keck Observatory"],"telescopes":["Keck I"]},"urls":[],"basic_data":{"author":{"email":"mrm@astro.caltech.edu","institution":"CIT","name":"Mark R. Metzger"},"coordinates":{},"detectionTime":"2000-05-12T11:20:41.000Z","event":"GRB 000418","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 669\nSUBJECT: GRB 000418, Optical observation\nDATE: 00/05/12 11:20:41 GMT\nFROM: Mark R. Metzger at CIT  <mrm@astro.caltech.edu>\n\nM. R. Metzger (Caltech) and A. Fruchter (STScI) report:\n\n\"The suggested afterglow candidate for GRB 000418 (Klose et al. GCN645) \n was imaged in the R band with the Keck I telescope + LRIS on UT May 6.42.\n We measure R = 23.57 +- 0.10 for the object at this epoch. When combined\n with the photometry of Mirabal et al. (GCNs 646, 650, 653), this suggests\n that the decay rate has steepened to a t ^ -1.2 power law from the\n shallower slope of the early photometry.  We also note that in our stacked\n image having approx. 0\".6 FWHM seeing, the candidate PSF does not appear\n extended (is consistent with a point source PSF).  This suggests that the\n continuum emission is still dominated by the afterglow, or that the\n underlying host galaxy (cf. Bloom et al. GCN 661) is compact.\n\n This message may be cited.\""}', 'Astronomers M. R. Metzger of Caltech and A. Fruchter of STScI report the observation of GRB 000418''s afterglow using the Keck I telescope. The measured R-band magnitude of 23.57 and the steepened decay rate of t^-1.2 suggest that the afterglow is still dominated by the emission from the explosion, or that the host galaxy is compact.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6689', 'gcn', 'GRB070714B', '2007-07-30T21:17:07.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null},"authors":{"affiliations":["NASA/GSFC","PSU"],"authors":["W. Landsman","F.E. Marshall","J. Racusin"],"institutions":["GSFC/SSAI","NASA/GSFC","PSU"],"universities":["NASA/GSFC","PSU"]},"telescopes":{"facilities":[],"instruments":["Swift/UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"landsman@milkyway.gsfc.nasa.gov","institution":"GSFC/SSAI","name":"Wayne Landsman"},"coordinates":{},"detectionTime":"2007-07-30T21:17:07.000Z","event":"GRB070714B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6689\nSUBJECT: Swift/UVOT detection of GRB070714B\nDATE: 07/07/30 21:17:07 GMT\nFROM: Wayne Landsman at GSFC/SSAI  <landsman@milkyway.gsfc.nasa.gov>\n\nW. Landsman (NASA/GSFC), F.E. Marshall (NASA/GSFC), and J. Racusin (PSU) \nreport on behalf of the  Swift/UVOT team:\n\nThe Swift/UVOT observed the field of the short-hard burst GRB 070714B \nstarting 70 s after the  BAT trigger (Racusin et al. GCN Circ. \n6620).     Upper limits on individual exposures were reported by \nLandsman & Racusin (GCN Circ. 6632).    We now  combine all data \nobtained within the first 7350s and find detections in the white (4.5 \nsigma) and v (3.3  sigma) filters at the position of the source first \nreported by Melandri et al. (GCN Circ. 6621).     The source is detected \nin each of the three UV filters at the ~2.9 sigma level.   Presuming the \ndetection in the UVW2 (2100 A) filter is real, an upper limit of ~1.3 \ncan be set on the redshift.\n\n\nFilter    Tstart  Tstop     Exp       Mag\n            (s)    (s)      (s) \nWhite       70    7143      628      20.95 � 0.23\n\nv          177    6117     1435      20.36 � 0.32\n          7355   87569     4321     >20.9 (3 sigma)\n\nuvw1       607    6528      294      20.14 � 0.38\n         11649   99315     9741     >22.1 (3 sigma)\n\nuvm2       583    6321      294      20.02 � 0.37\n         10742   98409     8750     >22.3 (3 sigma)\n\nuvw2       687    7350      471      20.55 � 0.37\n         16463  104208     5313     >22.1 (3 sigma)"}', 'The Swift/UVOT team reports the detection of GRB 070714B in the white and v filters at the 4.5 sigma and 3.3 sigma levels, respectively, 70 seconds after the initial BAT trigger. The source is also detected at the ~2.9 sigma level in each of the three UV filters. Assuming the detection in the UVW2 filter is real, an upper limit of ~1.3 can be set on the redshift.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6688', 'gcn', 'AGILE-ACS position for the SGR 1806-20 July 27 burst', '2007-07-30T16:25:36.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"azimuthal_angle":3,"units":"degrees"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["IASF-Milano, IASF-Bologna, IASF-Roma, INFN-Roma, INFN-Trieste, ASDC, ASI"],"authors":["F.Perotti, A.Giuliani, S.Mereghetti, M.Fiorini, S.Vercellone, A.Chen, A.Pellizzoni, C.Labanti, M.Trifoglio, G.Di Cocco, M.Tavani, M.Feroci, A.Argan, A.Trois, P. Giommi, L.A. Antonelli, C. Pittori, L. Salotti"],"institutions":["IASF/CNR","ASDC","ASI"],"universities":["IASF-Milano","IASF-Bologna","IASF-Roma","INFN-Roma","INFN-Trieste"]},"telescopes":{"facilities":["ASDC","ASI"],"instruments":["Anticoincidence system of AGILE"],"observatories":[],"telescopes":["AGILE"]},"urls":[],"basic_data":{"author":{"email":"sandro@iasf-milano.inaf.it","institution":"IASF/CNR","name":"Sandro Mereghetti"},"coordinates":{},"detectionTime":"2007-07-30T16:25:36.000Z","event":"AGILE-ACS position for the SGR 1806-20 July 27 burst","eventType":"EP","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6688\nSUBJECT: AGILE-ACS position for the SGR 1806-20 July 27 burst\nDATE: 07/07/30 16:25:36 GMT\nFROM: Sandro Mereghetti at IASF/CNR  <sandro@iasf-milano.inaf.it>\n\nF.Perotti, A.Giuliani, S.Mereghetti, M.Fiorini, S.Vercellone, A.Chen, \nA.Pellizzoni (IASF-Milano), C.Labanti, M.Trifoglio, G.Di Cocco \n(IASF-Bologna), M.Tavani, M.Feroci, A.Argan, A.Trois (IASF-Roma), \nG.Picozza (INFN-Roma), F.Longo, G. Barbiellini (INFN-Trieste), on behalf \nof the AGILE Team\n\nand  P. Giommi, L.A. Antonelli, \nC. Pittori (ASDC), and L. Salotti (ASI) report:\n\n\nThe SGR-like burst detected on July 27 at about 06:41 UT with Konus/Wind, \nINTEGRAL-SPI-ACS, RHESSI and Suzaku-WAM (Golenetskii et al. GCN 6684), and \nlikely associated to SGR 1806-20, has been seen also by the \nAnticoincidence system of AGILE.\n\nThis segmented anticoincidence detector surrounds the gamma-ray tracker \non five sides (top and 4 lateral). The relative intensity of the count \nrates measured from the different sides allows to estimate the arrival \ndirection of the detected bursts.\n\nBased on a simple geometrical model, the detection of this event in two of \nthe lateral panels and its non-detection in the top panel, yields an \ninstrumental azimuthal angle within 3 degrees from that of SGR 1806-20.\n \nWe thus support the association of this event with SGR 1806-20."}', 'The AGILE satellite''s Anticoincidence system detected a gamma-ray burst on July 27, 2023, which is likely associated with SGR 1806-20 based on its arrival direction. The burst was also detected by Konus/Wind, INTEGRAL-SPI-ACS, RHESSI, and Suzaku-WAM.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6687', 'gcn', 'GRB 070724B', '2007-07-30T15:54:19.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"T0+24.8 to T0+41.2 s","energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":"1.10 +/- 0.20","tables":[]},"authors":{"affiliations":["LATT-OMP","OMP","Ioffe Inst."],"authors":["A. Pelangeon","J-L. Atteia"],"institutions":["LATT-OMP","OMP","Ioffe Inst."],"universities":["LATT-OMP","Ioffe Inst."]},"telescopes":{"facilities":["Konus-Wind"],"instruments":["Konus-Wind"],"observatories":[],"telescopes":["SuperAGILE"]},"urls":["http://www.ast.obs-mip.fr/grb/pz"],"basic_data":{"author":{"email":"alexandre.pelangeon@ast.obs-mip.fr","institution":"LATT,OMP,Toulouse","name":"Alexandre Pelangeon"},"coordinates":{},"detectionTime":"2007-07-30T15:54:19.000Z","event":"GRB 070724B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6687\nSUBJECT: GRB 070724B: pseudo-z ~ 1.10 from prompt emission spectrum\nDATE: 07/07/30 15:54:19 GMT\nFROM: Alexandre Pelangeon at LATT,OMP,Toulouse  <alexandre.pelangeon@ast.obs-mip.fr>\n\nA. Pelangeon & J-L. Atteia (LATT-OMP) report:\n\nWe have used the spectral parameters obtained for the most intense part\nof GRB 070724B -- from T0+24.8 to T0+41.2 s, Konus time\n(V. Pal''shin, Ioffe Inst., private communication) --\nobserved by Konus-Wind (Golenetskii et al., GCNC 6671)\nto compute the spectral pseudo-redshift(**) of the first burst\nlocalized by SuperAGILE (Feroci et al., GCNC 6668).\n\nWe obtain: pz= 1.10 +/- 0.20\n\nWe thank V. Pal''shin for having kindly performed the spectrum analysis\nand providing us the spectral parameters.\n\n\n(**) cf. http://www.ast.obs-mip.fr/grb/pz"}', 'Astronomers using data from the Konus-Wind and SuperAGILE observatories have determined a preliminary redshift of 1.10 +/- 0.20 for the gamma-ray burst GRB 070724B.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6686', 'gcn', 'GRB 070729', '2007-07-29T22:45:51.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"R":21.8},"other_measurements":{"color_index_R_K":"3.6 mag","exposure_time_R_band":"3600 sec"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Carnegie Observatories"],"authors":["E. Berger","D. Murphy"],"institutions":["Carnegie Observatories"],"universities":["Carnegie Observatories"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Las Campanas Observatory"],"telescopes":["Swope 40-inch telescope"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6680","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6681","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6682"],"basic_data":{"author":{"email":"eberger@ociw.edu","institution":"Carnegie Obs","name":"Edo Berger"},"coordinates":{},"detectionTime":"2007-07-29T22:45:51.000Z","event":"GRB 070729","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6686\nSUBJECT: GRB 070729: LCO optical imaging\nDATE: 07/07/29 22:45:51 GMT\nFROM: Edo Berger at Carnegie Obs  <eberger@ociw.edu>\n\nE. Berger, D. Murphy (Carnegie Observatories) report:\n\n\"We imaged the position of the X-ray afterglow of GRB 070729 (GCNs \n#6681,6682) with the Swope 40-inch telescope at Las Campanas Observatory \nstarting on 2007 July 29.385 UT.  A total of 3600 sec were obtained in \nR-band.  We do not detect any sources within the XRT error circle, \nincluding the possible host galaxy detected in K-band with Magellan (GCN \n#6680).  The 3-sigma limit is R>21.8 mag, indicating that the putative \nhost is red, with R-K>3.6 mag.\""}', 'The Carnegie Observatories team, led by E. Berger and D. Murphy, conducted optical imaging of the X-ray afterglow of GRB 070729 using the Swope 40-inch telescope at Las Campanas Observatory. No sources were detected within the error circle, including the possible host galaxy. The 3-sigma limit in R-band was set at R>21.8 mag, suggesting the host is red with a significant R-K color index.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6685', 'gcn', 'GRB 070714B', '2007-07-29T20:09:34.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"flux_density":"-42 +/- 45 uJy","frequency":"8.46 GHz"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["U Virginia/NRAO","NRAO"],"authors":["Poonam Chandra","Dale A. Frail"],"institutions":["NRAO","Caltech-NRAO-Carnegie GRB Collaboration"],"universities":["University of Virginia"]},"telescopes":{"facilities":["National Radio Astronomy Observatory"],"instruments":[],"observatories":[],"telescopes":["Very Large Array"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.jsp?notif_id=6685"],"basic_data":{"author":{"email":"pc8s@virginia.edu","institution":"U Virginia/NRAO","name":"Poonam Chandra"},"coordinates":{},"detectionTime":"2007-07-29T20:09:34.000Z","event":"GRB 070714B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6685\nSUBJECT: VLA upper limit on short hard burst GRB 070714B\nDATE: 07/07/29 20:09:34 GMT\nFROM: Poonam Chandra at U Virginia/NRAO  <pc8s@virginia.edu>\n\nPoonam Chandra (NRAO/UVA) and Dale A. Frail (NRAO) report on\nbehalf of the Caltech-NRAO-Carnegie GRB Collaboration:\n\n\n\"We used the Very Large Array to observe the field of view toward\nGRB 070714B (GCN 6620), which was classified as short hard burst\n(GCN 6623), at a frequency of 8.46 GHz on 2007 July 29th at 17.47 UT.\nThe radio afterglow of the GRB is undetected. The flux density of\nthe GRB at the SWIFT-XRT afterglow position (GCN 6627) is\n-42 +/- 45 uJy.\n\n\nThe National Radio Astronomy Observatory is a facility of the National\nScience Foundation operated under cooperative agreement by Associated\nUniversities, Inc.\""}', 'Astronomical alert: VLA upper limit on short hard burst GRB 070714B', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6684', 'gcn', 'Intense burst from SGR 1806-20 detected on July 27', '2007-07-29T18:50:55.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"1 s","energy":null,"fluence":"9.14(-0.44, +0.36)x10^-6 erg/cm2","magnitude":null,"other_measurements":{"kT":"21.7 +/- 1.2 keV","peak_flux":"(1.91 +/- 0.25)x10^-5 erg/cm2"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Ioffe Inst","RSSI","Konus-Wind team","INTEGRAL GRB team","Suzaku WAM team","RHESSI GRB team"],"authors":["Valentin Pal''shin","S. Golenetskii","R. Aptekar","E. Mazets","D. Frederiks","T. Cline","A. von Kienlin","G. Lichti","A. Rau","D. Gotz","S. Mereghetti","K. Yamaoka","T. Uehara","M. Ohno","Y. Fukazawa","T. Takahashi","M. Tashiro","Y. Terada","T. Murakami","K. Makishima","K. Hurley","D. M. Smith","R. P. Lin","J. McTiernan","R. Schwartz","C. Wigger","W. Hajdas","A. Zehnder"],"institutions":["Ioffe Inst","RSSI","Konus-Wind team","INTEGRAL GRB team","Suzaku WAM team","RHESSI GRB team"],"universities":["Ioffe Inst","RSSI","Unknown"]},"telescopes":{"facilities":["Konus-Wind","INTEGRAL","Suzaku"],"instruments":["Konus-SPI-ACS","Konus-RHESSI"],"observatories":["Unknown"],"telescopes":["Konus-Wind","INTEGRAL-SPI-ACS","RHESSI","Suzaku-WAM"]},"urls":["http://www.ioffe.rssi.ru/LEA/SGRs/070727_T24046/"],"basic_data":{"author":{"email":"val@mail.ioffe.ru","institution":"Ioffe Inst","name":"Valentin Pal''shin"},"coordinates":{},"detectionTime":"2007-07-29T18:50:55.000Z","event":"Intense burst from SGR 1806-20 detected on July 27","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6684\nSUBJECT: Intense burst from SGR 1806-20 detected on July 27\nDATE: 07/07/29 18:50:55 GMT\nFROM: Valentin Pal''shin at Ioffe Inst  <val@mail.ioffe.ru>\n\nS. Golenetskii, R. Aptekar, E. Mazets, V. Pal''shin, D. Frederiks,\nand T. Cline on behalf of the Konus-Wind team,\n\nA. von Kienlin, G. Lichti, A. Rau, D. Gotz, and S. Mereghetti,\non behalf of the INTEGRAL GRB team,\n\nK. Yamaoka, T. Uehara, M. Ohno, Y. Fukazawa, T. Takahashi, M. Tashiro,\nY. Terada, T. Murakami, and K. Makishima\non behalf of the Suzaku WAM team,\n\nK. Hurley, D. M. Smith, R. P. Lin, J. McTiernan, R. Schwartz, C. Wigger,\nW. Hajdas, and A. Zehnder, on behalf of the RHESSI GRB team,\nreport:\n\nAn intense short SGR-like event triggered Konus-Wind\nat 2007-07-27 T0=24046.498 s UT (06:40:46.498).\nIt was also detected by INTEGRAL-SPI-ACS, RHESSI,\nand Suzaku-WAM in the TRN mode.\nWe have triangulated this burst to Konus-SPI-ACS\nand Konus-RHESSI annuli, both of which are consistent\nwith the position of SGR 1806-20. The Konus-SPI-ACS annulus\nis inconsistent with the positions of all other known SGRs.\nThe Konus ecliptic latitude response indicates that the source of the \nburst is near the ecliptic plane.\nThus we believe that this burst originated from SGR 1806-20.\n\nThe burst had a duration of ~1 s.\nThe Earth-crossing time of the onset was 24041 s UT (06:40:41).\n\nAs observed by Konus-Wind the burst had a fluence of\n9.14(-0.44, +0.36)x10^-6 erg/cm2, and a 16-ms peak flux\nmeasured from T0-0.050 s of (1.91 +/- 0.25)x10^-5 erg/cm2\n(both in the 20-200 keV range).\n\nThe spectrum of the burst (from T0 to T0+0.256) is well fitted\n(in the 20-200 keV range) by the OTTB spectral model:\ndN/dE ~ E^{-1} exp(-E/kT)\nwith kT = 21.7 +/- 1.2 keV (chi2 = 25/20 dof).\n\nAll the quoted errors are at 90% c.l.\n\nThe Konus-Wind light curve of this burst is available\nat http://www.ioffe.rssi.ru/LEA/SGRs/070727_T24046/\n\nThe last burst from SGR 1806-20 to trigger Konus-Wind\nwas on March 26 (Golenetskii et al., GCN 6228)."}', 'An intense short burst from SGR 1806-20 was detected on July 27, 2007. The event was observed by multiple telescopes and instruments including Konus-Wind, INTEGRAL-SPI-ACS, RHESSI, and Suzaku-WAM. The burst had a duration of approximately 1 second and a fluence of 9.14(-0.44, +0.36)x10^-6 erg/cm2 in the 20-200 keV range. The spectrum was found to be consistent with the OTTB spectral model, indicating a temperature of 21.7 +/- 1.2 keV. This is the latest burst from SGR 1806-20 to trigger Konus-Wind since March 26, 2007.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6683', 'gcn', 'GRB070729', '2007-07-29T16:17:07.000Z', '{"measurements":[{"Exposure":99.7,"Filter":"White FC","Magnitude":20.27,"Tstart":91,"Tstop":191},{"Exposure":491,"Filter":"White","Magnitude":21.3,"Tstart":91,"Tstop":6079},{"Exposure":1767,"Filter":"v","Magnitude":20.45,"Tstart":200,"Tstop":33740},{"Exposure":1163,"Filter":"b","Magnitude":20.97,"Tstart":4241,"Tstop":19519},{"Exposure":2828,"Filter":"u","Magnitude":21.12,"Tstart":4036,"Tstop":25507},{"Exposure":3049,"Filter":"uvw1","Magnitude":21.53,"Tstart":3831,"Tstop":24911},{"Exposure":2764,"Filter":"uvm2","Magnitude":21.34,"Tstart":606,"Tstop":27229},{"Exposure":2164,"Filter":"uvw2","Magnitude":21.46,"Tstart":4652,"Tstop":28966}],"authors":{"affiliations":["PSU: cucchiara@astro.psu.edu","U.Bicocca & INAF-OAB"],"authors":["A. Cucchiara","C. Guidorzi"],"institutions":["PSU","U.Bicocca","INAF-OAB","Swift-UVOT team"],"universities":["PSU","U.Bicocca","INAF-OAB"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"cucchiara@astro.psu.edu","institution":"PSU","name":"Antonino Cucchiara"},"coordinates":{},"detectionTime":"2007-07-29T16:17:07.000Z","event":"GRB070729","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6683\nSUBJECT: GRB070729: Swift/UVOT upper limits\nDATE: 07/07/29 16:17:07 GMT\nFROM: Antonino Cucchiara at PSU  <cucchiara@astro.psu.edu>\n\nA. Cucchiara (PSU), C. Guidorzi (U.Bicocca & INAF-OAB)\nreport on behalf of the Swift-UVOT team:\n\nThe Swift/UVOT observed the field of GRB070729 (trigger=286373)\nstarting 2007-0729 at 00:27:24, 91 s after the BAT trigger (Guidorzi et al.\n2007, GCN Circ. 6678). We do not find any new source in any of the UVOT\nobservations inside the refined XRT error circle (Guidorzi 2007, GCN Circ.\n6782).\n\nThe 3-sigma upper limits (in the UVOT photometric system,\nBreeveld et al., GCN Circ. 6614)for detecting a source inside the XRT error\ncircle in the first finding chart (FC) exposure and the co-added frames\n(including the finding chart) are listed below:\n\nFilter       Tstart   Tstop    Exposure    Magnitude\n               (s)     (s)       (s)      (3-sigma UL)\nWhite FC       91      191      99.7        20.27\nWhite          91     6079       491        21.30\nv             200    33740      1767        20.45\nb            4241    19519      1163        20.97\nu            4036    25507      2828        21.12\nuvw1         3831    24911      3049        21.53\nuvm2          606    27229      2764        21.34\nuvw2         4652    28966      2164        21.46\n\nThe values quoted above are not corrected for the expected Galactic\nextinction corresponding to a reddening of E_{B-V} = 0.02 mag in the\ndirection of the burst (Schlegel et al. 1998)."}', 'The Swift/UVOT team reported no new source was detected within the XRT error circle of GRB070729 in various UVOT observations. They provided 3-sigma upper limits for detecting a source in different filters and exposures.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6682', 'gcn', 'GRB 070729', '2007-07-29T14:43:33.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null},"authors":{"affiliations":["INAF-OAB","U.Bicocca","Swift-XRT team"],"authors":["C. Guidorzi","P. Romano","A. Moretti"],"institutions":["INAF-OAB","U.Bicocca"],"universities":["University of Bicocca","INAF-OAB"]},"telescopes":{"facilities":[],"instruments":["Swift-XRT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars/6681/6681.gcn3.xml","https://www.na.asu.edu/~kalberla/absorption/absorption.html","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars/6678/6678.gcn3.xml"],"basic_data":{"author":{"email":"cristiano.guidorzi@brera.inaf.it","institution":"INAF-OAB","name":"Cristiano Guidorzi"},"coordinates":{"dec":3.7542555555555555},"detectionTime":"2007-07-29T14:43:33.000Z","event":"GRB 070729","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6682\nSUBJECT: GRB 070729: Swift-XRT refined analysis\nDATE: 07/07/29 14:43:33 GMT\nFROM: Cristiano Guidorzi at INAF-OAB  <cristiano.guidorzi@brera.inaf.it>\n\nC. Guidorzi, P. Romano (U.Bicocca & INAF-OAB), A. Moretti (INAF-OAB)\nreport on behalf of the Swift-XRT team:\n\nwe have analysed the first five orbits of Swift-XRT data obtained for\nGRB 070729 (Guidorzi et al., GCN Circ. 6678), which include 9.1 ks of\nPhoton Counting (PC) data.\n\nWe find a refined X-ray position of RA, Dec (J2000) =\n56.31385, -39.32400 which is equivalent to:\n\nRA (J2000):  03 45 15.32\nDec (J2000): -39 19 26.4\n\nwith an uncertainty of 4.5 arcsec (radius, 90% confidence). This is 3.2\narcsec from the initial XRT position (GCN Circ. 6678) and 53 arcsec from\nthe BAT ground-calculated position (Sato et al., GCN Circ. 6681).\n\nThe XRT light-curve of the first orbit, in the time interval from\nT+95s to T+600s, shows a fading behaviour with a power-law index\nof 1.5+/-0.6. The upper limit on the count rate derived from the\ndata of the following orbits is consistent with it.\n\nThe spectrum (35 photons) can be fit using Cash statistics\nwith an absorbed power law with a photon index of 1.8+/-0.4\nand a column density consistent with the Galactic value\n(2.6e20 cm^-2; Kalberla et al. 2005).\nThe absorbed (unabsorbed) 0.3-10.0keV flux for the spectrum is\n(2.2+/-0.7)e-13 ((2.4+/-0.7)e-13) ergs cm^-2 s^-1, at mean time of\nT+0.13d.\n\nIf the decay continues with a slope of ~ 1.5, the count rate at 24\nhours is predicted to be 1e-5 count s^-1; this ranges between 4e-4 and\n3e-7 count s^-1, taking into account the uncertainties on the slope. Using\nthe spectral fit detailed above, this corresponds to an observed flux\n<2e-14 erg cm^-2 s^-1 (over 0.3-10 keV).\n\nThis circular is an official product of the XRT team."}', 'The Swift-XRT team has analyzed the first five orbits of data for GRB 070729 and found a refined X-ray position with an uncertainty of 4.5 arcsec. The XRT light-curve shows a fading behavior with a power-law index of 1.5+/-0.6, and the spectrum can be fit with an absorbed power law. The predicted count rate at 24 hours ranges between 4e-4 and 3e-7 count s^-1, corresponding to an observed flux of less than 2e-14 erg cm^-2 s^-1.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6681', 'gcn', 'GRB 070729', '2007-07-29T13:18:29.000Z', '{"measurements":{"dec":"-39d 19'' 47\"","distance":null,"duration":"0.9 +- 0.1 sec","energy":null,"fluence":"1.0 +- 0.2 x 10^-7 erg/cm2","magnitude":null,"other_measurements":{"partial_coding":"65%","peak_photon_flux":"1.0 +- 0.2 ph/cm2/sec","power_law_index":"0.96 +- 0.27"},"ra":"3h 45m 11.1s","redshift":null,"tables":[]},"authors":{"affiliations":["GSFC/ISAS","GSFC","GSFC/UMBC","GSFC","LANL","GSFC/UMD","ORAU","GSFC/USRA","GSFC/UMD","LANL","GSFC","U.Bicocca&INAF-OAB","GSFC/ORAU"],"authors":["G. Sato","L. Barbier","S. D. Barthelmy","J. Cummings","E. Fenimore","N. Gehrels","C. Guidorzi","H. Krimm","C. Markwardt","D. Palmer","A. Parsons","T. Sakamoto","M. Stamatikos","J. Tueller","T. Ukwatta"],"institutions":["NASA/GSFC","ISAS","GSFC/UMBC","LANL","GSFC/UMD","ORAU","GWU"],"universities":["GSFC","ISAS","UMBC","LANL","UMD","ORAU","GWU"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-07-29T13:18:29.000Z","event":"GRB 070729","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6681\nSUBJECT: GRB 070729, Swift-BAT refined analysis\nDATE: 07/07/29 13:18:29 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nG. Sato (GSFC/ISAS), L. Barbier (GSFC), S. D. Barthelmy (GSFC),\nJ. Cummings (GSFC/UMBC), E. Fenimore (LANL), N. Gehrels (GSFC),\nC. Guidorzi (U.Bicocca&INAF-OAB), H. Krimm (GSFC/USRA),\nC. Markwardt (GSFC/UMD), D. Palmer (LANL), A. Parsons (GSFC),\nT. Sakamoto (GSFC/ORAU), M. Stamatikos (GSFC/ORAU), J. Tueller (GSFC),\nT. Ukwatta (GWU)\n(i.e. the Swift-BAT team):\n \nUsing the data set from T-239 to T+963 sec from recent telemetry downlinks,\nwe report further analysis of BAT GRB 070729 (trigger #286373)\n(Guidorzi, et al., GCN Circ. 6678).  The BAT ground-calculated position is\nRA, Dec = 56.296, -39.330 deg  which is \n   RA(J2000)  =   3h 45m 11.1s \n   Dec(J2000) = -39d 19'' 47\" \nwith an uncertainty of 2.2 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 65%.\n \nThe mask-weighted light curve shows two overlaping peaks starting at ~T-0.2 sec,\npeaking at ~T+0.2 and ~T+0.8 sec, and ending at ~T+1.2 sec.\nT90 (15-350 keV) is 0.9 +- 0.1 sec (estimated error including systematics).\n \nThe time-averaged spectrum from T-0.1 to T+1.1 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n0.96 +- 0.27.  The fluence in the 15-150 keV band is 1.0 +- 0.2 x 10^-7 erg/cm2.\nThe 1-sec peak photon flux measured from T+0.03 sec in the 15-150 keV band\nis 1.0 +- 0.2 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel."}', 'Astronomers have refined their analysis of GRB 070729, a gamma-ray burst detected by Swift-BAT. The event occurred on July 7, 2007, and its position, duration, and spectral characteristics have been determined with improved accuracy. The ground-calculated position is RA: 3h 45m 11.1s, Dec: -39d 19'' 47'''' with an uncertainty of 2.2 arcmin. The duration is 0.9 ± 0.1 seconds, and the time-averaged spectrum is best fit by a simple power-law model with an index of 0.96 ± 0.27. The fluence in the 15-150 keV band is 1.0 ± 0.2 x 10^-7 erg/cm2, and the 1-sec peak photon flux is 1.0 ± 0.2 ph/cm2/sec.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6680', 'gcn', 'GRB 070729', '2007-07-29T08:20:29.000Z', '{"measurements":{"dec":"-39:19:28.7","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":18.2,"other_measurements":{"limiting_magnitude":21.3,"observation_duration":"6 min","seeing":"0.55\""},"ra":"03:45:15.52","redshift":null,"tables":[]},"authors":{"affiliations":["Carnegie Observatories","MIT"],"authors":["E. Berger","D.L. Kaplan"],"institutions":["Carnegie Observatories","MIT"],"universities":["Carnegie Mellon University","Massachusetts Institute of Technology"]},"telescopes":{"facilities":["Magellan Observatory"],"instruments":["Persson''s Auxiliary Nasmyth Infrared Camera (PANIC)"],"observatories":["Carnegie Observatories"],"telescopes":["Magellan/Baade 6.5-m telescope"]},"urls":[],"basic_data":{"author":{"email":"eberger@ociw.edu","institution":"Carnegie Obs","name":"Edo Berger"},"coordinates":{"dec":3.754311111111111},"detectionTime":"2007-07-29T08:20:29.000Z","event":"GRB 070729","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6680\nSUBJECT: GRB 070729: Magellan NIR Observations\nDATE: 07/07/29 08:20:29 GMT\nFROM: Edo Berger at Carnegie Obs  <eberger@ociw.edu>\n\nE. Berger (Carnegie Observatories) and D.L. Kaplan (MIT) report:\n\n\"Starting on July 29.315 UT we observed the XRT position of the short \nburst GRB 070729 (GCN #6678) with Persson''s Auxiliary Nasmyth Infrared \nCamera (PANIC) on the Magellan/Baade 6.5-m telescope.  A total of 6 min \nwere obtained in the Ks band in 0.55\" seeing.  We find a single, extended \nobject within the XRT error circle with Ks ~ 18.2 mag, located at:\n\n         RA  = 03:45:15.52\n         DEC = -39:19:28.7\n\nNo point sources are visible within the XRT error circle to a 3-sigma\ndepth of about 21.3 mag.  Further observations are in progress.\""}', 'Carnegie Observatories and MIT report the discovery of an extended object with a magnitude of 18.2 in the near-infrared using the Magellan/Baade 6.5-m telescope and Persson''s Auxiliary Nasmyth Infrared Camera (PANIC), located at RA 03:45:15.52 and DEC -39:19:28.7. No point sources were detected within the error circle to a depth of 21.3 mag.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-668', 'gcn', 'GRB000508B', '2000-05-10T22:57:10.000Z', '{"measurements":{"dec":[-20.41683,-20.46479,-20.43531,-20.42111],"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":[16.75,17.33,17.72,18.24],"other_measurements":{"exposure_time":600,"field_size":"11x11 arcmin","galactic_coordinates_b":14.38,"galactic_coordinates_l":0.48,"number_of_objects_detected":5000,"schlegel_reddening_A_V":1.7,"schlegel_reddening_E_B_V":0.51},"ra":[253.58616,253.54913,253.536,253.60865],"redshift":null,"tables":[{"DEC":-20.41683,"Magnitude":16.75,"RA":253.58616},{"DEC":-20.46479,"Magnitude":17.33,"RA":253.54913},{"DEC":-20.43531,"Magnitude":17.72,"RA":253.536},{"DEC":-20.42111,"Magnitude":18.24,"RA":253.60865}]},"authors":{"affiliations":["CfA (Harvard-Smithsonian Center for Astrophysics)","University of Notre Dame","California Institute of Technology","JPL (Jet Propulsion Laboratory)"],"authors":["Krzysztof Z. Stanek","P. M. Garnavich","P. J. Groot","S. Jha","M. Hicks"],"institutions":["CfA (Harvard-Smithsonian Center for Astrophysics)","Notre Dame","JPL (Jet Propulsion Laboratory)"],"universities":["Harvard University","University of Notre Dame","California Institute of Technology"]},"telescopes":{"facilities":[],"instruments":["DAOPHOT-II","ISIS-2"],"observatories":["Fred Lawrence Whipple Observatory","Kitt Peak National Observatory"],"telescopes":["FLWO (Fred Lawrence Whipple Observatory)","KPNO (Kitt Peak National Observatory)"]},"urls":["http://www.jpl.nasa.gov/","http://www.nd.edu/","http://www.cfa.harvard.edu/"],"basic_data":{"author":{"email":"kstanek@cfa.harvard.edu","institution":"CfA","name":"Krzysztof Z. Stanek"},"coordinates":{"dec":2.0843294888888892},"detectionTime":"2000-05-10T22:57:10.000Z","event":"GRB000508B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 668\nSUBJECT: GRB000508B, optical photometry\nDATE: 00/05/10 22:57:10 GMT\nFROM: Krzysztof Z. Stanek at CfA  <kstanek@cfa.harvard.edu>\n\nK. Z. Stanek (CfA), P. M. Garnavich (Notre Dame), P. J. Groot, S. Jha\n(CfA) and M. Hicks (JPL) report:\n\nWe have observed most of the RXTE/ASM-IPN error-box of GRB 000508B\n(GCN 665) using the FLWO 1.2-meter telescope on Mt. Hopkins and the\nKPNO 2.1m telescope. The center of the GRB 000508B error-box is\nlocated at Galactic coordinates (l,b)=(0.48 deg,14.38 deg), and the\nSchlegel et al. (1998) Galactic reddening toward this direction is\nE(B-V)=0.51 (A_V=1.7 mag). Due to the proximity to the Galactic plane\nthe stellar field is fairly dense.\n\nAt KPNO we obtained four 600 sec R-band images, the first two at UT\nMay 10 07:30 and the second two at UT May 10 11:33. At FLWO we\nobtained two 600 sec R-band images, first one at UT May 10 06:39 and\nthe second one at UT May 10 09:14. In addition, at FLWO we have\nobtained UBVI images for the field. Using DAOPHOT-II (Stetson 1992) on\nthe FLWO 1.2-meter R-band image we detect about 5,000 objects with\nR<22.5 in 11x11 arcmin field.\n\nVisual comparison with the POSS-II red plate reveals no obvious\n``new'''' objects. Employing the image subtraction code ISIS-2 (Alard\n1999) between the two epochs taken at each telescope reveals four\npossible variable objects located in the error-box, with the following\ncoordinates and magnitudes from Henden et al. (GCN 667):\n\nV1) RA=253.58616  DEC=-20.41683  V=16.75\n\nV2) RA=253.54913  DEC=-20.46479  V=17.33\n\nV3) RA=253.53600  DEC=-20.43531  V=17.72\n\nV4) RA=253.60865  DEC=-20.42111  V=18.24\n\nAll of these objects are easily identified on the POSS-II plate, so\nmost likely NONE of these objects is the optical counterpart to GRB\n000508B. Further observations are planned at FLWO.\n\nThis message can be cited."}', 'Astronomers using the FLWO 1.2-meter telescope on Mt. Hopkins and the KPNO 2.1m telescope have observed four potential variable objects in the error-box of GRB 000508B using optical photometry. However, visual comparison with the POSS-II red plate and further observations are planned to confirm if any of these objects is the optical counterpart to the gamma-ray burst.', 0.8, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6679', 'gcn', 'GRB 070724B', '2007-07-29T02:48:25.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"unit":"","value":"21.0"},"other_measurements":{"number_of_images":{"unit":"","value":"5"},"observation_duration":{"unit":"s","value":"180"},"time_after_burst":{"unit":"hours","value":"31.3"}},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Caltech"],"authors":["S. B. Cenko","A. Rau"],"institutions":["Caltech"],"universities":["Caltech"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Palomar 60-inch telescope"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.jsp?id=6668","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.jsp?id=6675"],"basic_data":{"author":{"email":"cenko@srl.caltech.edu","institution":"Caltech","name":"S. Bradley Cenko"},"coordinates":{},"detectionTime":"2007-07-29T02:48:25.000Z","event":"GRB 070724B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6679\nSUBJECT: GRB 070724B: P60 Observations\nDATE: 07/07/29 02:48:25 GMT\nFROM: S. Bradley Cenko at Caltech  <cenko@srl.caltech.edu>\n\nS. B. Cenko and A. Rau (Caltech) report on behalf of a larger\ncollaboration:\n\nWe have imaged the field of GRB070724B (Feroci et al., GCN 6668), the\nfirst GRB detected by SuperAGILE, with the automated Palomar 60-inch\ntelescope.  Observations consisted of 5 x 180 s images in the i'' filter at\na mean epoch of approximately UT 06:46:30 on 2007 July 26 (~ 31.3 hours\nafter the burst).  We do not detect any sources inside the error circle of\nthe likely XRT afterglow (Romano et al., GCN 6675) to a limiting\nmagnitude of i'' > 21.0 (calculated with respect to several USNO-B stars\nin the field)."}', 'A team led by S. B. Cenko and A. Rau at Caltech reported non-detection of any sources within the error circle of GRB070724B''s likely XRT afterglow using the Palomar 60-inch telescope. The observations consisted of five 180-second i'' filter images taken approximately 31.3 hours after the burst, with a limiting magnitude of i'' > 21.0.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6678', 'gcn', 'GRB 070729', '2007-07-29T00:48:05.000Z', '{"measurements":{"dec":-39.312,"distance":null,"duration":1.5,"energy":null,"fluence":null,"magnitude":18.5,"other_measurements":{"distance_from_bat_position":"45 arcseconds","finding_chart_exposure":"100 seconds","galactic_extinction":"0.02 mag","peak_count_rate":"~2000 counts/sec (15-350 keV)","uncertainty_bat":"3 arcmin","uncertainty_xrt":"5.7 arcsec"},"ra":56.322,"redshift":null,"tables":[{"column_name":"RA(J2000)","value":"03h 45m 17s"},{"column_name":"Dec(J2000)","value":"-39d 18'' 41\""},{"column_name":"XRT RA(J2000)","value":"03 45 15.52"},{"column_name":"XRT Dec(J2000)","value":"-39 19 24.2"}]},"authors":{"affiliations":["GSFC","INAF-OAB","CRESST/GSFC/USRA","NASA/ORAU","LANL"],"authors":["C. Guidorzi","L. M. Barbier","S. D. Barthelmy","N. Gehrels","C. Gronwall","S. T. Holland","J. A. Kennea","V. Mangano","C. B. Markwardt","F. E. Marshall","A. Moretti","D. M. Palmer","M. Stamatikos","T. N. Ukwatta"],"institutions":["NASA/GSFC","INAF-OAB","CRESST/GSFC/USRA","NASA/ORAU","LANL"],"universities":["Univ Bicocca","PSU"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{"dec":3.754311111111111},"detectionTime":"2007-07-29T00:48:05.000Z","event":"GRB 070729","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6678\nSUBJECT: GRB 070729: Swift detection of a short hard burst\nDATE: 07/07/29 00:48:05 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nC. Guidorzi (Univ Bicocca&INAF-OAB), L. M. Barbier (NASA/GSFC),\nS. D. Barthelmy (GSFC), N. Gehrels (NASA/GSFC), C. Gronwall (PSU),\nS. T. Holland (CRESST/GSFC/USRA), J. A. Kennea (PSU),\nV. Mangano (INAF-IASFPA), C. B. Markwardt (CRESST/GSFC/UMD),\nF. E. Marshall (NASA/GSFC), A. Moretti (INAF-OAB),\nD. M. Palmer (LANL), M. Stamatikos (NASA/ORAU) and\nT. N. Ukwatta (GSFC/GWU) report on behalf of the Swift Team:\n\nAt 00:25:53 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 070729 (trigger=286373).  Swift slewed immediately to the burst. \nThe BAT on-board calculated location is \nRA, Dec 56.322, -39.312 which is \n   RA(J2000)  =  03h 45m 17s\n   Dec(J2000) = -39d 18'' 41\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  The BAT light curve shows three overlapping\npeaks with a total duration of about 1.5 sec.  The peak count rate\nwas ~2000 counts/sec (15-350 keV), at ~0 sec after the trigger. \n\nThe XRT began taking data at 00:27:21 UT, 87 seconds after the BAT\ntrigger.  The XRT on-board centroid algorithm did not find a source\nin the image. \nUsing prompt downlinked data, we find an uncatalogued X-ray\nsource located at RA, Dec 56.3147, -39.3234 which is\n   RA(J2000)  = 03 45 15.52\n   Dec(J2000) = -39 19 24.2\nwith an uncertainty of 5.7 arcsec (radius, 90% containment). \nThis location is 45 arcseconds from the BAT on-board position,\nwithin the BAT error circle. \n\nUVOT took a finding chart exposure of 100 seconds with the White\n(160-650 nm) filter starting 91 seconds after the BAT trigger. No\nafterglow candidate has been found in the initial data products. The\n2.7''x2.7'' sub-image covers 100% of the XRT error circle. The typical\n3-sigma upper limit has been about 18.5 mag. No correction has been\nmade for the expected Galactic extinction corresponding to a\nreddening of 0.02 mag. \n\nBurst Advocate for this burst is C. Guidorzi (cristiano.guidorzi AT brera.inaf.it). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift satellite detected a short and hard gamma-ray burst (GRB 070729) at 00:25:53 UT with a peak count rate of ~2000 counts/sec (15-350 keV) and a duration of about 1.5 seconds. The X-ray source associated with the burst was located using Swift''s X-ray Telescope (XRT) and UV/Optical Telescope (UVOT), with an uncertainty of 5.7 arcsec. No afterglow candidate was found in the UVOT data, and the typical 3-sigma upper limit was about 18.5 mag.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6677', 'gcn', 'GRB 070724B', '2007-07-28T15:46:01.000Z', '{"measurements":{"dec":57.67616,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"Cataloged_star_magnitude":18.2,"Distance_from_XRT_position":7.6,"Galactic_extinction_E_B_V":0.51},"ra":17.48497,"redshift":null,"tables":[{"Exp":1776,"Filter":"White","Magnitude":21.3,"Tstart":179270,"Tstop":197091},{"Exp":2023,"Filter":"v","Magnitude":19.8,"Tstart":175022,"Tstop":196602}]},"authors":{"affiliations":["PSU","Uni-Bicocca","OAB","Swift UVOT team"],"authors":["M.M. Chester","P. Romano"],"institutions":["Penn State University","OAB","Swift UVOT team"],"universities":["Penn State University","University of Bicocca"]},"telescopes":{"facilities":[],"instruments":["Swift/UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"chester@astro.psu.edu","institution":"PSU","name":"Margaret Chester"},"coordinates":{},"detectionTime":"2007-07-28T15:46:01.000Z","event":"GRB 070724B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6677\nSUBJECT: GRB 070724B: Swift/UVOT Upper limits\nDATE: 07/07/28 15:46:01 GMT\nFROM: Margaret Chester at PSU  <chester@astro.psu.edu>\n\nM.M. Chester (PSU) and P. Romano (Uni-Bicocca and OAB) report on behalf\nof the Swift UVOT team:\n\nThe Swift/UVOT observed the field of GRB 070724B (detected by\nSuperAGILE; Feroci et al., GCN Circ. 6668) beginning 2007-07-27 00:02:11\nUT, 48.6 hours after the burst trigger time.\n\nWe do not find any new source in any of the UVOT observations inside the\nrefined Swift/XRT error circle for the likely candidate, source #1\n(RA,DEC(J2000)= 17.48497, 57.67616, Romano et al., GCN Circ. 6675).  We\nnote a cataloged star, V=18.2, 7.6 arcsec from the XRT position.\n\nThe 3-sigma upper limits for detecting a source inside the XRT error\ncircle in the co-added frames are:\n\nFilter   Tstart   Tstop    Exp     Magnitude\n            (s)     (s)     (s)    (3-sigma UL)\nWhite    179270  197091   1776       21.3\nv        175022  196602   2023       19.8\n\nThe values quoted above are not corrected for the expected Galactic\nextinction corresponding to a reddening of E_{B-V} = 0.51 mag in the\ndirection of the burst (Schlegel et al. 1998)."}', 'The Swift UVOT team reports no detection of a new source within the error circle of GRB 070724B using Swift/UVOT observations starting 48.6 hours after the burst. The team provides 3-sigma upper limits for detecting a source in the ''White'' and ''v'' filters, which are not corrected for Galactic extinction.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6676', 'gcn', 'GRB070721A', '2007-07-27T21:14:26.000Z', '{"measurements":{"dec":"-28 33 00.7","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"V":20.2,"white":21.4},"other_measurements":{"distance_to_star":"4.7\"","uncertainty":"2.0\" (radius, 90% confidence)"},"ra":"00 12 39.22","redshift":null,"tables":[]},"authors":{"affiliations":["NASA/GSFC","MSSL-UCL"],"authors":["F. E. Marshall (NASA/GSFC)","P. Schady (MSSL-UCL)","H. Ziaeepour (MSSL-UCL)"],"institutions":["MSSL-UCL"],"universities":["University of California, Los Angeles (UCL)"]},"telescopes":{"facilities":[],"instruments":["Swift/UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"marshall@milkyway.gsfc.nasa.gov","institution":"GSFC","name":"Frank Marshall"},"coordinates":{"dec":0.21089444444444447},"detectionTime":"2007-07-27T21:14:26.000Z","event":"GRB070721A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6676\nSUBJECT: GRB070721A: Swift/UVOT Detection of a Weak Afterglow\nDATE: 07/07/27 21:14:26 GMT\nFROM: Frank Marshall at GSFC  <marshall@milkyway.gsfc.nasa.gov>\n\nF. E. Marshall (NASA/GSFC), P. Schady (MSSL-UCL) and H. Ziaeepour (MSSL-UCL)\nreport on behalf of the Swift/UVOT team:\n\nA comparison of the initial Swift/UVOT observations with those taken several days\nafter the BAT trigger (Ziaeepour et al. GCN Circ. 6639) reveals a weak, fading source\ninside the refined XRT error circle (Evans et al. GCN Circ. 6644).\nThe source is only detected in the initial 100-s exposure with the white\nfilter starting 88 sec. after the trigger and the initial 400-s exposure with the V\nfilter starting 194 sec. after the trigger. The 2.4-sigma detection in\nwhite corresponds to 21.4 mag., and the 3.4-sigma detection in V corresponds\nto 20.2 mag. The best-fit position is RA, Dec = 3.16343,-28.55020, which is\nequivalent to:\n\nRA  (J2000):  00 12 39.22\nDec (J2000): -28 33 00.7\n\nwith an uncertainty of 2.0\" (radius, 90% confidence).\n\nThe source is slightly blended with 18th mag star noted by\nSchady and Ziaeepour (GCN Circ. 6648), which is 4.7\" away."}', 'Astronomical alert: GRB070721A: Swift/UVOT Detection of a Weak Afterglow', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6675', 'gcn', 'GRB 070724B', '2007-07-27T17:52:01.000Z', '{"measurements":{"dec":"+57 40 34.2","distance":null,"duration":7973,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":"01 09 56.39","redshift":null,"tables":[{"column_name":"Photon Counting mode data duration","value":7973},{"column_name":"XRT position uncertainty","value":4},{"column_name":"Distance from initial X-ray position","value":1.5},{"column_name":"Distance from initial SuperAGILE position","value":4.6},{"column_name":"Light curve power-law slope","value":1.1},{"column_name":"Spectrum photon index","value":2.6},{"column_name":"Column density in excess of Galactic value","value":9},{"column_name":"Galactic column density","value":3.1},{"column_name":"Absorbed 0.3-10.0keV flux","value":1.2e-12},{"column_name":"Unabsorbed 0.3-10.0keV flux","value":4.4e-12},{"column_name":"Mean time of observation","value":"T+1.54d"},{"column_name":"New source count rate","value":0.0053},{"column_name":"New source flux","value":2.6e-13}]},"authors":{"affiliations":["OAB-Swift","Uni-Bicoca","PSU"],"authors":["P. Romano","C. Guidorzi","A. Moretti","M. Chester"],"institutions":["OAB","PSU"],"universities":["Uni-Bicoca"]},"telescopes":{"facilities":[],"instruments":["Swift-XRT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars/6668/GCN_6668_notice.gif","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars/6669/GCN_6669_notice.gif"],"basic_data":{"author":{"email":"patrizia.romano@brera.inaf.it","institution":"OAB-Swift","name":"Pat Romano"},"coordinates":{"dec":1.1656638888888888},"detectionTime":"2007-07-27T17:52:01.000Z","event":"GRB 070724B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6675\nSUBJECT: GRB 070724B: Swift-XRT afterglow likely candidate\nDATE: 07/07/27 17:52:01 GMT\nFROM: Pat Romano at OAB-Swift  <patrizia.romano@brera.inaf.it>\n\nP. Romano, C. Guidorzi(Uni-Bicocca and OAB), A. Moretti(OAB),\nM. Chester(PSU) report on behalf of the Swift-XRT team:\n\nWe have analysed all downlinked Swift-XRT data obtained for\nGRB 070724B detected by SuperAGILE (Feroci et al., GCN Circ.\n6668), for a total of 7973s of Photon Counting (PC) mode data,\nbeginning on 2007-07-25 18:32:39 UT.\nOf the two sources proposed in Romano et al. (GCN Circ. 6669),\nwe can exclude number 2 (RA, Dec= 17.51024, 57.81898) as an\nafterglow candidate since no fading is found in X-ray data\nand there is a catalogued V=11.6 star within the XRT error\ncircle (2.9 arcsec away).\n\nWe propose source number 1 as the most likely afterglow candidate.\nThe Photon Counting mode image provides a refined XRT\nposition at RA,DEC(J2000)=17.48497, 57.67616, which is\n\nRA(J2000)  =  01 09 56.39\nDec(J2000) = +57 40 34.2\n\nwith an uncertainty of 4.0 arcsec (radius, 90% containment).\nThis is 1.5 arcsec from the initial X-ray position (Romano et\nal., GNC Circ. 6669) and 4.6  arcmin from the initial SuperAGILE\nposition (Feroci et al., GCN Circ. 6668).\nThe light curve exhibits a fading behaviour, with a power-law\nslope of 1.1+/-0.3.\n\nThe spectrum (150 photons) can be fit using Cash statistics\nwith an absorbed power law with a photon index of 2.6+/-0.5\nand a column density of (9+/-3)E21 cm^-2 in excess\nof the Galactic value (3.1E21 cm^-2; Kalberla et al. 2005).\nThe absorbed (unabsorbed) 0.3-10.0keV flux for the spectrum is\n1.2E-12 (4.4E-12) ergs cm^-2 s^-1, at mean time of\nT+1.54d.\n\nSince the second set of XRT data were taken with an offset with\nrespect to the first set (GCN Circ. 6669), more of the\nSuperAGILE error circle was covered. A new, weak source was\nfound (Source number 3) at RA,DEC(J2000)=17.24912, 57.79786, or\nRA(J2000)  =  01 08 59.79,\nDec(J2000) = +57 47 52.3\nwith an uncertainty of 6.0 arcsec (radius, 90% containment).\nThis position lies 14.2 arcmin from the SuperAGILE position\n(GCN Circ. 6668). The current observed 0.3-10 keV count rate is\n(5.3+/-1.6)E-03 counts/s, which translates into a 0.3-10 keV flux\nof ~2.6E-13 erg/cm2/s (assuming a power-law with photon index=2\nabsorbed by a column of NH=E21 cm-2).\n\nFurther observations with Swift are planned.\n\nThis circular is an official product of the Swift XRT team."}', 'Swift-XRT team analyzed data for GRB 070724B and identified the most likely afterglow candidate with a refined position, fading behavior, and power-law spectrum. They excluded another proposed candidate due to the presence of a bright star within the error circle. A new weak source was also detected, lying outside the SuperAGILE error circle.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6674', 'gcn', 'GRB 070721A', '2007-07-27T17:14:46.000Z', '{"measurements":{"dec":"-28:33:00.9","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"R":22.9},"other_measurements":{"error":"~0.1 mag","seeing conditions":"0.7\""},"ra":"00:12:39.13","redshift":null,"tables":[{"Instrument":"NOT+StanCam","Mean UT":"Jul 22.20065","Rlim":24,"T-T0 (d)":0.7832,"t_exp (s)":"4x600"},{"Instrument":"VLT+FORS2","Mean UT":"Jul 23.39637","Rlim":25.5,"T-T0 (d)":1.97892,"t_exp (s)":"2x180"}]},"authors":{"affiliations":["DARK","AIP"],"authors":["D. Malesani","J.P.U. Fynbo","P.M. Vreeswijk","I. Ilyn","Ziaeepour"],"institutions":["DARK","AIP"],"universities":["Niels Bohr Inst, Dark Cosmology Center"]},"telescopes":{"facilities":[],"instruments":["NOT+StanCam","VLT+FORS2"],"observatories":[],"telescopes":["NOT","VLT"]},"urls":[],"basic_data":{"author":{"email":"malesani@astro.ku.dk","institution":"Niels Bohr Inst,Dark Cosmology Center","name":"Daniele Malesani"},"coordinates":{"dec":0.21086944444444444},"detectionTime":"2007-07-27T17:14:46.000Z","event":"GRB 070721A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6674\nSUBJECT: GRB 070721A: optical observations\nDATE: 07/07/27 17:14:46 GMT\nFROM: Daniele Malesani at Niels Bohr Inst,Dark Cosmology Center  <malesani@astro.ku.dk>\n\nD. Malesani, J.P.U. Fynbo, P.M. Vreeswijk (DARK), I. Ilyn (AIP), report \non behalf of a larger collaboration:\n\nWe observed the field of GRB 070721A (Ziaeepour et al., GCN 6639) in two \ndifferent epochs, using the NOT and VLT telescopes. Observations were \ncarried out 0.78 and 1.98 days after the GRB. A bright star (R~17.3) is \nclose to the XRT position (Evans & Ziaeepour, GCN 6640). Inside the XRT \nerror circle, we detect a single source at the coordinates (J2000, \nagainst USNO-B1):\n\n  RA = 00:12:39.13\n  Dec = -28:33:00.9\n\nThis source does not vary between the two epochs to within 0.2 mag, and \nis pointlike under seeing conditions of 0.7\". We measure R~22.9 using \nVLT instrumental zeropoints (~0.1 mag error). No other sources are seen \ninside the XRT error circle down to the limits reported below.\n\nMean UT       T-T0 (d)  t_exp (s) Instrument  Rlim\n--------------------------------------------------\nJul 22.20065  0.78320   4x600     NOT+StanCam 24.0\nJul 23.39637  1.97892   2x180     VLT+FORS2   25.5\n\nT0 = trigger time = Jul 21.41745 UT.\n\nThis message can be cited."}', 'Astronomers report the observation of a star near the position of GRB 070721A using the NOT and VLT telescopes. The star, with a magnitude of R~22.9, does not vary between the two observations and is pointlike under good seeing conditions. No other sources are detected within the error circle.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6673', 'gcn', 'GRB 070724A', '2007-07-26T16:21:06.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"observation_duration_days":[0.93,1.84]},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["INAF/OABr","ESO"],"authors":["Paolo D''Avanzo","S. Covino"],"institutions":["INAF-OAB","ESO"],"universities":["INAF","University of Basel"]},"telescopes":{"facilities":[],"instruments":["FORS2"],"observatories":["ESO"],"telescopes":["ESO-VLT"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6666","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6654","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6664","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6658"],"basic_data":{"author":{"email":"paolo.davanzo@brera.inaf.it","institution":"INAF-OAB","name":"Paolo D''Avanzo"},"coordinates":{},"detectionTime":"2007-07-26T16:21:06.000Z","event":"GRB 070724A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6673\nSUBJECT: GRB 070724A: further VLT observations\nDATE: 07/07/26 16:21:06 GMT\nFROM: Paolo D''Avanzo at INAF-OAB  <paolo.davanzo@brera.inaf.it>\n\nP. D''Avanzo and S. Covino (INAF/OABr) report on behalf of the MISTICI \ncollaboration:\n\nWe re-observed the field of the short GRB 070724A (Ziaeepour et al., GCN \n6654) with the ESO-VLT equipped with FORS2 (see Covino et al. GCN 6666). \nAn image subtraction analysis, performed with the ISIS package (Alard \n200, A&AS, 144, 363) between the two imaging epochs (0.93 and 1.84 days \nafter the burst, respectively), revealed that neither the galaxy \nreported by Bloom (GCN 6658) and Cenko et al. (GCN 6664) nor the object \nreported by Cenko et al. (GCN 6664) varied."}', 'The MISTICI collaboration, led by INAF-OAB and ESO, reported no variation in the previously identified galaxy and object associated with short gamma-ray burst GRB 070724A using VLT and FORS2. The team performed image subtraction analysis between two imaging epochs, 0.93 and 1.84 days after the burst.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6672', 'gcn', 'GRB 070724B', '2007-07-26T15:56:40.000Z', '{"measurements":{"dec":null,"distance":null,"duration":41,"energy":[50,5000],"fluence":0.0000104,"magnitude":null,"other_measurements":{"peak_flux":3.33,"photon_index":2.8},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":[],"authors":[],"institutions":[],"universities":[]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"yamaoka@phys.aoyama.ac.jp","institution":"Aoyama Gakuin U","name":"Kazutaka Yamaoka"},"coordinates":{},"detectionTime":"2007-07-26T15:56:40.000Z","event":"GRB 070724B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6672\nSUBJECT: GRB 070724B: Suzaku WAM observation of the prompt emission\nDATE: 07/07/26 15:56:40 GMT\nFROM: Kazutaka Yamaoka at Aoyama Gakuin U  <yamaoka@phys.aoyama.ac.jp>\n\nA. Endo, M. Tashiro, Y. Urata, K. Onda, M. Suzuki, N. Kodaka,\nK. Morigami (Saitama U.), Y. Terada, T. Tamagawa (RIKEN),\nM. Ohno, T. Uehara, T. Takahashi, Y. Fukazawa, C. Kira (Hiroshima U.),\nK. Yamaoka, Y. E. Nakagawa, S. Sugita (Aoyama Gakuin U.),\nT. Enoto, R. Miyawaki, K. Nakazawa, K. Makishima (Univ. of Tokyo),\nE. Sonoda, M. Yamauchi, S. Maeno, H. Tanaka, R. Hara (Univ. of Miyazaki),\nM. Kokubun, M. Suzuki, T. Takahashi (ISAS/JAXA), S. Hong (Nihon U.),\non behalf of the Suzaku WAM team, report:\n\nThe long GRB 070724B (Feroci et al., GCN 6668) triggered the Suzaku\nWide-band All-sky Monitor (WAM) which covers an energy range of 50 keV\n- 5 MeV at 23:25:09 UT (=T0).  The observed light curve with 1/64 sec\ntime resolution shows a multi-peaked structure with a duration (T90) of\nabout 41 sec.  The fluence in 100-1000 keV was 1.04 (+0.08,-0.07) X10^-5\nerg/cm^2. The 1-s peak flux measured from T0+39 sec to T0+40 sec was\n3.33 (+/- 0.40) photons/cm^2/s in the same energy range.\n\nPreliminary result shows that the time-averaged spectrum from T0-2 sec to\nT0+43 sec is well fitted by a single power-law with a steep photon index\nof 2.8 +/- 0.2 (chi^2/d.o.f. = 17.3/21).\n\nAll the quoted errors are at statistical 90% confidence level,\nin which the systematic uncertainties are not included.\n\nThe light curves for this burst are available at:\nhttp://www.astro.isas.jaxa.jp/suzaku/HXD-WAM/WAM-GRB/grb/trig/grb_table.html"}', 'The Suzaku Wide-band All-sky Monitor (WAM) detected a long gamma-ray burst (GRB 070724B) with a multi-peaked structure and a duration of about 41 seconds. The fluence in the 100-1000 keV energy range was 1.04 (+0.08,-0.07) X10^-5 erg/cm^2, and the peak flux was 3.33 (+/- 0.40) photons/cm^2/s. Preliminary analysis suggests a steep power-law spectrum with a photon index of 2.8 +/- 0.2.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6671', 'gcn', 'GRB 070724B', '2007-07-26T15:32:31.000Z', '{"measurements":{"dec":null,"distance":null,"duration":{"main_pulse":"50 s","weak_pulse":"10 s"},"energy":{"cutoff_energy":"82 +/- 5 keV","peak_flux_energy_range":"20 - 500 keV"},"fluence":"1.80(-0.25, +0.04)x10^-5 erg/cm2","magnitude":null,"other_measurements":{"alpha":"1.15 +/- 0.13"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Ioffe Inst, on behalf of the Konus-Wind team"],"authors":["S. Golenetskii","R.Aptekar","E. Mazets","V. Pal''shin","D. Frederiks","T. Cline"],"institutions":["Ioffe Inst"],"universities":["Ioffe Inst"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Konus-Wind"]},"urls":["http://www.ioffe.rssi.ru/LEA/GRBs/GRB070724_T84307/"],"basic_data":{"author":{"email":"val@mail.ioffe.ru","institution":"Ioffe Inst","name":"Valentin Pal''shin"},"coordinates":{},"detectionTime":"2007-07-26T15:32:31.000Z","event":"GRB 070724B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6671\nSUBJECT: Konus-Wind observation of GRB 070724B\nDATE: 07/07/26 15:32:31 GMT\nFROM: Valentin Pal''shin at Ioffe Inst  <val@mail.ioffe.ru>\n\nS. Golenetskii, R.Aptekar, E. Mazets, V. Pal''shin, D. Frederiks, and\nT. Cline on behalf of the Konus-Wind team report:\n\nThe long soft GRB 070724B localized by SuperAGILE (Feroci et al., GCN \n6668), triggered Konus-Wind at T0=84307.346 s UT (23:25:07.346).\n\nThe Konus-Wind light curve shows the main multipeaked pulse\nwith a total duration of ~50 s followed by a weak pulse\nat T-T0 ~102 sec with a duration of ~10 s.\nAs observed by Konus-Wind the burst\nhad a fluence of 1.80(-0.25, +0.04)x10^-5 erg/cm2,\nand a 64-ms peak flux measured from T0+29.744 s\n2.17(-0.45, +0.34)x10^-6 erg/cm2/s\n(both in the 20 - 500 keV energy range).\n\nThe time-integrated spectrum of the burst\n(from T0 to T0+49.408 s) can be fitted (in the 20 - 500 keV range)\nby a power law with exponential cutoff model:\ndN/dE ~ E^(-alpha)*exp(-E*(2-alpha)/Ep)\nwith alpha = 1.15 +/- 0.13\nand Ep = 82 +/- 5 keV (chi2 = 40/42 dof).\n\nAll the quoted errors are at the 90% confidence level.\n\nThe Konus-Wind light curve of this GRB is available\nat http://www.ioffe.rssi.ru/LEA/GRBs/GRB070724_T84307/"}', 'The Konus-Wind team reports the observation of GRB 070724B, a long soft gamma-ray burst with a duration of approximately 50 seconds, including a weak pulse at around 102 seconds. The burst had a fluence of $1.80(-0.25, +0.04)×10^{-5}$ erg/cm$^2$ and a peak flux of $2.17(-0.45, +0.34)×10^{-6}$ erg/cm$^2$/s in the 20-500 keV energy range. The time-integrated spectrum can be fitted with a power law with exponential cutoff model, with a photon index of $1.15±0.13$ and a cutoff energy of $82±5$ keV.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6670', 'gcn', 'GRB 070724B', '2007-07-26T15:31:47.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"100 seconds","energy":"50 MeV","fluence":null,"magnitude":null,"other_measurements":{"gamma_ray_flux_comparison":"similar to GRB930131 observed with EGRET, would give about 20 counts in the GRID in the same time interval"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":[],"authors":[],"institutions":[],"universities":[]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"sandro@iasf-milano.inaf.it","institution":"IASF/CNR","name":"Sandro Mereghetti"},"coordinates":{},"detectionTime":"2007-07-26T15:31:47.000Z","event":"GRB 070724B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6670\nSUBJECT: GRB 070724B: Analysis of AGILE gamma-ray data\nDATE: 07/07/26 15:31:47 GMT\nFROM: Sandro Mereghetti at IASF/CNR  <sandro@iasf-milano.inaf.it>\n\nA.Chen, S.Vercellone, A.Giuliani, A.Pellizzoni, F.Fornari, S.Mereghetti, \nF.Perotti, M.Fiorini, P.Caraveo (IASF-Milano), C.Labanti, M.Marisaldi, \nF.Fuschino, M.Galli, A.Bulgarelli, F.Gianotti, M.Trifoglio, G.Di Cocco \n(IASF-Bologna), M.Tavani, G.Pucella, F.D''Ammando, E.Costa, M.Feroci, \nA.Trois, A.Argan (IASF-Roma), G.Picozza (INFN-Roma), F.Longo, \nG.Barbiellini (INFN-Trieste) on behalf of the AGILE Team\n\nand  \n\nC. Pittori, P.Giommi, L.A.Antonelli (ASDC), and L. Salotti (ASI) report:\n\n\nFurther analysis of the AGILE GRID (Gamma-Ray Imaging Detector) data of \nGRB 070724B (Feroci et al. GCN 6668) confirms the absence of significant \nemission at energy above 50 MeV. Only one photon consistent with the \ndirection of GRB 070724B has been detected by the GRID in a ~100 second \ninterval around the time of the burst. This is consistent with the \nmeasured background rate.\n\nWe note that a gamma-ray flux similar to that observed with EGRET from \nGRB930131 (Sommer et al.1994, ApJ 422, L66), would have given about 20 \ncounts in the GRID in the same time interval.\n\nWe also analyzed the data of the AGILE Mini-Calorimeter, which provides a \nnearly whole-sky monitor in the energy range ~0.35-3 MeV (no directional \ninformation), without finding any statistically significant count rate \nincrease in correspondence of GRB 070724B.\n\n[GCN OPS NOTE(26jul06): Per author''s reuqest, the Subject line was changed\nfrom \"070734B\" to \"070724B\".]"}', 'Further analysis of AGILE gamma-ray data for GRB 070724B found no significant emission above 50 MeV, detecting only one photon consistent with the burst direction and consistent with the background rate. The absence of a gamma-ray flux similar to that observed with EGRET for GRB930131 suggests no significant emission in this energy range.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-667', 'gcn', 'GRB000508B', '2000-05-10T17:56:33.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"V":12},"other_measurements":{"external_zero_point_error":"2%","internal_errors":"less than 100mas"},"ra":null,"redshift":null,"tables":[{"column_names":["Not specified"],"values":["ftp://ftp.nofs.navy.mil/pub/outgoing/aah/grb/grb000508b.dat"]}]},"authors":{"affiliations":["USRA/USNO"],"authors":["A. Henden"],"institutions":["USNO/USRA"],"universities":["USRA","USNO"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["USNOFS 1.0-m telescope"]},"urls":["ftp://ftp.nofs.navy.mil/pub/outgoing/aah/grb/grb000508b.dat"],"basic_data":{"author":{"email":"aah@nofs.navy.mil","institution":"USNO/USRA","name":"Arne A. Henden"},"coordinates":{},"detectionTime":"2000-05-10T17:56:33.000Z","event":"GRB000508B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 667\nSUBJECT: GRB000508B, BVR field photometry\nDATE: 00/05/10 17:56:33 GMT\nFROM: Arne A. Henden at USNO/USRA  <aah@nofs.navy.mil>\n\nA. Henden (USRA/USNO) reports on behalf of the USNO GRB team:\n\nWe have acquired preliminary shallow BVRc all-sky photometry for\nan 11x11 arcmin field that covers the error box for GRB000508B\nwith the USNOFS 1.0-m telescope on one photometric night.\nStars brighter than V=12 are saturated and should be used with care.\nWe have placed the photometric data on our anonymous ftp site:\nftp://ftp.nofs.navy.mil/pub/outgoing/aah/grb/grb000508b.dat\nThe current photometry has a potential external zero-point\nerror of about two percent.  The astrometry in this file\nis based on linear plate solutions with respect to USNO-A2.0.\nThe internal errors are less than 100mas.\n  Further calibration of this field will be performed if\nan optical afterglow is identified."}', 'The USNO GRB team has acquired preliminary BVR photometry for the error box of GRB0005058B using the USNOFS 1.0-m telescope. The data, which includes stars brighter than V=12, has a potential external zero-point error of about 2% and internal errors less than 100mas. The photometric data is available on their FTP site.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6669', 'gcn', 'GRB 070724B', '2007-07-25T23:50:43.000Z', '{"measurements":{"dec":["57.67613","57.81898"],"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":["17.48574","17.51024"],"redshift":null,"tables":[{"column_name":"Position","value":"RA(J2000)  =  01 09 56.58, Dec(J2000) = +57 40 34.1"},{"column_name":"Error Radius","value":"4.5 arcsec (90% confidence)"},{"column_name":"Distance from SuperAGILE Position","value":"4.6 arcmin"},{"column_name":"Count Rate","value":"(3.9+/-0.4)E-02 counts/s"},{"column_name":"Flux","value":"~2E-12 erg/cm2/s"},{"column_name":"Position","value":"RA(J2000)  =  01 10 02.46, Dec(J2000) = +57 49 08.3"},{"column_name":"Error Radius","value":"6.1 arcsec (90% confidence)"},{"column_name":"Distance from SuperAGILE Position","value":"9.5 arcmin"},{"column_name":"Count Rate","value":"(0.6+/-0.2)E-02 counts/s"},{"column_name":"Flux","value":"~3E-13 erg/cm2/s"}]},"authors":{"affiliations":["Uni-Bicocca and OAB","PSU"],"authors":["P. Romano","J.A. Kennea","C. Guidorzi","D. Burrows"],"institutions":["OAB","INAF","PSU"],"universities":["Uni-Bicocca","PSU"]},"telescopes":{"facilities":[],"instruments":["Swift-XRT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"patrizia.romano@brera.inaf.it","institution":"OAB-Swift","name":"Pat Romano"},"coordinates":{"dec":1.1657166666666665},"detectionTime":"2007-07-25T23:50:43.000Z","event":"GRB 070724B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6669\nSUBJECT: GRB 070724B: Swift-XRT afterglow candidates\nDATE: 07/07/25 23:50:43 GMT\nFROM: Pat Romano at OAB-Swift  <patrizia.romano@brera.inaf.it>\n\nP. Romano(Uni-Bicocca and OAB), J.A. Kennea(PSU), C. Guidorzi(Uni-Bicocca and OAB),\nD. Burrows(PSU) report on behalf of the Swift-XRT team:\n\nWe have analysed the first two orbits of Swift-XRT data obtained for\nGRB 070724B detected by SuperAGILE (Feroci et al., GCN Circ. 6668),\nwhich include 3971s of Photon Counting (PC) mode data, beginning\non 2007-07-25 18:32:39 UT, 19.1 hours after the burst trigger time.\nUsing the PC data we found two sources within the SuperAGILE error circle,\nat the following positions:\n\n1) RA, Dec=17.48574, 57.67613, which is equivalent to\nRA(J2000)  =  01 09 56.58\nDec(J2000) = +57 40 34.1\nwith an estimated error radius of 4.5 arcsec (90% confidence).\nThis position lies 4.6 arcmin  from the SuperAGILE position\n(GCN Circ. 6668). The current observed 0.3-10 keV count rate is\n(3.9+/-0.4)E-02 counts/s, which translates into a 0.3-10 keV flux of\n~2E-12 erg/cm2/s (assuming a power-law with photon index=2 absorbed\nby a column of NH=E21 cm-2).\n\n2) RA, Dec= 17.51024, 57.81898, which is\nRA(J2000)  =  01 10 02.46\nDec(J2000) = +57 49 08.3\nwith an estimated error radius of 6.1 arcsec (90% confidence).\nThis position lies 9.5 arcmin  from the SuperAGILE position.\nThe current observed 0.3-10 keV count rate is (0.6+/-0.2)E-02\ncounts/s, which translates into a 0.3-10 keV flux of ~3E-13 erg/cm2/s.\n\nMore data are being collected and a new circular will be issued\nwhen the fading nature of these objects is established.\n\nThis circular is an official product of the XRT team.\n\n[GCN OPS NOTE(26jul07): Per author''s request, DB''s affiliation was added,\n\"17.1 hours\" was changed to \"19.1 hours\", and the exponent of the count rate\nin the second source changed from \"03\" to \"02\".]"}', 'Swift-XRT team reports the detection of two X-ray sources within the error circle of GRB 070724B using the first two orbits of data. The sources are located at RA(J2000) 01 09 56.58, +57 40 34.1 and RA(J2000) 01 10 02.46, +57 49 08.3, with estimated error radii of 4.5 and 6.1 arcsec respectively. The current observed X-ray count rates and fluxes for the sources are (3.9+/-0.4)E-02 counts/s and ~2E-12 erg/cm2/s for the first source, and (0.6+/-0.2)E-02 counts/s and ~3E-13 erg/cm2/s for the second source.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6668', 'gcn', 'GRB 070724b', '2007-07-25T18:29:51.000Z', '{"measurements":{"dec":"+57d 40'' 23\"","distance":null,"duration":"55 seconds","energy":"20-60 keV","fluence":null,"magnitude":null,"other_measurements":{"off-axis angle":"21 degrees","uncertainty radius":"20''"},"ra":"01h 10m 31.0s","redshift":null,"tables":[]},"authors":{"affiliations":["IASF-ROMa (INAF)","ASDC"],"authors":["M. Feroci","E. Costa","E. Del Monte","I. Donnarumma","Y. Evangelista","I. Lapshov","F. Lazzarotto","L. Pacciani","M. Rapisarda","P. Soffitta","A. Rubini","E. Morelli","M. Mastropietro","G. Di Persio","M. Frutti","S. Mereghetti","A. Pellizzoni","G. Di Cocco","C. Labanti","M. Trifoglio","G. Barbiellini","P. Picozza","A. Argan","M. Tavani","P. Giommi","L.A. Antonelli","C. Pittori"],"institutions":["IASF-ROMa (INAF)","ASDC"],"universities":["IASF/INAF","ASDC"]},"telescopes":{"facilities":["ASDC"],"instruments":["SuperAGILE","AGILE Gamma Ray Imager (GRID)"],"observatories":[],"telescopes":["AGILE"]},"urls":[],"basic_data":{"author":{"email":"feroci@iasf-roma.inaf.it","institution":"IASF/INAF","name":"Marco Feroci"},"coordinates":{},"detectionTime":"2007-07-25T18:29:51.000Z","event":"GRB 070724b","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6668\nSUBJECT: GRB 070724b: First Gamma Ray Burst Localization by SuperAGILE onboard\nDATE: 07/07/25 18:29:51 GMT\nFROM: Marco Feroci at IASF/INAF  <feroci@iasf-roma.inaf.it>\n\nGRB 070724b: First Gamma Ray Burst Localization by SuperAGILE onboard \nAGILE\n\nM. Feroci, E. Costa, E. Del Monte, I. Donnarumma, Y. Evangelista, \nI. Lapshov, F. Lazzarotto, L. Pacciani, M. Rapisarda, P. Soffitta, \nA. Rubini, E. Morelli, M. Mastropietro, G. Di Persio, M. Frutti, \nand S. Mereghetti, A. Pellizzoni, G. Di Cocco, C. Labanti, M. Trifoglio, \nG. Barbiellini, P. Picozza, A. Argan and M. Tavani, \non behalf of the AGILE Team, P. Giommi, L.A. Antonelli, \nC. Pittori (ASDC), and L. Salotti (ASI) report:\n\nThe SuperAGILE experiment onboard the AGILE mission, launched on April \n23rd on an equatorial orbit, is currently performing the in-flight \ncheck-out and performance verification. The experiment is not yet in its \noptimal configuration and not all the functions are active. In \nparticular, the onboard triggering and imaging is not active yet\nand the absolute position reconstruction is being calibrated by\nusing celestial X-ray sources.\nDuring this testing phase SuperAGILE detected and imaged \nGRB 070724b. The event starting time is approximately at \n23:25:09 UT on July 24 and it was observed at 21 degrees off-axis.\nThe observed duration in the 20-60 keV energy range is about 55 seconds, \nwith a multi-peak time structure. \n\nThe burst position was reconstructed as (RA, Dec) (17.629 deg, \n57.673 deg), which is:\n\nRA(J2000) = 01h 10m 31.0s\nDec(J2000) = +57d 40'' 23\"\n\nwith an uncertainty of 20'' radius. The given uncertainty is almost \nentirely systematic and it is due to the very preliminary absolute \nposition calibration, carried out only on 3 X-ray sources. At this \npreliminary stage the absolute positioning was obtained by the ground \ncalibrations, preliminarily checked with these sources. The error box\nmay be improved over the next hours/days.\n\nAn analysis of the AGILE Gamma Ray Imager (GRID) data is in progress.\nA quick look analysis does not show any bright gamma-ray transient\nin coincidence with the X-ray emission of GRB 070724b."}', 'The SuperAGILE experiment onboard the AGILE mission detected and imaged a gamma ray burst (GRB 070724b) during its testing phase. The burst occurred approximately at 23:25:09 UT on July 24 and was observed at an off-axis angle of 21 degrees. The burst position was determined to be (RA, Dec) (01h 10m 31.0s, +57d 40'' 23'''') with an uncertainty of 20''. No bright gamma-ray transient was detected in coincidence with the X-ray emission of GRB 070724b using AGILE Gamma Ray Imager (GRID) data.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6667', 'gcn', 'GRB 070724', '2007-07-25T18:21:35.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null},"authors":{"affiliations":["U Virginia/NRAO","NRAO"],"authors":["Poonam Chandra","Dale A. Frail"],"institutions":["NRAO","GCN"],"universities":["University of Virginia","Caltech","Carnegie"]},"telescopes":{"facilities":["National Science Foundation"],"instruments":[],"observatories":["National Radio Astronomy Observatory"],"telescopes":["Very Large Array"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.jsp?id=6667"],"basic_data":{"author":{"email":"pc8s@virginia.edu","institution":"U Virginia/NRAO","name":"Poonam Chandra"},"coordinates":{"dec":17.403906111111112,"ra":1.8539180555555557},"detectionTime":"2007-07-25T18:21:35.000Z","event":"GRB 070724","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6667\nSUBJECT: Four radio sources in Swift-XRT error box of GRB 070724\nDATE: 07/07/25 18:21:35 GMT\nFROM: Poonam Chandra at U Virginia/NRAO  <pc8s@virginia.edu>\n\nPoonam Chandra (NRAO/UVA) and Dale A. Frail (NRAO) report on\nbehalf of the Caltech-NRAO-Carnegie GRB Collaboration:\n\n\n\"We used the Very Large Array to observe the field of view toward\nGRB 070724 (GCN 6654) at a frequency of 8.46 GHz on 2007 July 25th\nat 12.50 UT, 25.4 hours after the burst. Owing to VLA A-array observation,\nwe obtained excellent resolution of 0.33\"x0.24\". We find four possible\nsources in the Swift-XRT error box, which are above 3-sigma. These are\n\n     Position (J2000)                           Flux density (Jy)\n\n1:   RA 01 51 14.105    +/-  0.002         4.3899E-04 +/-  8.40E-05\n     DEC -18 35 45.938  +/-  0.024\n\n2:   RA 01 51 14.125    +/-  0.002         4.0976E-04 +/-  8.51E-05\n     DEC -18 35 41.404  +/-  0.021\n\n3:   RA 01 51 13.824    +/-  0.003         3.1155E-04 +/-  8.48E-05\n     DEC -18 35 36.626  +/-  0.033\n\n4:   RA 01 51 14.104    +/-  0.003         3.1204E-04 +/-  8.47E-05\n     DEC -18 35 40.626  +/-  0.030\n\nHere source 4 is closest to Josh Bloom''s blue source (GCN 6658) with\noffset of 1.7 arcsec. Source 2 is closest to P60 afterglow position of the\nGRB (Cenko et al. GCN 6664) with offset of 1.3 arcsec.\n\nNVSS does not show any radio source around this position.\nMore observations are planned to see the variability of these sources.\n\n\nThe National Radio Astronomy Observatory is a facility of the National\nScience Foundation operated under cooperative agreement by Associated\nUniversities, Inc.\""}', 'Astronomers using the Very Large Array detected four radio sources in the error box of the gamma-ray burst GRB 070724, 25.4 hours after the burst. The sources, located closest to previous identified positions of the afterglow and a blue source, have flux densities above 3-sigma and are not detected in the NVSS catalog. Further observations are planned to study their variability.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6666', 'gcn', 'GRB 070724', '2007-07-25T13:21:12.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"exposure_time":"10 minutes","seeing":"0.7 arcseconds","time_after_trigger":"22.1 hours"},"ra":null,"redshift":0.457,"tables":[]},"authors":{"affiliations":["INAF/OAR","INAF-OABr","DIAS and DCU"],"authors":["S. Covino","S. Piranomonte","S.D. Vergani","P. D''Avanzo","L. Stella"],"institutions":["OAR","OABr","INAF","DIAS","DCU"],"universities":["INAF","DIAS","DCU"]},"telescopes":{"facilities":[],"instruments":["FORS2"],"observatories":["OAR"],"telescopes":["ESO-VLT"]},"urls":["http://horde.org/imp/"],"basic_data":{"author":{"email":"piranomonte@mporzio.astro.it","institution":"OAR","name":"Silvia Piranomonte"},"coordinates":{},"detectionTime":"2007-07-25T13:21:12.000Z","event":"GRB 070724","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6666\nSUBJECT: GRB 070724: optical observations\nDATE: 07/07/25 13:21:12 GMT\nFROM: Silvia Piranomonte at OAR  <piranomonte@mporzio.astro.it>\n\nS. Covino (INAF/OABr), S. Piranomonte (INAF/OAR), S.D. Vergani (DIAS and\nDCU), P. D''Avanzo (INAF-OABr), L. Stella (INAF/OAR), report on behalf of\nthe MISTICI collaboration:\n\nWe observed the afterglow of GRB 070724 (Ziaeepour et al., GCN 6654)\nwith the ESO-VLT equipped with FORS2. Starting on 2007 Jul 25.3735 UT\n(22.1 hr after the trigger), we acquired 10 minutes of imaging in the I\nband. Inside the XRT error circle (Page & Ziaeepour, GCN 6659), we\ndetect both objects reported by Bloom (GCN 6658) and Cenko et al. (GCN\n6664).\n\nWhen compared with the photometry reported by Cenko et al. (GCN 6664),\nnone of the objects seems to have faded. The faintest object is\npointlike (seeing of 0.7\").\n\nWe also took two 10-min spectra with VLT+FORS2. Based on detection of [OII] 3727\nHbeta and [OIII] 4959,5007, we confirm the redshift z=0.457 proposed by Cucchiara\net al. (GCN 6665).\n\nWe thank Brad Cenko for very useful discussion.\n\n-------------------------------------------------\nThis mail sent through IMP: http://horde.org/imp/"}', 'A team of astronomers led by S. Covino, S. Piranomonte, and colleagues observed the afterglow of GRB 070724 using the ESO-VLT and FORS2. They detected two objects within the XRT error circle and confirmed the redshift of z=0.457 using spectroscopy. No fading was observed in the detected objects.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6665', 'gcn', 'GRB070724', '2007-07-25T10:23:16.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"exposure_time":"900 seconds","wavelength_range":"~5000-9000 A"},"ra":null,"redshift":0.457,"tables":[]},"authors":{"affiliations":["PSU","Penn State","Caltech","Carnegie Observatories","IfA","Gemini"],"authors":["A. Cucchiara","D. B. Fox","S. B. Cenko","E. Berger","P. A. Price","J. Radomski"],"institutions":["PSU","Caltech","Carnegie Observatories","IfA"],"universities":["Penn State","Caltech","Carnegie","IfA"]},"telescopes":{"facilities":["Gemini South"],"instruments":["GMOS"],"observatories":["Gemini"],"telescopes":["Gemini South"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.jsp?id=6654","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.jsp?id=6658"],"basic_data":{"author":{"email":"cucchiara@astro.psu.edu","institution":"PSU","name":"Antonino Cucchiara"},"coordinates":{},"detectionTime":"2007-07-25T10:23:16.000Z","event":"GRB070724","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6665\nSUBJECT: GRB070724: Host galaxy redshift\nDATE: 07/07/25 10:23:16 GMT\nFROM: Antonino Cucchiara at PSU  <cucchiara@astro.psu.edu>\n\nA. Cucchiara, D. B. Fox (Penn State), S. B. Cenko (Caltech), E. Berger \n(Carnegie),\nP. A. Price (IfA) and J. Radomski (Gemini) report on behalf of a larger \ncollaboration:\n\n\nStarting on 2007 July 25 at 06:40 UT we used GMOS on the Gemini South\ntelescope to obtain a set of 900 seconds spectra of the host galaxy of \nGRB070724\n(Ziaeepour et al., GCN 6654).  \nThe covered wavelength  range is ~5000-9000 A.\n\nWe found strong evidence of emission lines identified as [O II] 3727, \nHbeta and\n[O III] 4959,5007 doublet at redshift z=0.457.  \nThis confirms the low-redshift nature\nof the host galaxy for this short burst as noted by Bloom et al. (GCN 6658).\n\n\nWe wish to thank and acknowledge the effort of the staff at Gemini South\nin undertaking these observations."}', 'Astronomers led by A. Cucchiara at Penn State used the Gemini South telescope to observe the host galaxy of GRB070724 and identified emission lines at a redshift of 0.457, confirming its low-redshift nature.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6664', 'gcn', 'GRB 070724', '2007-07-25T07:28:40.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null},"authors":{"affiliations":["Caltech","Caltech","Carnegie/Princeton","IfA","Penn State"],"authors":["S. B. Cenko","A. Rau","E. Berger","P. A. Price","A. Cucchiara"],"institutions":["Caltech","Carnegie/Princeton","IfA","Penn State"],"universities":["Caltech","Carnegie/Princeton","IfA","Penn State"]},"telescopes":{"facilities":["Caltech","Gemini Observatory"],"instruments":["automated Palomar 60-inch telescope","Gemini Multi-Object Spectrograph (GMOS)","Near-Infrared Imager (NIRI)"],"observatories":["Gemini Observatory"],"telescopes":["Palomar 60-inch telescope","10-m Gemini North Telescope"]},"urls":["https://www.gemini.edu"],"basic_data":{"author":{"email":"cenko@srl.caltech.edu","institution":"Caltech","name":"S. Bradley Cenko"},"coordinates":{"dec":17.404972222222224,"ra":1.853902777777778},"detectionTime":"2007-07-25T07:28:40.000Z","event":"GRB 070724","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6664\nSUBJECT: GRB 070724: P60 and Gemini Observations\nDATE: 07/07/25 07:28:40 GMT\nFROM: S. Bradley Cenko at Caltech  <cenko@srl.caltech.edu>\n\nS. B. Cenko, A. Rau (Caltech), E. Berger (Carnegie/Princeton), P. A. Price\n(IfA), and A. Cucchiara (Penn State) report on behalf of a larger\ncollaboration:\n\nWe have imaged the field of GRB070724 (Ziaeepour et al., GCN 6654) on\nthe night of 2007 July 24 UT with the automated Palomar 60-inch telescope\n(beginning approximately 2.5 minutes after the burst) and the Gemini\nMulti-Object Spectrograph (GMOS) and Near-Infrared Imager (NIRI) mounted\non the 10-m Gemini North Telescope (beginning approximately 2 hours after\nthe burst).\n\nThe nearby galaxy first mentioned by Bloom (GCN 6658) shows no sign of\nvariability, either from our P60 to our GMOS imaging (remaining at a\nconstant magnitude of i'' ~ 20.3), or within our Gemini imaging (verified\nwith psf-matched digital image subtraction).\n\nIn addition the aforementioned galaxy, we find a faint source on the\noutskirts of the revised XRT error circle (Page and Ziaeepour, GCN 6659)\nat coordinates (J2000.0):\n\n   RA: 01:51:14.05\n   Dec: -18:35:42.1\n\nwith an estimated astrometric uncertainty of approximately 0.3\" in each\ncoordinate.  The object is only visible in our Gemini/GMOS i'' imaging of\nthe field, with a magnitude of i'' ~ 24.6 (using GMOS zeropoints from the\nGemini webpage).  This object is not present in our earlier P60 imaging of\nthe field; however it is well below our detection threshold (see below).\nAs our only two Gemini/GMOS i'' images were taken back-to-back, we have no\ninformation on the variability of this source at the current time.\n\nNo other object is detected in the revised XRT error circle in any other\nfilter.  Our limiting magnitudes, calculated with respect to the USNO-B\ncatalog (P60) or using zeropoints from the Gemini website (GMOS and NIRI),\nare quoted below:\n\nInstrument\tFilter\tUT (July 24)\tdt (hr)\tExposure (s)\tMagnitude\n---------------------------------------------------------------------------\nP60\t\ti''\t11:13\t\t0.32\t3x60 + 3x120\t> 21.5\nGMOS\t\ti''\t13:17\t\t2.38\t2x180\t\t> 24.5\nNIRI\t\tKs\t13:44\t\t2.83\t15x60\t\t> 20.0\nNIRI\t\tJ\t14:02\t\t3.13\t15x60\t\t> 22.0\nNIRI\t\tH\t14:19\t\t3.42\t15x60\t\t> 21.0\nNIRI\t\tKs\t14:36\t\t3.70\t15x60\t\t> 20.0"}', 'Astronomers using the Palomar 60-inch telescope and Gemini Observatory report no variability in a nearby galaxy near GRB070724, but find a faint source on the outskirts of the error circle with a magnitude of i'' ~ 24.6, only visible in Gemini/GMOS i'' imaging. The object is not present in earlier P60 imaging and its variability is unknown.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6663', 'gcn', 'GRB 060814', '2007-07-24T21:18:06.000Z', '{"measurements":{"dec":"+20:35:10.7","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"exposure_time_I_band":"750s","exposure_time_V_band":"840s"},"ra":"14:45:21.29","redshift":0.84,"tables":[]},"authors":{"affiliations":["DARK/UC Berkeley","UC Berkeley"],"authors":["Christina C. Thoene","Daniel A. Perley","J. S. Bloom"],"institutions":["Niels Bohr Institute","DARK Cosmo Ctr","UC Berkeley"],"universities":["University of Copenhagen","University of California, Berkeley"]},"telescopes":{"facilities":[],"instruments":["LRIS"],"observatories":[],"telescopes":["Keck I 10m telescope"]},"urls":["http://astro.berkeley.edu/~nat/swift/xrt_pos.html","http://lyra.berkeley.edu/~cthoene/GRBs/GRB060814_2dspec.jpg","http://lyra.berkeley.edu/~dperley/060814/060814_lris_v.png","http://lyra.berkeley.edu/~dperley/060814/"],"basic_data":{"author":{"email":"cthoene@astro.ku.dk","institution":"Niels Bohr Institute,DARK Cosmo Ctr","name":"Christina Thoene"},"coordinates":{},"detectionTime":"2007-07-24T21:18:06.000Z","event":"GRB 060814","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6663\nSUBJECT: GRB 060814 - Keck host detection and redshift\nDATE: 07/07/24 21:18:06 GMT\nFROM: Christina Thoene at Niels Bohr Institute,DARK Cosmo Ctr  <cthoene@astro.ku.dk>\n\nChristina C. Thoene (DARK/UC Berkeley), Daniel A. Perley and J. S. Bloom\n(UC Berkeley) report:\n\nOn 2007 April 15 (UT) we imaged the field of GRB 060814 with Keck I 10m\ntelescope + LRIS for 750s in I and 840s in V under poor seeing conditions.\nThe host galaxy reported by Malesani et al. (GCN 5456) and others is\nwell-detected at a position consistent with the locations of the IR (Levan\net al., GCN 5455) and X-ray (GCN 5451; [1]) transients. A finding chart of\nthe field can be found at:\n\nhttp://lyra.berkeley.edu/~dperley/060814/060814_lris_v.png\n\nWe also took spectra of the host galaxy on July 18 with LRIS, using grism\n600/4000 and dicroic 560, which covers the wavelength range between 5500\nand 9700 AA in the red arm. From the detected [OII] 3729 AA and [OIII]\n5008 AA emission lines, we infer a redshift of z=0.84 for the host galaxy.\nThe second [OIII] line at 4959 is marginally detected whereas H beta lies\nin the atmospheric absorption lines and could not be detected.\nAn image of the 2D spectrum indicating the detected emission lines can be\nfound at:\n\nhttp://lyra.berkeley.edu/~cthoene/GRBs/GRB060814_2dspec.jpg\n\n\nfootnote:\n\n[1] 14:45:21.29, +20:35:10.7, 90% unc. 0.9\", from\nhttp://astro.berkeley.edu/~nat/swift/xrt_pos.html (v0.0)"}', 'Astronomers using the Keck I 10m telescope and LRIS instrument have detected and measured the redshift of the host galaxy for GRB 060814. The redshift, z=0.84, was determined from the detection of [OII] and [OIII] emission lines in a spectrum taken on July 18, 2007.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6662', 'gcn', 'GRB 070724', '2007-07-24T20:50:02.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"observation_time_1":"13:11 UT","observation_time_2":"14:02 UT"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["U.of Leicester (anl@star.le.ac.uk)","University of Warwick (A.J. Levan)"],"authors":["A.J. Levan","N.R. Tanvir","C. Davis"],"institutions":["U.of Leicester","Warwick"],"universities":["University of Leicester","University of Warwick"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["UKIRT"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"anl@star.le.ac.uk","institution":"U.of Leicester","name":"Andrew Levan"},"coordinates":{},"detectionTime":"2007-07-24T20:50:02.000Z","event":"GRB 070724","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6662\nSUBJECT: GRB 070724: IR observations\nDATE: 07/07/24 20:50:02 GMT\nFROM: Andrew Levan at U.of Leicester  <anl@star.le.ac.uk>\n\nA.J. Levan (Warwick), N.R. Tanvir (Leicester), C. Davis (JAC) report on \nbehalf of a large collaboration:\n\nWe observed the location of GRB 070724 in the K-band using UKIRT. Two \nepochs were obtained beginning at 13:11 UT and 14:02 UT. We clearly detect \nthe object refered to by (Bloom GCNC 6658), and confirm that it is indeed \na galaxy.\n\nWe find no evidence of variability within the galaxy between the two \nobservations. No other objects are detected within the refined XRT error \ncircles of Page & Ziaeepour (GCNC 6659) or Bloom & Butler (GCNC 6661).\n\nFurther observations are planned."}', 'Astronomers using the UKIRT telescope have observed and confirmed the identification of a galaxy at the location of GRB 070724. No variability was detected in the galaxy during two observations. No other objects were found within the error circles of previous XRT observations.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6661', 'gcn', 'GRB 070724', '2007-07-24T19:07:24.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"offset":"<~ 2\"","time":"07/07/24 19:07:24 GMT"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["UC Berkeley"],"authors":["J. S. Bloom","N. R. Butler"],"institutions":["UC Berkeley"],"universities":["University of California, Berkeley"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://lyra.berkeley.edu/~jbloom/grb070724-update1.png","<http://lyra.berkeley.edu/~jbloom/grb070724-update1.png>"],"basic_data":{"author":{"email":"jbloom@astron.berkeley.edu","institution":"UC Berkeley","name":"Josh Bloom"},"coordinates":{},"detectionTime":"2007-07-24T19:07:24.000Z","event":"GRB 070724","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6661\nSUBJECT: GRB 070724: Closer association with DSS source\nDATE: 07/07/24 19:07:24 GMT\nFROM: Josh Bloom at UC Berkeley  <jbloom@astron.berkeley.edu>\n\nJ. S. Bloom and N. R. Butler (UC Berkeley) remark:\n\n\"The updated XRT position of GRB 070724 from Page & Ziaeepour (GCN  \n#6659), puts the GRB afterglow closer to the proposed low redshift  \nhost (Bloom GCN #6658) seen in the DSS. We emphasize that the galaxy  \nnature of this source has yet to be confirmed; yet, the small offset  \n(<~ 2\") is reminiscent of the SHB 050709 (Fox et al. Nature, 437,  \n845, 2005) and SHB 051221 (Soderberg et al. ApJ, 650, 261, 2006)  \nconfigurations (see Bloom & Prochaska for an early SHB-host offsets  \nreview; AIP Conf. Proc. 838, 473, 2006).\" An updated finder can now  \nbe found at:\n\n     http://lyra.berkeley.edu/~jbloom/grb070724-update1.png\n\nWe thank Massimiliano de Pasquale for helpful conversations about the  \nUVOT imaging.\n\nThis message could, in principle, be cited."}', 'Astronomers at UC Berkeley have identified a closer association between the afterglow of GRB 070724 and a proposed low redshift host seen in the Deep Sky Survey (DSS). The small offset of approximately 2 inches is reminiscent of other short-hard bursts and may suggest a confirmed galaxy host.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6660', 'gcn', 'GRB070724', '2007-07-24T18:05:38.000Z', '{"measurements":[20.4,19.5,21.1,20,20.3,20,20.4,20.4,20.7],"authors":{"affiliations":["MSSL-UCL"],"authors":["M. De Pasquale","H. Ziaeepour"],"institutions":["MSSL-UCL"],"universities":["University College London (UCL)"]},"telescopes":{"facilities":[],"instruments":["Swift/UVOT","XRT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6660"],"basic_data":{"author":{"email":"mdp@mssl.ucl.ac.uk","institution":"MSSL-UCL","name":"Massimiliano de Pasquale"},"coordinates":{},"detectionTime":"2007-07-24T18:05:38.000Z","event":"GRB070724","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6660\nSUBJECT: Swift/UVOT refined analysis of GRB070724\nDATE: 07/07/24 18:05:38 GMT\nFROM: Massimiliano de Pasquale at MSSL-UCL  <mdp@mssl.ucl.ac.uk>\n\nM. De Pasquale (MSSL-UCL) and H. Ziaeepour (MSSL-UCL) report on\nthe behalf of the Swift UVOT/team:\n\n  The Swift/UVOT observed the field of GRB070724 starting 58s after\nthe BAT trigger (Ziaaepour et al. GCN circ. 6654). Inside the\nrefined XRT error circle (Page et al., GCN circ 6659) we do not\nfind any new source, either in the first finding chart exposures\nin the White and V filter or in the summed exposures of any of the\nUVOT filters.\n\n  The 3 sigma upper limits for detecting a source inside the XRT\nerror circle are:\n\n  Filter  T obs (s)  Exp (s)  Mag (3 sigma u.l.)\n\n  White    76-176      98           20.4\n\n   v      182-581     393           19.5\n\n\n  White   76-5531     380           21.1\n\n   v     182-5941     806           20.0\n\n   b     662-5325     216           20.3\n\n   u     636-6456     332           20.0\n\n  uvw1   612-6352     432           20.4\n\n  uvm2   587-6146     432           20.4\n\n  uvw2   692-5736     432           20.7\n\n\n  No correction has been done for the expected low Galactic\nreddening towards the burst, E(B-V)=0.01 (Schlegel et al.\n11998)."}', 'Swift/UVOT team at MSSL-UCL reports no detection of new sources inside the XRT error circle of GRB070724 using UVOT filters. The team provides 3 sigma upper limits for detecting a source in various filters.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-666', 'gcn', 'Possible GRB-related phenomenon', '2000-05-09T23:38:25.000Z', '{"measurements":{"dec":"+36o40''08.5\"","distance":"7.8 Mpc","duration":null,"energy":null,"fluence":null,"magnitude":17.4,"other_measurements":{"fading_by":"3.5 magnitudes","slope_of_power_law_fit":"-3.3 +/- 0.1"},"ra":"10h 52m41.40s","redshift":null,"tables":[]},"authors":{"affiliations":["Astronomical Institute Ondrejov","Klet Observatory","USNO Flagstaff","University of California, Berkeley"],"authors":["R. Hudec","V. Simon","M. Tichy","J. Ticha","W. Li","A. Filippenko","M. Papenkova","F. Vrba","B. Canzian"],"institutions":["Astronomical Institute Ondrejov","Klet Observatory","USNO Flagstaff"],"universities":["Astronomical Institute Ondrejov","University of California, Berkeley"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Astronomical Institute Ondrejov","Klet Observatory","USNO Flagstaff"],"telescopes":["0.8 automatic KAIT","0.6 m Klet","1.0 m Flagstaff"]},"urls":["flipper.berkeley.edu/pub/bait/ngc3432","ftp.nofs.navy.mil/pub/outgoing/fjv/ngc3432.dir/"],"basic_data":{"author":{"email":"fjv@nofs.navy.mil","institution":"USNO","name":"Fredrick J. Vrba"},"coordinates":{},"detectionTime":"2000-05-09T23:38:25.000Z","event":"Possible GRB-related phenomenon","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 666\nSUBJECT: Possible GRB-related phenomenon\nDATE: 00/05/09 23:38:25 GMT\nFROM: Fredrick J. Vrba at USNO  <fjv@nofs.navy.mil>\n\n[WARNING: This is not a typical GCN reporting observations associated\nwith any GRB detection. The uniqueness of this transient object (see\nbelow) and its remote chance of being GRB-related along with its rapid \nfading prompt this GCN.]\n\nR. Hudec, V. Simon (Astronomical Institute Ondrejov), M. Tichy and \nJ. Ticha (Klet Observatory), W. Li, A. Filippenko and M. Papenkova (UCB), \nF. Vrba and B. Canzian (USNO Flagstaff) report:\n\nWe have obtained seven CCD observations with the 0.8 automatic KAIT,\n0.6 m Klet, and 1.0 m Flagstaff telescopes covering the position of the \noptical transient detected in the field of NGC 3432 (IAUC 7415: \nR.A. 10h 52m41.40s, Decl. +36o40''08.5\", equinox 2000.0). The object is \nabout 123\" east and 180\" north of the diffuse nucleus and superimposed \non an HII region (or the spiral arm) of this interacting dwarf galaxy \nat D = 7.8 Mpc.\n\nThe object was discovered on May 3.228 UT at nearly mag 17.4 (unfiltered \nimage) and since then (our last measurement is from May 9.181 UT) has \nfaded by nearly 3.5 magnitudes, similar to rapid GRB optical afterglow\ndeclines. Analysis of the data taken at our observatories is in \nprogress to produce a final light curve. Preliminary analysis indicates \nthat a power law fits the data well with a slope of -3.3 +/- 0.1, if T_0 \nis assumed to be May 0.0 UT for instance, (based on differential photometry \nwith respect only to a nearby star so far), although without a known GRB time\nthe choice of this T_0 is totally arbitrary.\n\nA spectrum of the object (IAUC 7417) shows its distance to be consistent \nwith that of NGC 3432 and thus not a foreground or background object. \nWhile this spectrum is consistent with that of a classical nova, the \nthe brightness at this distance would make the nova extraordinarily\nbright. The object might yet be a (probably absorbed) optical afterglow \nof a not-observed GRB (due to different beaming opening angles in gamma \nrays and in the optical). Even if this not a GRB optical afterglow (an \nextraordinary bright nova, for instance ), the object is still worthy of \nfurther study, but is rapidly fading into the background of NGC 3432.\nTonight might be the last opportunity to observe it.\n\nThe discovery FITS frame is available by anonymous ftp at flipper.berkeley.edu,\nin the directory /pub/bait/ngc3432. Finding charts from UT May 07 and\n09 showing the object fading are avaiable in postscript format by anonymous \nftp at ftp.nofs.navy.mil in the directory /pub/outgoing/fjv/ngc3432.dir."}', 'Astronomers have reported the discovery of a rapidly fading optical transient in the field of the interacting dwarf galaxy NGC 3432. The object, located about 123" east and 180" north of the galaxy nucleus, was first observed on May 3 at a magnitude of 17.4 and has since faded by approximately 3.5 magnitudes. Preliminary analysis suggests a power law decline with a slope of -3.3 +/- 0.1. The object''s distance and spectrum are consistent with that of NGC 3432, but its brightness at this distance is unusual, leading to the possibility that it may be an optical afterglow of an unobserved gamma-ray burst. The discovery team urges further study, as tonight may be the last opportunity to observe it.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6659', 'gcn', 'GRB 070724', '2007-07-24T17:29:58.000Z', '{"measurements":{"dec":-18.59448,"distance":null,"duration":5.2,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"decay_slope_alpha":0.4,"decay_slope_alpha_lower_error":0.2,"decay_slope_alpha_upper_error":0.3,"distance_from_bat_position":77.8,"distance_from_initial_position":2.7,"galactic_column_density":143000000000000000000,"galactic_column_density_unit":"cm^-2","gamma_lower_error":0.6,"gamma_upper_error":0.8,"gamma_value":1.3,"observed_flux":5.18e-13,"observed_flux_unit":"erg cm^-2 s^-1","predicted_count_rate":0.004,"predicted_count_rate_range_max":0.008,"predicted_count_rate_range_min":0.002,"predicted_observed_flux":2e-13,"predicted_observed_flux_lower_error":1e-13,"predicted_observed_flux_unit":"erg cm^-2 s^-1","predicted_observed_flux_upper_error":7e-13,"unabsorbed_flux":5.27e-13,"unabsorbed_flux_unit":"erg cm^-2 s^-1","uncertainty":2.2},"ra":27.80815,"redshift":null,"tables":[]},"authors":{"affiliations":["U. Leicester","UCL-MSSL"],"authors":["K.L Page","H. Ziaeepour"],"institutions":["UCL-MSSL"],"universities":["U. of Leicester"]},"telescopes":{"facilities":[],"instruments":["Swift-XRT","UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"kpa@star.le.ac.uk","institution":"U.of Leicester","name":"Kim Page"},"coordinates":{"dec":1.853877777777778},"detectionTime":"2007-07-24T17:29:58.000Z","event":"GRB 070724","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6659\nSUBJECT: GRB 070724: Swift-XRT Team refined analysis\nDATE: 07/07/24 17:29:58 GMT\nFROM: Kim Page at U.of Leicester  <kpa@star.le.ac.uk>\n\nK.L Page (U. Leicester) and H. Ziaeepour (UCL-MSSL) report on behalf of \nthe Swift-XRT team:\n\nWe have analysed the first three orbits of Swift-XRT data obtained for GRB \n070724 (Ziaeepour et al., GCN Circ. 6654), which includes ~60 s of \nWindowed Timing (WT) mode data and ~5.2 ks of Photon Counting (PC) data.\n\nUsing 399 s of overlapping XRT PC mode and UVOT V-band data, we find an \nastrometrically corrected X-ray position (using the XRT-UVOT alignment and \nmatching UVOT field sources to the USNO-B1 catalogue) of RA, Dec (J2000) = \n27.80815, -18.59448 which is equivalent to:\n\nRA (J2000):   01 51 13.96\nDec (J2000): -18 35 40.1\n\nwith an uncertainty of 2.2 arcsec (radius, 90% confidence). This is 2.7 \narcsec from the initial XRT position (GCN Circ. 6654) and 77.8 arcsec from \nthe ground-calculated BAT position (Parsons et al., GCN Circ. 6656).\n\nThe first orbit of XRT data shows flaring activity, with the underlying \npower-law decay asserting itself from about 500 seconds after the trigger. \nThis decay slope is poorly constrained with the data currently available: \nalpha ~ 0.4 +0.3/-0.2\n\nFitting the PC data from the second and third orbits (~4-12 ks after the \ntrigger) in order to avoid any spectral evolution during the flares, the \nspectrum can be modelled by a power-law of Gamma = 1.3 +0.8/-0.6, absorbed \nby the Galactic column in this direction of 1.43e20 cm^-2. The 0.3-10 keV \nobserved (unabsorbed) flux during this time is 5.18e-13 (5.27e-13) erg \ncm^-2 s^-1.\n\nIf the decay continues with a slope of alpha ~ 0.4, the count rate at 24 \nhours is predicted to be 4e-3 count s^-1; this ranges between 2e-3 and \n8e-3 count s^-1, taking into account the uncertainties on the slope. Using \nthe spectral fit detailed above, this corresponds to an observed flux of \n(2 +7/-1)e-13 erg cm^-2 s^-1 (over 0.3-10 keV).\n\nThis circular is an official product of the XRT team."}', 'The Swift-XRT team has refined their analysis of GRB 070724, reporting a more accurate X-ray position with an uncertainty of 2.2 arcsec. The team also determined the decay slope and spectral properties of the gamma-ray burst, predicting a count rate and observed flux at 24 hours.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6658', 'gcn', 'GRB 070724', '2007-07-24T17:03:08.000Z', '{"measurements":{"dec":"-18:35:39.1","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":"01:51:14.05","redshift":null,"tables":[]},"authors":{"affiliations":["UC Berkeley"],"authors":["J. S. Bloom"],"institutions":["UC Berkeley"],"universities":["University of California, Berkeley"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://lyra.berkeley.edu/~jbloom/grb070724.png"],"basic_data":{"author":{"email":"jbloom@astron.berkeley.edu","institution":"UC Berkeley","name":"Josh Bloom"},"coordinates":{},"detectionTime":"2007-07-24T17:03:08.000Z","event":"GRB 070724","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6658\nSUBJECT: GRB 070724: Pre-Imaging Shows a Source in the XRT Error Circle\nDATE: 07/07/24 17:03:08 GMT\nFROM: Josh Bloom at UC Berkeley  <jbloom@astron.berkeley.edu>\n\nJ. S. Bloom (UC Berkeley) notes:\n\n\"The JFN color plates from the Digitized Sky Survey show a blue source in\nthe Northeast portion of the XRT error circle of SHB 070724 (Ziaeepour et\nal. GCN 6654; Parsons et al. GCN 6656) at position RA= 01:51:14.05, DEC =\n-18:35:39.1 (J2000). The source appears somewhat extended in the\nnorth-south direction; if confirmed with new digital imaging, this would\nsuggest the source as a prime low redshift star-forming host galaxy\ncandidate.\"\n\nAn image may be found at:\n http://lyra.berkeley.edu/~jbloom/grb070724.png\n\nNo need to cite this message."}', 'A blue source has been identified in pre-imaging data within the error circle of GRB 070724. The source, located at RA: 01:51:14.05, DEC: -18:35:39.1, appears extended and could potentially be a low redshift star-forming host galaxy.', 0.8, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6657', 'gcn', 'GRB070714B', '2007-07-24T15:35:26.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"b":19.9,"v":19.8},"other_measurements":{"observation_duration_b":"13 x 80 sec","observation_duration_v":"20 x 80 sec","observation_start_time_b":"4.9 hours","observation_start_time_v":"5.5 hours"},"ra":null,"redshift":null,"tables":[{"column_name":"B","unit":"mag","value":19.9},{"column_name":"V","unit":"mag","value":19.8}]},"authors":{"affiliations":[],"authors":["C. Weaver","T. Brennan","M. Schubel","J. Styblova","J. Haislip","D. Reichart","M. Nysewander","A. LaCluyze","K. Ivarsen","J. A. Crain","A. Foster","A. Trotter"],"institutions":["FUNGRB/PROMPT"],"universities":[]},"telescopes":{"facilities":[],"instruments":[],"observatories":["CTIO"],"telescopes":["two of the 16\" PROMPT telescopes at CTIO"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.html?id=6621","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.html?id=6620"],"basic_data":{"author":{"email":"eweaver9@physics.unc.edu","institution":"FUNGRB/PROMPT","name":"Christine Weaver"},"coordinates":{},"detectionTime":"2007-07-24T15:35:26.000Z","event":"GRB070714B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6657\nSUBJECT: Short-Hard GRB070714B: PROMPT Observations\nDATE: 07/07/24 15:35:26 GMT\nFROM: Christine Weaver at FUNGRB/PROMPT  <eweaver9@physics.unc.edu>\n\nC. Weaver, T. Brennan, M. Schubel, J. Styblova, J. Haislip, D. Reichart, M. \nNysewander, A. LaCluyze, K. Ivarsen, J. A. Crain, A. Foster, and A. Trotter \nreport:\n\nSkynet observed the localization of short-hard GRB 070714B (Racusin et al., \nGCN 6620) with two of the 16\" PROMPT telescopes at CTIO beginning 4.5 hours \nafter the burst in UBV.\n\nWe do not detect the afterglow (Melandri et al., GCN 6621) to 3-sigma \nlimiting magnitudes of B = 19.9 mag at a mean time of 4.9 hours after the \nburst (13 x 80 sec, calibrated to 14 USNO B1.0 stars) and V = 19.8 mag at a \nmean time of 5.5 hours after the burst (20 x 80 sec, calibrated to 13 NOMAD \nstars."}', 'The PROMPT team at CTIO used two of their 16-inch telescopes to observe the afterglow of short-hard gamma-ray burst GRB070714B, but did not detect it to a 3-sigma limit in B and V bands, 4.5 hours after the burst.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6656', 'gcn', 'GRB 070724', '2007-07-24T15:31:04.000Z', '{"measurements":{"dec":"-18d 36'' 35\"","distance":null,"duration":"0.4 +- 0.04 sec","energy":null,"fluence":"3.0 +- 0.7 x 10^-08 erg/cm2","magnitude":null,"other_measurements":{"partial_coding":"91%","peak_photon_flux":"1.0 +- 0.2 ph/cm2/sec","power_law_index":"1.81 +- 0.33"},"ra":"1h 51m 17.9s","redshift":null,"tables":[]},"authors":{"affiliations":["NASA/GSFC/Swift","GSFC","GSFC/UMBC","LANL","GSFC/USRA","GSFC/ISAS","GSFC/ORAU"],"authors":["A. Parsons","L. Barbier","S.D. Barthelmy","J. Cummings","E. Fenimore","N. Gehrels","H. Krimm","C. Markwardt","D. Palmer","T. Sakamoto","G. Sato","M. Stamatikos","J. Tueller","T. Ukwatta","H. Ziaeepour"],"institutions":["NASA/GSFC","LANL","GSFC/USRA","ISAS"],"universities":["University of Maryland, Baltimore County (UMBC)","University of California, Los Angeles (UCL)","George Washington University (GWU)"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"parsons@milkyway.gsfc.nasa.gov","institution":"NASA/GSFC/Swift","name":"Ann M. Parsons"},"coordinates":{},"detectionTime":"2007-07-24T15:31:04.000Z","event":"GRB 070724","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6656\nSUBJECT: GRB 070724, Swift-BAT refined analysis of a short burst\nDATE: 07/07/24 15:31:04 GMT\nFROM: Ann M. Parsons at NASA/GSFC/Swift  <parsons@milkyway.gsfc.nasa.gov>\n\nA. Parsons (GSFC), L. Barbier (GSFC), S.D. Barthelmy (GSFC),\nJ. Cummings (GSFC/UMBC), E. Fenimore (LANL),\nN. Gehrels (GSFC), H. Krimm (GSFC/USRA),\nC. Markwardt (GSFC/UMD), D. Palmer (LANL),\nT. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS),\nM. Stamatikos (GSFC/ORAU), J. Tueller (GSFC),\nT. Ukwatta (GWU), H. Ziaeepour (UCL-MSSL)\n(i.e. the Swift-BAT team):\n\nUsing the data set from T-310 to T+ 310 sec from the recent\ntelemetry downlink, we report further analysis of BAT GRB 070724\n(trigger #285948) (Ziaeepour, et al., GCN Circ. 6654).  The BAT\nground-calculated position is RA, Dec = 27.824, -18.610 deg which is\n    RA(J2000) = 1h 51m 17.9s\n    Dec(J2000) = -18d 36'' 35\"\nwith an uncertainty of 2.3 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 91%.\n\nThe mask-weighted light curve for GRB 070724 consists of a single spike\npeaking at  T+0.2 sec.  Upon inspection of the mask weighted light curve\nout to T + 310 sec we find no evidence for extended emission.\nT90 (15-350 keV) is 0.4 +- 0.04 sec (estimated error including\nsystematics).\n\nThe time-averaged spectrum from T-0.0 to T+0.4 sec is best fit by\na simple power-law model. The power law index of the time-averaged\nspectrum is 1.81 +- 0.33. The fluence in the 15-150 keV band is\n3.0 +- 0.7 x 10^-08 erg/cm2. The 1-sec peak photon flux measured\nfrom T-0.30 sec in the 15-150 keV band is 1.0 +- 0.2 ph/cm2/sec.\nAll the quoted errors are at the 90% confidence level."}', 'Astronomical alert: GRB 070724, Swift-BAT refined analysis of a short burst', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6655', 'gcn', 'GRB 070721B', '2007-07-24T15:00:42.000Z', '{"measurements":{"dec":"-02:11:41.4","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"distance_to_high_redshift_galaxy":"~150 kpc","time_since_trigger_first_observation":"17.6 hr","time_since_trigger_second_observation":"47.3 hr"},"ra":"02:12:33.00","redshift":3.62,"tables":[]},"authors":{"affiliations":["University of Hertfordshire","Niels Bohr Institute, University of Copenhagen, Danish Astrophysical Observatory"],"authors":["J.P.U. Fynbo","P. Jakobsson","Daniele Malesani","J. Hjorth","I. Ilyn"],"institutions":["Dark Cosmology Center"],"universities":["University of Hertfordshire","Niels Bohr Institute, University of Copenhagen"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Nordic Optical Telescope","ESO-VLT"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_search.msfc?GCN_ID=6655"],"basic_data":{"author":{"email":"malesani@astro.ku.dk","institution":"Niels Bohr Inst,Dark Cosmology Center","name":"Daniele Malesani"},"coordinates":{"dec":2.209166666666667},"detectionTime":"2007-07-24T15:00:42.000Z","event":"GRB 070721B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6655\nSUBJECT: GRB 070721B: further observations and analysis\nDATE: 07/07/24 15:00:42 GMT\nFROM: Daniele Malesani at Niels Bohr Inst,Dark Cosmology Center  <malesani@astro.ku.dk>\n\nJ.P.U. Fynbo (DARK), P. Jakobsson (Univ. Hertfordshire), D. Malesani, J. \nHjorth (DARK), I. Ilyn (AIP), report:\n\nWe have obtained further observations of GRB 070721B (Ziaeepour et al., \nGCN Report 73). We also performed further analysis on our images of the \noptical afterglow of GRB 070721B (Malesani et al., GCN 6651).\n\nOur first observation was carried out with the Nordic Optical Telescope \n(mean time July 22.173 UT, i.e. 17.6 hr after the trigger). Close to the \nUVOT position, we detect a single source at the following coordinates \n(J2000, against USNO-B1):\n\nRA = 02:12:33.00\nDec = -02:11:41.4\n\nThis position is consistent with source #2 reported by Malesani et al. \n(GCN 6651).\n\nWe have also obtained further imaging with the ESO-VLT on July 23.409 UT \n(47.3 hr after the trigger). We find that source #2 has faded compared \nto the two previous epochs. We hence confirm that object #2 is the \noptical afterglow of GRB 070721B. Object #1, reported by Malesani et al. \n(GCN 6651), is most likely a spurious source caused by a reflection from \nthe bright star 0877-0042643 in the field (R~6.5).\n\nIn our 2-dimensional spectrum we also note the presence of bright \nhigh-redshift galaxy with a redshift z=3.62, very close to the redshift \nof GRB 070721B (Malesani et al., GCN 6651). This object is 21\" away of \nthe afterglow, which corresponds to ~150 kpc at z=3.62.\n\nWe acknowledge the ESO staff for excellent support."}', 'Astronomers report further observations and analysis of GRB 070721B using the Nordic Optical Telescope and ESO-VLT. They confirm the identification of the optical afterglow and detect a high-redshift galaxy with a redshift of 3.62, which is 21" (~150 kpc) away from the afterglow.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6654', 'gcn', 'GRB 070724', '2007-07-24T11:22:00.000Z', '{"measurements":{"dec":-18.622,"distance":null,"duration":1,"energy":null,"fluence":null,"magnitude":19.2,"other_measurements":{"E(B-V) Reddening":"0.01","UVOT Finding Chart Exposure":"100s","XRT Error Circle Coverage":"100%","XRT Observation Time":"67 seconds"},"ra":27.818,"redshift":null,"tables":[{"column_name":"RA(J2000)","value":"01h 51m 16s"},{"column_name":"Dec(J2000)","value":"-18d 37'' 17\""},{"column_name":"Uncertainty","value":"3 arcmin"},{"column_name":"Peak Count Rate","value":"~2700 counts/sec (15-350 keV)"},{"column_name":"RA(J2000)","value":"01 51 13.86"},{"column_name":"Dec(J2000)","value":"-18 35 42.4"},{"column_name":"Uncertainty","value":"4.7 arcsec"},{"column_name":"Initial Flux","value":"6.4e-10 erg/cm2/s (0.2-10 keV)"},{"column_name":"Finding Chart Exposure","value":"100s"},{"column_name":"3-sigma upper limit","value":"19.2 mag"}]},"authors":{"affiliations":["UCL-MSSL","GSFC","U Leicester","PSU","NASA/GSFC","CRESST/GSFC/USRA","GSFC/USRA","INAF-IASFPA","Univ. Bicocca","INAF-OAB","MSSL-UCL"],"authors":["H. Ziaeepour","S. D. Barthelmy","A. P. Beardmore","D. N. Burrows","M. De Pasquale","P. A. Evans","N. Gehrels","S. T. Holland","H. A. Krimm","V. Mangano","F. E. Marshall","P. T. O''Brien","J. P. Osborne","C. Pagani","K. L. Page","D. M. Palmer","A. M. Parsons","P. Romano","B. Sbarufatti","P. Schady","M. Stamatikos","R. L. C. Starling"],"institutions":["NASA/GSFC","CRESST/GSFC/USRA","GSFC/USRA","INAF-OAB","NASA/ORAU"],"universities":["UCL-MSSL","PSU","U Leicester","NASA/ORAU","Univ. Bicocca","INAF-IASFPA","MSSL-UCL"]},"telescopes":{"facilities":["Swift"],"instruments":["BAT"],"observatories":["Swift"],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{"dec":1.85385},"detectionTime":"2007-07-24T11:22:00.000Z","event":"GRB 070724","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6654\nSUBJECT: GRB 070724: Swift detection of a burst\nDATE: 07/07/24 11:22:00 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nH. Ziaeepour (UCL-MSSL), S. D. Barthelmy (GSFC),\nA. P. Beardmore (U Leicester), D. N. Burrows (PSU),\nM. De Pasquale (UCL-MSSL), P. A. Evans (U Leicester),\nN. Gehrels (NASA/GSFC), S. T. Holland (CRESST/GSFC/USRA),\nH. A. Krimm (GSFC/USRA), V. Mangano (INAF-IASFPA),\nF. E. Marshall (NASA/GSFC), P. T. O''Brien (U Leicester),\nJ. P. Osborne (U Leicester), C. Pagani (PSU),\nK. L. Page (U Leicester), D. M. Palmer (LANL), A. M. Parsons (GSFC),\nP. Romano (Univ. Bicocca & INAF-OAB), B. Sbarufatti (INAF-IASFPA),\nP. Schady (MSSL-UCL), M. Stamatikos (NASA/ORAU) and\nR. L. C. Starling (U Leicester) report on behalf of the Swift Team:\n\nAt 10:53:50 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 070724 (trigger=285948). Swift slewed immediately to the\nburst. The BAT on-board calculated location is RA, Dec 27.818,\n-18.622 which is\n  RA(J2000) = 01h 51m 16s\n  Dec(J2000) = -18d 37'' 17\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including\nsystematic uncertainty). The BAT light curve showed a strong spike\nabout one second long at T+0 sec. The peak count rate was ~2700\ncounts/sec (15-350 keV), at ~0 sec after the trigger. This could be a\nshort burst although the spectrum is not hard. \n\nThe XRT began observing the field at 10:54:56 UT, 67 seconds after the\nBAT trigger. Using prompt downlinked data, we find a variable, \nuncatalogued X-ray source located at RA, Dec 27.8077, -18.5951 which is\n   RA(J2000)  = 01 51 13.86\n   Dec(J2000) = -18 35 42.4\nwith an uncertainty of 4.7 arcsec (radius, 90% containment). \nThis location is 102 arcseconds from the BAT on-board position,\nwithin the BAT error circle. The initial flux in the 2.5s image\nwas 6.4e-10 erg/cm2/s (0.2-10 keV). \n\nUVOT took a finding chart exposure of 100s with the White filter\nstarting 75s after the BAT trigger. No afterglow candidate has been\nfound in the initial data products. The 2.7''x2.7'' sub-image covers\n100% of the XRT error circle. The 3-sigma upper limit is\nabout 19.2 mag. No correction has been made for the expected reddening \nof E(B-V) of 0.01. \n\nBurst Advocate for this burst is H. Ziaeepour (hz AT mssl.ucl.ac.uk). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift satellite detected a gamma-ray burst (GRB 070724) at 10:53:50 UT with a peak count rate of ~2700 counts/sec and a location of RA 01h 51m 16s, Dec -18d 37'' 17'''' (uncertainty: 3 arcmin). The X-ray Telescope (XRT) identified a variable X-ray source 102 arcseconds from the burst position, with an initial flux of 6.4e-10 erg/cm2/s (0.2-10 keV). No afterglow candidate was found in the UV-Optical Telescope (UVOT) data. The XRT observed the field 67 seconds after the trigger and covered 100% of the XRT error circle.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6653', 'gcn', 'GRB 070326', '2007-07-22T21:59:33.000Z', '{"measurements":{"dec":"-66d 59'' 21\"","distance":null,"duration":"17.3 sec","energy":"15-150 keV","fluence":"(3.45 +- 0.37) x 10^-7 erg/cm2","magnitude":null,"other_measurements":{"coding_fraction":"65%","exposure_time":"58.0 sec","photon_index":"1.44 +- 0.17","rise_duration":"3 sec"},"ra":"2h 41m 20.8s","redshift":null,"tables":[]},"authors":{"affiliations":["Harvard","NASA/GSFC"],"authors":["A. Copete","J. Grindlay","J. Hong","S. Barthelmy","N. Gehrels"],"institutions":["Harvard-Smithsonian Center for Astrophysics (CFA)"],"universities":["Harvard"]},"telescopes":{"facilities":["BAT Slew Survey (BATSS)"],"instruments":["BAT"],"observatories":["GSFC"],"telescopes":["Swift"]},"urls":["https://ui.adsabs.harvard.edu/abs/2007astro.ph..43294G"],"basic_data":{"author":{"email":"acopete@head.cfa.harvard.edu","institution":"Harvard U","name":"Antonio Copete"},"coordinates":{},"detectionTime":"2007-07-22T21:59:33.000Z","event":"GRB 070326","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6653\nSUBJECT: GRB 070326: Detection of first burst from BAT Slew Survey (BATSS)\nDATE: 07/07/22 21:59:33 GMT\nFROM: Antonio Copete at Harvard U  <acopete@head.cfa.harvard.edu>\n\nA. Copete, J. Grindlay, and J. Hong (Harvard),\nS. Barthelmy and N. Gehrels (NASA/GSFC)\n\nWe report on the first GRB found solely from imaging using BAT slew data,\nfrom a test run carried out in March 2007 of what will become the BAT Slew\nSurvey (BATSS; Grindlay, astro-ph# 0704.3294). A 58sec-long slew which\nbegan on 2007-03-26 16:29:10 UT, from a prior SAA passage onto Swift\nobservation number 00271019007, included a burst (hereafter referred to as\nGRB 070326) detected independently at 8.9 sigma and 6.9 sigma in the\n15-50keV and 50-150keV energy bands, respectively. The GRB T0 occurred 2\nsec after the start of the slew. The averaged position of the burst was\nfound to be:\n  RA(J2000) = 2h 41m 20.8s\n  Dec(J2000) = -66d 59'' 21\"\nwith an uncertainty radius of 3.9 arcmin (99% confidence).\nThe time-averaged coding fraction at the burst location was 65% and the\nexposure time was 58.0 sec.\n\nThe mask-weighted lightcurve features a single 17.3 sec peak, rising\nsharply over 3 sec and then followed by a steady, approximately\nexponential decay. Preliminary spectral analysis over the total duration\nof the burst shows a 15-150 keV spectrum that is best fit with a simple\npower law, with photon index of 1.44 +- 0.17. The burst fluence was\nestimated at (3.45 +- 0.37) x 10^-7 erg/cm2 (15-150 keV).\n\nBATSS will begin regular operations as soon as its pipeline processing\nsystems developed at Harvard are implemented at GSFC. Based on this\ninitial 7d of test slew processing and one new GRB detected, the overall\nrate of Swift GRBs could increase by ~20-40%. Follow-up pointings with XRT\ncould be commanded on the next satellite data pass, or with ~1-4h delay."}', 'Astronomers report the first detection of a gamma-ray burst (GRB) using data from the BAT Slew Survey (BATSS) on Swift. The burst, named GRB 070326, was detected during a test run in March 2007 and occurred 2 seconds into a 58-second slew. The burst was located in the sky with an uncertainty radius of 3.9 arcmin and had a peak duration of 17.3 seconds. Preliminary analysis suggests a simple power law spectrum with a photon index of 1.44 ± 0.17 and a fluence of (3.45 ± 0.37) x 10^-7 erg/cm2. The detection of this GRB indicates that BATSS could potentially increase the overall rate of Swift GRB detections by 20-40%.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6652', 'gcn', 'GRB 070714B', '2007-07-22T20:15:47.000Z', '{"measurements":{"dec":"+28:17:50.8","distance":null,"duration":{"R":780,"g''":920},"energy":null,"fluence":null,"magnitude":25.5,"other_measurements":{"comparison_star_magnitude":null,"position_error":"0.4\""},"ra":"03:51:22.23","redshift":null,"tables":[]},"authors":{"affiliations":["UC Berkeley","DARK, UCB"],"authors":["D. A. Perley","J. S. Bloom","C. Thoene","N. R. Butler"],"institutions":["UC Berkeley","DARK, UCB"],"universities":["University of California, Berkeley"]},"telescopes":{"facilities":[],"instruments":["LRIS"],"observatories":[],"telescopes":["10m Keck I Telescope"]},"urls":["http://astro.berkeley.edu/~nat/swift/xrt_pos.html"],"basic_data":{"author":{"email":"dperley@astro.berkeley.edu","institution":"U.C. Berkeley","name":"Daniel Perley"},"coordinates":{"dec":3.856175},"detectionTime":"2007-07-22T20:15:47.000Z","event":"GRB 070714B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6652\nSUBJECT: GRB 070714B:  Keck observations\nDATE: 07/07/22 20:15:47 GMT\nFROM: Daniel Perley at U.C. Berkeley  <dperley@astro.berkeley.edu>\n\nGRB 070714B:  Keck late-time observations\n\nD. A. Perley, J. S. Bloom (UC Berkeley), C. Thoene (DARK, UCB), and N. R.\nButler (UC Berkeley) report:\n\nOn the night of 2007 July 18 (UT) we observed the field of GRB 070714B\nwith the 10m Keck I Telescope (+LRIS) for 780 seconds in R and 920 seconds\nin g'', starting at 14:30 UT.  We detect a single, very faint source\nconsistent with the position reported by Melandri et al. (GCN 6621) and\ninside the refined (GCN 6627) and improved [1] XRT error circles, in both\nfilters.  The location of this source is:\n\nRA = 03:51:22.23\nDec = +28:17:50.8\n\n(+/- 0.4\")\n\nThe object has an approximate magnitude of R~25.5, calibrating relative to\nthe USNO-B2.0 star at (03:51:21.5973, +28:18:55.810).  It does not appear\nvisibly extended in our imaging.  This rules out the presence of a bright\nhost galaxy and, comparing to the magnitude reported by Levan et al. (GCN\n6630) suggests a rapid late-time afterglow decay rate of the afterglow.\n\n\n[1] http://astro.berkeley.edu/~nat/swift/xrt_pos.html"}', 'A team of astronomers led by D. A. Perley at U.C. Berkeley observed the field of GRB 070714B using the 10m Keck I Telescope and detected a faint source consistent with the position of the gamma-ray burst. The source, which does not appear visibly extended, has an approximate magnitude of R~25.5 and suggests a rapid late-time afterglow decay rate.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6651', 'gcn', 'GRB 070721B', '2007-07-22T19:37:46.000Z', '{"measurements":{"dec":["-02:11:41.0","-02:11:41.6"],"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":[23.8,24.3],"other_measurements":{"time_after_grb":"21.6 hours"},"ra":["02:12:32.97","02:12:33.03"],"redshift":"3.626","tables":[]},"authors":{"affiliations":["Univ. Hertfordshire","Niels Bohr Inst, Dark Cosmology Center"],"authors":["Daniele Malesani","P. Jakobsson","J.P.U. Fynbo","J.","P.M. Vreeswijk"],"institutions":["Dark Cosmology Center"],"universities":["University of Hertfordshire","Niels Bohr Institute, University of Copenhagen"]},"telescopes":{"facilities":[],"instruments":["FORS2"],"observatories":[],"telescopes":["ESO-VLT"]},"urls":["http://www.astro.ku.dk/~malesani/GRB/070721B"],"basic_data":{"author":{"email":"malesani@astro.ku.dk","institution":"Niels Bohr Inst,Dark Cosmology Center","name":"Daniele Malesani"},"coordinates":{},"detectionTime":"2007-07-22T19:37:46.000Z","event":"GRB 070721B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6651\nSUBJECT: GRB 070721B: optical observations and proposed redshift\nDATE: 07/07/22 19:37:46 GMT\nFROM: Daniele Malesani at Niels Bohr Inst,Dark Cosmology Center  <malesani@astro.ku.dk>\n\nD. Malesani (DARK), P. Jakobsson (Univ. Hertfordshire), J.P.U. Fynbo, J. \nHjorth and P.M. Vreeswijk (DARK) report:\n\nWe observed the optical counterpart of GRB 070721B (Ziaeepour et al., \nGCN 6640; Schady, GCN 6641) with the ESO-VLT equipped with FORS2.\n\nClose to the UVOT position (Schady, GCN 6641), we detect two objects:\n\n1: RA = 02:12:32.97, Dec = -02:11:41.0\n2: RA = 02:12:33.03, Dec = -02:11:41.6\n\nWe note that object #1 is consistent with the UVOT position, while #2 is \n1.6\" away. We estimate R~23.8 and R~24.3 on Jul 22.319 UT (21.6 hr after \nthe GRB) for objects #1 and #2, respectively.\n\nWe acquired spectra for both objects. Thanks to the detection of a DLA \nand several metallic lines, we infer for object #2 a redshift z=3.626. \nThe spectrum is typical of a GRB afterglow, and we thus suggest that \nobject #2 is the optical counterpart of GRB 070721B. This redshift is \nalso consistent with the nondetection of the object in filters bluer \nthan V (De Pasquale & Ziaeepour, GCN 6650). Further observations are \nplanned to test the variability of both objects.\n\nA finding chart and a plot of the 2D spectrum is available at:\n\nhttp://www.astro.ku.dk/~malesani/GRB/070721B\n\nWe acknowledge excellent support from the ESO staff, in particular \nAngela Cortes, Dominique Naef and Yuri Beletsky. We thank Massimiliano \nDe Pasquale for useful discussion."}', 'Astronomers led by Daniele Malesani at the Niels Bohr Institute have identified the optical counterpart of GRB 070721B using the ESO-VLT and FORS2. They detected two objects near the GRB position, with one having a redshift of z=3.626, consistent with the nondetection in bluer filters. The team suggests this object is the afterglow of GRB 070721B.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6650', 'gcn', 'GRB070721B', '2007-07-21T21:37:28.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null},"authors":{"affiliations":["MSSL/UCL"],"authors":["M. De Pasquale","H. Ziaeepour"],"institutions":["MSSL (Mullard Space Science Laboratory)"],"universities":["University College London (UCL)"]},"telescopes":{"facilities":[],"instruments":["Swift/UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"mdp@mssl.ucl.ac.uk","institution":"MSSL-UCL","name":"Massimiliano de Pasquale"},"coordinates":{},"detectionTime":"2007-07-21T21:37:28.000Z","event":"GRB070721B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6650\nSUBJECT: Swift/UVOT observations of GRB070721B optical afterglow.\nDATE: 07/07/21 21:37:28 GMT\nFROM: Massimiliano de Pasquale at MSSL-UCL  <mdp@mssl.ucl.ac.uk>\n\nM. De Pasquale and H. Ziaeepour (MSSL/UCL) report on the\nbehalf of the Swift/UVOT:\n\n  The optical afterglow of GRB070721B (Ziaeepour et al. GCN 6640, Schady\net al. 6641) is detected by Swift/UVOT in White filter and V filter\nfinding chart exposures, taken 100s-200s and 207-607s after the BAT\ntrigger. It is not detected at 3sigma level in other exposures, either\nsingle or summed ones in all filters, till ~7000s after the trigger.\n\n  In the following table, we report the magnitudes of the afterglow for\nthe exposures where the source is detected with at least 3sigma level,\nand 3sigma upper limits otherwise.\n\n\n  Filter  Time(s)   Exp(s)      Magnitude\n\n  White   100-200      99       16.82 +/- 0.1\n\n  White   701-711      10        >18.8\n\n  White   855-955      99        >19.9\n\n  White   5089-6716   393        >20.9\n\n\n   V      207-453     399       16.7 +/- 0.1\n\n   V      621-641      19        >17.5\n\n   V      961-1116    154        >18.3\n\n   V     5500-5699    199        >18.7\n\n\n   B       687-850     19        >18.4\n\n   B     4884-6519    393        >20.4\n\n\n   U       662-835     39        >18.5\n\n   U     4679-6314    393        >20.1\n\n\n  UW1     638-658      39        >18.8\n\n  UW1    638-6109     432        >20.2\n\n\n  UM2     613-786      39        >18.9\n\n  UM2    613-5904     432        >20.6\n\n\n  UW2     780-800      19        >18.8\n\n  UW2    780-6902     385        >20.3\n\n\n  These values are not corrected for the Galactic\nreddening towards the bursts E(B-V)=0.02 mag (Schlegel,\nFinkbeiner & Davic, 1998)"}', 'Swift/UVOT has detected the optical afterglow of GRB070721B in White and V filters, with magnitudes of 16.82 +/- 0.1 and 16.7 +/- 0.1, respectively. The afterglow was not detected in other filters or exposures taken after ~700 seconds. These measurements were obtained by M. De Pasquale and H. Ziaeepour at MSSL/UCL.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-665', 'gcn', 'GRB 000508B', '2000-05-09T22:03:52.000Z', '{"measurements":{"dec":-20.504,"distance":null,"duration":10,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"camera_rotation":"six degrees","observation_duration":"90 s","peak_intensity":"~1.5 Crab (2-12 keV)","rise_duration":"approximately 10 s"},"ra":253.498,"redshift":null,"tables":[{"Decl.":-20.432,"R.A.":253.7},{"Decl.":-20.38,"R.A.":253.643},{"Decl.":-20.456,"R.A.":253.483},{"Decl.":-20.511,"R.A.":253.5383}]},"authors":{"affiliations":["MIT","UCB","NASA/GSFC"],"authors":["D. A. Smith","A. M. Levine","K. Hurley","S. Barthelmy"],"institutions":["MIT","NASA/GSFC"],"universities":["MIT","UCB"]},"telescopes":{"facilities":[],"instruments":["ASM"],"observatories":["IPN"],"telescopes":["RXTE/ASM"]},"urls":["http://xte.mit.edu/grb000508b/"],"basic_data":{"author":{"email":"dasmith@space.mit.edu","institution":"MIT","name":"Don Smith"},"coordinates":{},"detectionTime":"2000-05-09T22:03:52.000Z","event":"GRB 000508B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 665\nSUBJECT: RXTE/ASM and IPN localization of GRB 000508B\nDATE: 00/05/09 22:03:52 GMT\nFROM: Don Smith at MIT  <dasmith@space.mit.edu>\n\nD. A. Smith and A. M. Levine (MIT), K. Hurley (UCB), and S. Barthelmy\n(NASA/GSFC) report on behalf of the RXTE/ASM teams at MIT and\nNASA/GSFC and the IPN collaboration:\n\nThe RXTE All-Sky Monitor has detected emission we associate with GRB\n000508B (BATSE #8098).  One camera of the ASM was advantageously\nplaced to observe the field around the BATSE LOCBURST position within\n200 seconds of the trigger time (19:10:50.88 UTC).  A dramatic rise in\nintensity occured over approximately 10 s, to a peak of ~1.5 Crab\n(2-12 keV) at roughly 19:13:44, 75 s into a 90-s ASM observation.\nAnalysis of the position histogram data shows evidence for a\npreviously unknown X-ray source in this and the next sequential\nobservation, after the camera was rotated through six degrees.\n\nLocalizations of these two detections yields an error box in the shape\nof a long, thin parallelogram centered at R.A. = 253.498d, Decl. =\n-20.504d (J2000).  This position is confirmed by an annulus derived\nvia the IPN through detections by BATSE and Ulysses.  The preliminary\nannulus is 9.67'' in width (3sigma), with a radius of 76.512 deg,\ncentered at R.A. = 309.088, Decl. = 35.112 (J2000.0).  This annulus\nintersects the above diamond at the following points, creating a joint\nerror box with area ~46 sq. arcmin.:\n\n253.700d {16h 54m 48s} -20.432d {-20d 25'' 55\"}\n253.643d {16h 54m 34s} -20.380d {-20d 22'' 48\"}\n253.483d {16h 53m 56s} -20.456d {-20d 27'' 22\"}\n253.5383 {16h 54m 09s} -20.511d {-20d 30'' 40\"}\n\nThe time of the increase in the count rate in the first ASM\nobservation is consistent with the estimated time that the best-fit\nlocation for the GRB rose from behind the Earth''s limb, so we\nattribute the characteristics of the rise and the lack of detectable\nemission prior to this time to Earth occultation, not to any intrinsic\nproperties of the GRB source.\n \nSee the web page at http://xte.mit.edu/grb000508b/\nfor images and further commentary."}', 'The RXTE/ASM team at MIT and NASA/GSFC, in collaboration with the IPN, report the detection of GRB 000508B and its subsequent localization. The event was observed by one ASM camera, which detected a dramatic rise in intensity approximately 10 seconds after the trigger time. The position of the GRB was determined to be at R.A. = 253.498d, Decl. = -20.504d, with an error box shaped as a long, thin parallelogram. This position was confirmed by the IPN through detections by BATSE and Ulysses.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6649', 'gcn', 'GRB 070721B', '2007-07-21T20:44:28.000Z', '{"measurements":{"dec":null,"distance":null,"duration":340,"energy":null,"fluence":0.0000036,"magnitude":null,"other_measurements":{"duration_band":"15-350 keV","fluence_band":"15-150 keV","peak_photon_flux":1.5,"peak_photon_flux_band":"15-150 keV","power_law_index":1.34,"time_interval_duration_1":140,"time_interval_duration_2":110},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["NASA/GSFC","GSFC/UMBC","GSFC/UMD","LANL","GSFC/ORAU","UCL-MSSL"],"authors":["S. D. Barthelmy","J. Cummings","C. Markwardt","D. Palmer","T. Sakamoto","H. Ziaeepour"],"institutions":["GSFC","ORAU"],"universities":["UMBC","UMD","LANL","UCL-MSSL"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-07-21T20:44:28.000Z","event":"GRB 070721B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6649\nSUBJECT: GRB 070721B, Further Swift-BAT refined analysis\nDATE: 07/07/21 20:44:28 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nS. D. Barthelmy (GSFC), J. Cummings (GSFC/UMBC), C. Markwardt (GSFC/UMD),\nD. Palmer (LANL), T. Sakamoto (GSFC/ORAU), H. Ziaeepour (UCL-MSSL)\n(on behalf of the Swift-BAT team):\n \nUsing the data set from T-239 to T+903 sec from recent telemetry downlinks,\nwe report further analysis of BAT GRB 070721B (trigger #285654)\n(Ziaeepour, et al., GCN Circ. 6640; and Palmer, et al., GCN Circ. 6643).\n \nBeyond the previously reported description of the mask-weighted lightcurve\n(Palmer, 6643), the burst had a second episode of emission with multiple peaks\nfrom T+230 sec to T+380.  We note that there are still gaps in the downlinked\nlightcurve data (1: T+530 to T+670, and 2: T+720 to T+830 sec) and as such,\nwe can not say anything about burst emission in these two intervals.\nT90 (15-350 keV) is 340 +- 10 sec (estimated error including systematics).\n \nThe time-averaged spectrum from T-6.7 to T+359.9 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n1.34 +- 0.11.  The fluence in the 15-150 keV band is 3.6 +- 0.2 x 10^-06 erg/cm2.\nThe 1-sec peak photon flux measured from T-0.19 sec in the 15-150 keV band\nis 1.5 +- 0.3 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel."}', 'Astronomers, led by the Swift-BAT team, have reported further analysis of GRB 070721B (trigger #285654), identifying a second episode of emission with multiple peaks from 230 to 380 seconds after the initial gamma-ray burst. The duration of the burst is estimated to be 340 seconds, with a time-averaged spectrum best fit by a simple power-law model. The power law index of the time-averaged spectrum is 1.34 +- 0.11, and the fluence in the 15-150 keV band is 3.6 +- 0.2 x 10^-06 erg/cm2. The 1-sec peak photon flux measured from 190 milliseconds in the same band is 1.5 +- 0.3 ph/cm2/sec.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6648', 'gcn', 'GRB070721A', '2007-07-21T18:56:56.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"Galactic extinction":"E(B-V) = 0.01 mag","Star distance from XRT position":"4 arcseconds","Star magnitude":"18th mag"},"ra":null,"redshift":null,"tables":[{"Exp(s)":156,"Filter":"White","Mag (3-sig upper limit)":"> 21.7","T_mid(s)":1088},{"Exp(s)":453,"Filter":"V","Mag (3-sig upper limit)":"> 20.9","T_mid(s)":1194},{"Exp(s)":97,"Filter":"B","Mag (3-sig upper limit)":"> 19.5","T_mid(s)":1509},{"Exp(s)":117,"Filter":"U","Mag (3-sig upper limit)":"> 20.0","T_mid(s)":1359},{"Exp(s)":117,"Filter":"UVW1","Mag (3-sig upper limit)":"> 19.6","T_mid(s)":1334},{"Exp(s)":117,"Filter":"UVM2","Mag (3-sig upper limit)":"> 19.2","T_mid(s)":1309},{"Exp(s)":97,"Filter":"UVW2","Mag (3-sig upper limit)":"> 19.4","T_mid(s)":1530}]},"authors":{"affiliations":["MSSL-UCL"],"authors":["P. Schady","H. Ziaeepour"],"institutions":["MSSL (Mullard Space Science Laboratory)"],"universities":["University College London (UCL)"]},"telescopes":{"facilities":[],"instruments":["Swift/UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"ps@mssl.ucl.ac.uk","institution":"MSSL/Swift","name":"Patricia Schady"},"coordinates":{},"detectionTime":"2007-07-21T18:56:56.000Z","event":"GRB070721A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6648\nSUBJECT: Swift/UVOT Observations of GRB070721A\nDATE: 07/07/21 18:56:56 GMT\nFROM: Patricia Schady at MSSL/Swift  <ps@mssl.ucl.ac.uk>\n\nP. Schady (MSSL-UCL) and H. Ziaeepour (MSSL-UCL) report on behalf of the \nSwift/UVOT team:\n\nThe Swift/UVOT observed the field of GRB 070721A starting 69 s after the \nBAT trigger (Ziaeepour et al. GCN Circ.6639). We do not find any source, \nin any of the UVOT observations inside the refined XRT error circle (Evans \net al., GCN Circ.6644). However, we note that there is an 18th mag star 4 \narcseconds from the XRT refined position.\n\nThe 3-sigma upper limits for detecting a source inside the XRT error \ncircle are:\n\nFilter  T_mid(s)  Exp(s)  Mag (3-sig upper limit)\n=================================================\nWhite   1088      156     > 21.7\nV       1194      453     > 20.9\nB       1509      97      > 19.5\nU       1359      117     > 20.0\nUVW1    1334      117     > 19.6\nUVM2    1309\t  117     > 19.2\nUVW2    1530      97      > 19.4\n\nwhere T_mid is the weighted mid time of the coadded exposure. The values \nquoted above are not corrected for the expected Galactic extinction \ncorresponding to a reddening of E(B-V) = 0.01 mag in the direction of the \nburst (Schlegel et al. 1998)."}', 'The Swift/UVOT team reported no detection of a source within the XRT error circle of GRB 070721A, despite observing the field 69 seconds after the gamma-ray burst trigger. The team noted an 18th magnitude star 4 arcseconds from the XRT position. They provided 3-sigma upper limits for detecting a source in various filters, uncorrected for Galactic extinction.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6647', 'gcn', 'GRB 070721B', '2007-07-21T18:43:02.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"I":17.8,"R":19.3},"other_measurements":{"time_after_trigger_I":"6.2 hours","time_after_trigger_R":"6.4 hours"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Liverpool JMU","Uni-Bicoca/INAF-OAB","Ljubljana"],"authors":["A. Melandri","C. Guidorzi","I.A. Steele","C.G. Mundell","D. Carter","R.J. Smith","C.J. Mottram","D.F. Bersier","S. Kobayashi","M.J. Burgdorf","M.F. Bode","A. Gomboc","P. O''Brien","E. Rol","N. Bannister"],"institutions":["Liverpool John Moores U","Uni-Bicocca","INAF-OAB","Ljubljana"],"universities":["Liverpool JMU","Uni-Bicoca","INAF-OAB","Ljubljana"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Faulkes Telescope South"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"axm@astro.livjm.ac.uk","institution":"Liverpool John Moores U","name":"Andrea Melandri"},"coordinates":{},"detectionTime":"2007-07-21T18:43:02.000Z","event":"GRB 070721B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6647\nSUBJECT: GRB 070721B : Faulkes Telescope South observations\nDATE: 07/07/21 18:43:02 GMT\nFROM: Andrea Melandri at Liverpool John Moores U  <axm@astro.livjm.ac.uk>\n\nA. Melandri, (Liverpool JMU), C. Guidorzi (Uni-Bicocca/INAF-OAB),\nI.A. Steele, C.G. Mundell, D. Carter, R.J. Smith, C.J. Mottram,\nD.F. Bersier, S. Kobayashi, M.J. Burgdorf, M.F. Bode (Liverpool JMU),\nA. Gomboc (Ljubljana), P. O''Brien, E. Rol, N. Bannister (Leicester)\nreport\n\nWe observed the field of GRB 070721B (trigger=285654, Ziaeepour\net al., GCN 6640) with the Faulkes Telescope South on 2007 Jul 21\nstarting at 16:01:21 UT (~5.45 hours after the trigger).\n\nWe do not detect any new source inside the refined XRT error circle\n(Beardmore et al., GCN 6646) and we do not detect the UVOT candidate\nreported by Schady et al. (GCN 6641) in our optical images.\n\nWe can set an upper limit for this burst of R>19.3 and I>17.8\n@ 6.4 and 6.2 hours after the trigger, respectively."}', 'Astronomers using the Faulkes Telescope South reported no detection of a new source or the UVOT candidate in the error circle of GRB 070721B, a gamma-ray burst discovered on July 21, 2007. They set upper limits for the burst''s optical magnitudes at R=19.3 and I=17.8, 6.4 and 6.2 hours after the trigger, respectively.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6646', 'gcn', 'GRB 070721B', '2007-07-21T18:32:41.000Z', '{"measurements":{"dec":"-02:11:40.6","distance":null,"duration":"700 seconds","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"column_density":"1.9 (+1.8-1.9) e20 cm^-2","count_rate_max":"50 count/s","observed_flux_0_3_10_kev":"2.37+/-0.25 e-10 ergs cm^-2 s^-1","photon_index":"1.48 +0.18-0.16","predicted_count_rate_24hr":"0.025 count/s","predicted_flux_24hr_0_3_10_kev":"1.4e-12 ergs cm^-2 s^-1","unabsorbed_flux_0_3_10_kev":"2.45+/-0.25 e-10 ergs cm^-2 s^-1","uncertainty":"3.5 arcseconds"},"ra":"02:12:32.90","redshift":null,"tables":[]},"authors":{"affiliations":["U. Leicester","MSSL-UCL"],"authors":["A.P. Beardmore","K.L. Page","P.A. Evans","H. Ziaeepour"],"institutions":["U. Leicester","MSSL-UCL"],"universities":["University of Leicester","MSSL-UCL"]},"telescopes":{"facilities":[],"instruments":["Swift-XRT"],"observatories":[],"telescopes":["Swift-XRT"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars/6641/6641.gcn3.xml","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars/6643/6643.gcn3.xml","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars/6640/6640.gcn3.xml"],"basic_data":{"author":{"email":"apb@star.le.ac.uk","institution":"U Leicester","name":"Andy Beardmore"},"coordinates":{"dec":2.209138888888889},"detectionTime":"2007-07-21T18:32:41.000Z","event":"GRB 070721B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6646\nSUBJECT: GRB 070721B: Swift-XRT refined analysis\nDATE: 07/07/21 18:32:41 GMT\nFROM: Andy Beardmore at U Leicester  <apb@star.le.ac.uk>\n\nA.P. Beardmore, K.L. Page, P.A. Evans (U. Leicester) and H. Ziaeepour \n(MSSL-UCL) report on behalf of the Swift-XRT team :\n\nWe have analysed the first three orbits of Swift-XRT data on GRB 070721B\n(Ziaeepour et al., GCN 6640). Using 5.78ks of Photon Counting mode data, \nwe find a refined XRT position of  RA, Dec = 33.13710, -2.19462 which is\n\nRA(J2000):   02:12:32.90\nDec(J2000): -02:11:40.6\n\nwith an uncertainty of 3.5 arcseconds (90% containment radius).  This\nis 35 arcseconds from the refined BAT position reported by Palmer et\nal. (GCN 6643), 8.9 arcsec from the original XRT position reported in\nZiaeepour et al. (GCN 6640), and 0.7 arcseconds from the UVOT position\nreported by Schady (GCN 6641).\n\nThe X-ray light curve shows an initial steep decay from T+100s to\nT+144s, followed by a number of flares from T+255s to T+800s\nwhich reached a maximum count rate of 50 count/s at T+315s.  The\nunderlying decay is a powerlaw with a slope of approximately -0.9,\nthough it is difficult to be precise with the data available so far.\n\nThe X-ray spectrum from the Windowed Timing mode data obtained during\nthe non-flare intervals from the 1st orbit (T+144s to T+220s and\nT+400s to T+475s) can be fit with an absorbed powerlaw to give a photon\nindex of 1.48 +0.18-0.16 and a column density of 1.9 (+1.8-1.9) e20 cm^-2,\nconsistent with the Galactic value of 2.3e20 cm^-2 in this direction\n(Kalberla et al. 2005).  The observed 0.3-10 keV flux is 2.37+/-0.25 e-10\nergs cm^-2 s^-1, which corresponds to an unabsorbed flux of \n2.45+/-0.25 e-10 ergs cm^-2 s^-1.\n\nIf the underlying decay continues at the same rate, we predict an XRT\ncount rate of 0.025 count/s at T+24hr, which corresponds to an observed\n0.3-10keV flux of 1.4e-12 ergs cm^-2 s^-1.\n\nThis circular is an official product of the Swift-XRT team."}', 'The Swift-XRT team at the University of Leicester and MSSL-UCL have analyzed the first three orbits of Swift-XRT data on GRB 070721B and refined its position to RA, Dec = 02:12:32.90, -02:11:40.6 with an uncertainty of 3.5 arcseconds. The X-ray light curve shows an initial steep decay followed by a number of flares, and the underlying decay is a powerlaw with a slope of approximately -0.9. The X-ray spectrum obtained during non-flare intervals can be fit with an absorbed powerlaw, and the observed 0.3-10 keV flux is 2.37+/-0.25 e-10 ergs cm^-2 s^-1.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6645', 'gcn', 'GRB 070721A', '2007-07-21T15:25:42.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":20,"other_measurements":{"observation_time":"between 3.9 and 4.8 hours after the trigger"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Liverpool JMU","Uni-Bicocca/INAF-OAB","Ljubljana"],"authors":["A. Melandri","C. Guidorzi","I.A. Steele","C.G. Mundell","D. Carter","R.J. Smith","C.J. Mottram","D.F. Bersier","S. Kobayashi","M.J. Burgdorf","A. Gomboc","P. O''Brien","E. Rol","N. Bannister"],"institutions":["Liverpool John Moores U","Uni-Bicocca/INAF-OAB"],"universities":["Liverpool JMU","Uni-Bicocca","INAF-OAB","Ljubljana"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Faulkes Telescope South"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6644","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6639"],"basic_data":{"author":{"email":"axm@astro.livjm.ac.uk","institution":"Liverpool John Moores U","name":"Andrea Melandri"},"coordinates":{},"detectionTime":"2007-07-21T15:25:42.000Z","event":"GRB 070721A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6645\nSUBJECT: GRB 070721A : Faulkes Telescope South optical limit\nDATE: 07/07/21 15:25:42 GMT\nFROM: Andrea Melandri at Liverpool John Moores U  <axm@astro.livjm.ac.uk>\n\nA. Melandri, (Liverpool JMU), C. Guidorzi (Uni-Bicocca/INAF-OAB),\nI.A. Steele, C.G. Mundell, D. Carter, R.J. Smith, C.J. Mottram,\nD.F. Bersier, S. Kobayashi, M.J. Burgdorf, M.F. Bode (Liverpool JMU),\nA. Gomboc (Ljubljana), P. O''Brien, E. Rol, N. Bannister (Leicester)\nreport\n\n\nOn 2007 Jul 21 at 13:47:14 UT the Faulkes Telescope South\nobserved the field of GRB070721A (trigger=285653, Ziaeepour\net al., GCN 6639).\n\nNo new source is detected inside the refined XRT error circle\n(Evans et al., GCN 6644) and we can set an upper limit of\nR > 20.0 between 3.9 and 4.8 hours after the trigger."}', 'The Faulkes Telescope South did not detect a new source in the error circle of GRB070721A, and set an upper limit of R > 20.0 for the magnitude between 3.9 and 4.8 hours after the trigger.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6644', 'gcn', 'GRB 070721A', '2007-07-21T14:31:11.000Z', '{"measurements":{"dec":"-28 33 00.6","distance":null,"duration":"1.3 ks","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"alpha_initial_decay":2.97,"alpha_shallow_decay":0.75,"column_density":"1.61e20 cm^-2","gamma_value":2.24,"observed_flux_0_3_to_10_kev":"6.53e-12 erg cm^-2 s^-1","predicted_count_rate_24_hours":"2.7e-3 counts/s","predicted_observed_flux_24_hours":"1.87e-13 erg cm^-2 s^-1","predicted_unabsorbed_flux_24_hours":"2.36e-13 erg cm^-2 s^-1","time_of_alpha_change":"T0+281 (+112/-71) s","unabsorbed_flux_0_3_to_10_kev":"8.23e-12 erg cm^-2 s^-1"},"ra":"00 12 39.24","redshift":null,"tables":[]},"authors":{"affiliations":["U. Leicester","UCL-MSSL"],"authors":["P.A. Evans","H. Ziaeepour"],"institutions":["UCL-MSSL"],"universities":["University of Leicester"]},"telescopes":{"facilities":[],"instruments":["Swift/XRT","UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"pae9@star.le.ac.uk","institution":"U of Leicester","name":"Phil Evans"},"coordinates":{"dec":0.2109},"detectionTime":"2007-07-21T14:31:11.000Z","event":"GRB 070721A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6644\nSUBJECT: GRB 070721A: Swift/XRT refined analysis\nDATE: 07/07/21 14:31:11 GMT\nFROM: Phil Evans at U of Leicester  <pae9@star.le.ac.uk>\n\nP.A. Evans (U. Leicester) and H. Ziaeepour (UCL-MSSL) report on behalf of \nthe Swift/XRT team:\n\nWe have analyzed the first 1.3 ks of Swift XRT data for GRB 070721A \n(Ziaeepour et al. GCN Circ. 6639), comprising 35 s in Windowed Timing (WT) \nmode, and 1.3 ks in Photon Counting (PC) mode. The burst is clearly \ndetected. Using 799 s of overlapping XRT Photon Counting mode and UVOT \nV-band data, we find an astrometrically corrected X-ray position (using \nthe XRT-UVOT alignment and matching UVOT field sources to the USNO-B1 \ncatalogue): RA, Dec = 3.16348, -28.55017 which is equivalent to:\n\nRA (J2000):  00 12 39.24\nDec (J2000): -28 33 00.6\n\nwith an uncertainty of 2.3 arcsec (radius, 90% confidence). This position \nis 3.2\" from the initial XRT position reported in GCN Circ. 6639, and 95\" \nfrom the BAT-refined position reported by Sakamoto et al. (GCN Circ. \n6642).\n\nThe XRT light curve shows a fading behaviour, which is well fitted by a \nbroken power-law. The initial decay followed a slope of alpha=2.97 \n(+0.57/-0.42). At T0+281 (+112/-71) s the decay shallows to an alpha of \n0.75 (+0.39/-0.49).\n\nThe Photon Counting mode spectrum is well fitted by an absorbed power-law, \nwith a column density of 1.61e20 cm^-2 (the Galactic value) and a gamma of \n2.24 (+0.33/-0.26). This is consistent with the value derived for the BAT \nspectrum (GCN Circ 6642). The observed (unabsorbed) 0.3-10 keV flux is \n6.53e-12 (8.23e-12) erg cm^-2 s^-1.\n\nIf the source continues to decay at the same rate, we predict a count rate \nof 2.7e-3 counts/s at T0+24 hours, which corresponds to an observed \n(unabsorbed) flux of 1.87e-13 (2.36e-13) erg cm^-2 s^-1.\n\nThis circular is an official product of the Swift/XRT team."}', 'The Swift/XRT team has refined the analysis of GRB 070721A, reporting a revised X-ray position with an uncertainty of 2.3 arcsec and a decay behavior well-fit by a broken power-law. The initial decay followed a slope of 2.97, while the shallow decay occurred at T0+281 seconds with a slope of 0.75. The XRT light curve also revealed a column density of 1.61e20 cm^-2 and a gamma value of 2.24, consistent with the BAT spectrum. The observed (unabsorbed) 0.3-10 keV flux was measured at 6.53e-12 erg cm^-2 s^-1, and the team predicted a count rate of 2.7e-3 counts/s at T0+24 hours.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6643', 'gcn', 'GRB 070721B', '2007-07-21T14:22:17.000Z', '{"measurements":{"dec":-2.198,"distance":null,"duration":31.5,"energy":null,"fluence":0.0000021,"magnitude":null,"other_measurements":{"fluence_band":"15-150 keV","fluence_value":"2.1 +- 0.1 x 10^-6 erg/cm2","partial_coding":23,"peak_photon_flux":1.5,"peak_photon_flux_band":"15-150 keV","peak_photon_flux_value":"1.5 +- 0.3 ph/cm2/sec","power_law_index":1.31},"ra":33.128,"redshift":null,"tables":[]},"authors":{"affiliations":["NASA/GSFC","GSFC/UMBC","LANL","GSFC/USRA","GSFC/UMD","GSFC","GSFC/ORAU","GSFC","GSFC","GSFC/ORAU","GSFC/ISAS","UCL-MSSL"],"authors":["D. Palmer","L. Barbier","S. D. Barthelmy","J. Cummings","E. Fenimore","N. Gehrels","H. Krimm","C. Markwardt","A. Parsons","T. Sakamoto","G. Sato","M. Stamatikos","J. Tueller","T. Ukwatta","H. Ziaeepour"],"institutions":["NASA/GSFC","GSFC/UMBC","LANL","GSFC/USRA","GSFC/UMD","GSFC/ORAU","GWU"],"universities":["GSFC","UMBC","LANL","ISAS","UCL-MSSL","ORAU"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-07-21T14:22:17.000Z","event":"GRB 070721B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6643\nSUBJECT: GRB 070721B, Swift-BAT refined analysis\nDATE: 07/07/21 14:22:17 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nD. Palmer (LANL), L. Barbier (GSFC), S. D. Barthelmy (GSFC),\nJ. Cummings (GSFC/UMBC), E. Fenimore (LANL), N. Gehrels (GSFC),\nH. Krimm (GSFC/USRA), C. Markwardt (GSFC/UMD), A. Parsons (GSFC),\nT. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS), M. Stamatikos (GSFC/ORAU),\nJ. Tueller (GSFC), T. Ukwatta (GWU), H. Ziaeepour (UCL-MSSL)\n(i.e. the Swift-BAT team):\n \nUsing the data set from T-119 to T+183 sec from the recent telemetry downlink,\nwe report further analysis of BAT GRB 070721B (trigger #285654)\n(Ziaeepout, et al., GCN Circ. 6640).  The BAT ground-calculated position is\nRA, Dec = 33.128, -2.198 deg  which is \n   RA(J2000)  =  2h 12m 30.8s \n   Dec(J2000) = -2d 11'' 54\" \nwith an uncertainty of 1.2 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 23%.\n \nThe mask-weighted light curve shows a large main peak starting at ~T-20 sec,\npeaking at ~T+0 sec, and ending at ~T+70 sec.  We caution that currently\nwe only have downlinked data out to T+183 sec, and that there is a hint\nof activity past T+70 sec.  But we wanted to get this circular out without\nwaiting for further downlinks due to the uncertainites given the GCN Notices\nproblems earlier.  T90 (15-350 keV) is 31.5 +- TTT sec (estimated error\nincluding systematics).\n \nThe time-averaged spectrum from T-6.7 to T+33.7 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n1.31 +- 0.11.  The fluence in the 15-150 keV band is 2.1 +- 0.1 x 10^-6 erg/cm2.\nThe 1-sec peak photon flux measured from T-0.14 sec in the 15-150 keV band\nis 1.5 +- 0.3 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel."}', 'Astronomical alert: GRB 070721B, Swift-BAT refined analysis', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6642', 'gcn', 'GRB 070721A', '2007-07-21T14:07:31.000Z', '{"measurements":{"dec":-28.53,"distance":null,"duration":3.4,"energy":null,"fluence":7.1e-8,"magnitude":null,"other_measurements":{"fluence_band_15_150_kev":"7.1 +- 1.8 x 10^-8 erg/cm2","fluence_ratio_25_50_kev_to_50_100_kev":1.38,"partial_coding":72,"peak_photon_flux":0.7,"peak_photon_flux_band_15_150_kev":"0.7 +- 0.1 ph/cm2/sec","power_law_index":2.46},"ra":3.144,"redshift":null,"tables":[]},"authors":{"affiliations":["GSFC/ORAU","GSFC","GSFC/UMBC","LANL","GSFC/USRA"],"authors":["T. Sakamoto","L. Barbier","S. D. Barthelmy","J. Cummings","E. Fenimore","N. Gehrels","H. Krimm","C. Markwardt","D. Palmer","A. Parsons","G. Sato","M. Stamatikos","J. Tueller","T. Ukwatta","H. Ziaeepour"],"institutions":["NASA/GSFC","ORAU","LANL","GSFC/USRA"],"universities":["UMBC","UMD","ISAS","UCL-MSSL"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-07-21T14:07:31.000Z","event":"GRB 070721A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6642\nSUBJECT: GRB 070721A, Swift-BAT refined analysis\nDATE: 07/07/21 14:07:31 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nT. Sakamoto (GSFC/ORAU), L. Barbier (GSFC), S. D. Barthelmy (GSFC),\nJ. Cummings (GSFC/UMBC), E. Fenimore (LANL), N. Gehrels (GSFC),\nH. Krimm (GSFC/USRA), C. Markwardt (GSFC/UMD), D. Palmer (LANL),\nA. Parsons (GSFC), G. Sato (GSFC/ISAS), M. Stamatikos (GSFC/ORAU),\nJ. Tueller (GSFC), T. Ukwatta (GWU), H. Ziaeepour (UCL-MSSL)\n(i.e. the Swift-BAT team):\n \nUsing the data set from T-239 to T+352 sec from the recent telemetry downlink,\nwe report further analysis of BAT GRB 070721A (trigger #285653)\n(Ziaeepour, et al., GCN Circ. 6639).  The BAT ground-calculated position is\nRA, Dec = 3.144, -28.530 deg which is \n   RA(J2000)  =   0h 12m 34.5s \n   Dec(J2000) = -28d 31'' 47\" \nwith an uncertainty of 2.3 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 72%.\n \nThe mask-weighted lightcurve has a single peak starting at ~T-4 sec,\npeaking at ~T+1 sec, and ending at ~T+8 sec.  T90 (15-350 keV) is\n3.4 +- 0.2 sec (estimated error including systematics).\n \nThe time-averaged spectrum from T-0.1 to T+3.7 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n2.46 +- 0.41.  The fluence in the 15-150 keV band is 7.1 +- 1.8 x 10^-8 erg/cm2.\nThe 1-sec peak photon flux measured from T+0.12 sec in the 15-150 keV band\nis 0.7 +- 0.1 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel. \n \nWe note that the fluence ratio in a simple power-law fit between the\n25-50 keV band and the 50-100 keV band is 1.38.  This fluence ratio is larger\nthan 1.32 which can be achieved in the Band function of alpha=-1.0, beta=-2.5,\nand Epeak=30 keV.  Thus, preliminary analysis shows that Epeak of the burst\nis very likely around or below 30 keV.  Therefore the burst can be classified\nas an X-ray flash."}', 'Astronomical alert: GRB 070721A, Swift-BAT refined analysis', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6641', 'gcn', 'GRB070721B', '2007-07-21T12:05:59.000Z', '{"measurements":{"dec":-2.1946,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":15.9,"other_measurements":{"distance_from_bat_error_circle":9.7,"error_radius":0.9,"finding_chart_exposure_time":100,"galactic_reddening":0.02,"magnitude_error":0.5,"time_after_bat_trigger":50},"ra":33.1373,"redshift":null,"tables":[]},"authors":{"affiliations":["MSSL/Swift, University College London"],"authors":["Patricia Schady"],"institutions":["MSSL (Mullard Space Science Laboratory)"],"universities":["University College London (UCL)"]},"telescopes":{"facilities":[],"instruments":["Swift/UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"ps@mssl.ucl.ac.uk","institution":"MSSL/Swift","name":"Patricia Schady"},"coordinates":{},"detectionTime":"2007-07-21T12:05:59.000Z","event":"GRB070721B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6641\nSUBJECT: GRB070721B: A bright UVOT candidate\nDATE: 07/07/21 12:05:59 GMT\nFROM: Patricia Schady at MSSL/Swift  <ps@mssl.ucl.ac.uk>\n\nP. Schady (MSSL-UCL) reports on behalf of the Swift team\n\nThe Swift/UVOT observed the field of GRB 070721B and took a finding chart \nexposure of 100 seconds with the White (160-650 nm) filter starting ~50 \nseconds after the BAT trigger. A candidate afterglow was found on-board in \nthe rapidly available 2.7''x2.7'' sub-image, consistent with the XRT \nposition (Ziaeepour et al., GCN 6640) at\n   RA(J2000)  =  02:12:32.95 =  33.1373 degrees\n   DEC(J2000) = -02:11:40.6  =  -2.1946 degrees\nwith a 1-sigma error radius of about 0.9 arc sec. This position is 9.7 \narcsec. from the center of the BAT error circle. The estimated magnitude \nis 15.9 with a 1-sigma error of about 0.5 mag. No correction has been made \nfor the estimated Galactic reddenning of E(B-V)=0.02 mag (Schlegel, \nFinkbeiner & Davic, 1998)"}', 'The Swift satellite detected a gamma-ray burst (GRB 070721B) and observed a candidate afterglow using the UVOT instrument. The afterglow was found to be located approximately 9.7 arcsec from the center of the BAT error circle with an estimated magnitude of 15.9 and a 1-sigma error of 0.5 mag. No correction for Galactic reddening has been made.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6640', 'gcn', 'GRB 070721B', '2007-07-21T11:16:00.000Z', '{"measurements":{"dec":-2.184,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"flux_unit":"cgs","offset_from_bat_position":45.7,"offset_unit":"arcseconds","source_flux":1.296e-9,"typical_uncertainty":6,"uncertainty_unit":"arcseconds","xrt_dec":-2.19602,"xrt_ra":33.13506},"ra":33.131,"redshift":null,"tables":[]},"authors":{"affiliations":["MSSL-UCL (University College London - Mullard Space Science Laboratory)","GSFC (NASA Goddard Space Flight Center)","U Leicester (University of Leicester)","PSU (Penn State University)"],"authors":["H. Ziaeepour","S. D. Barthelmy","A. P. Beardmore","D. N. Burrows","P. A. Evans","K. L. Page","P. Schady"],"institutions":["MSSL-UCL","GSFC"],"universities":["UCL-MSSL","U Leicester","PSU"]},"telescopes":{"facilities":[],"instruments":["XRT (X-ray Telescope)"],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{"dec":13.835},"detectionTime":"2007-07-21T11:16:00.000Z","event":"GRB 070721B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6640\nSUBJECT: GRB 070721B: Swift detection of a burst\nDATE: 07/07/21 11:16:00 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nH. Ziaeepour (UCL-MSSL), S. D. Barthelmy (GSFC),\nA. P. Beardmore (U Leicester), D. N. Burrows (PSU),\nP. A. Evans (U Leicester), K. L. Page (U Leicester) and\nP. Schady (MSSL-UCL) report on behalf of the Swift Team:\n\nAt 10:33:48 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 070721B (trigger=285654).  Swift slewed immediately to the burst. \nThe BAT on-board calculated location is \nRA, Dec 33.131, -2.184 (J2000) with an uncertainty of 3 arcmin\n(radius, 90% containment, including systematic uncertainty). \nLike the previous trigger, there continues be a problem with the messages,\nso we are not able to say anything about the lightcurve at this time. \n\nThe XRT found a bright, uncatalogued source at \nRA(J2000) = 33.13506 \nDEC(J2000) = -2.19602\nwhich is  45.7 arcseconds from the BAT position. We do not have\nan  error estimate, but the typical uncertainty for on-board centroids\nis 6 arcseconds. The source flux was about 1.296e-09 cgs. While we don''t\nhave the usual GCN notices for this trigger, the realtime\ntelemetry from the spacecraft indicates that the source is fading. \n\nAt the moment no UVOT data are available. We are waiting for the next\nMalindi pass to download more data. \n\nBurst Advocate for this burst is H. Ziaeepour (hz AT mssl.ucl.ac.uk). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift Burst Alert Telescope (BAT) detected a gamma-ray burst (GRB 070721B) at 10:33:48 UT with a calculated location of RA 33.131, Dec -2.184 (J2000) and an uncertainty of 3 arcmin. The X-ray Telescope (XRT) identified a bright, uncatalogued source 45.7 arcseconds from the BAT position with a source flux of about 1.296e-09 cgs. The burst is fading, but UVOT data are not yet available.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-664', 'gcn', 'GRB000424', '2000-05-03T23:31:21.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"V":14},"other_measurements":{"external_zero_point_error":"3%","internal_errors":"less than 100mas"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["USRA/USNO"],"authors":["A. Henden"],"institutions":["USNO/USRA"],"universities":["USRA","USNO"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["USNOFS 1.0-m telescope"]},"urls":["ftp://ftp.nofs.navy.mil/pub/outgoing/aah/grb/grb000424.dat"],"basic_data":{"author":{"email":"aah@nofs.navy.mil","institution":"USNO/USRA","name":"Arne A. Henden"},"coordinates":{},"detectionTime":"2000-05-03T23:31:21.000Z","event":"GRB000424","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 664\nSUBJECT: GRB000424, UBVRI field photometry\nDATE: 00/05/03 23:31:21 GMT\nFROM: Arne A. Henden at USNO/USRA  <aah@nofs.navy.mil>\n\nA. Henden (USRA/USNO) reports on behalf of the USNO GRB team:\n\nWe have acquired preliminary UBVRcIc all-sky photometry for\nan 11x11 arcmin field that covers the\nerror box for GRB000424 with the USNOFS 1.0-m telescope on one\nmarginally photometric night.  Stars brighter than\nV=14 are saturated and should be used with care.\nWe have placed the photometric data on our anonymous ftp site:\nftp://ftp.nofs.navy.mil/pub/outgoing/aah/grb/grb000424.dat\nThe current photometry has a potential external zero-point\nerror of about three percent.  The astrometry in this file\nis based on linear plate solutions with respect to USNO-A2.0.\nThe internal errors are less than 100mas.\n  Further calibration of this field will be performed if\nan optical afterglow is identified."}', 'The USNO GRB team reports preliminary UBVRcIc photometry for GRB000424 using the USNOFS 1.0-m telescope. The data, which covers an 11x11 arcmin field, has a potential external zero-point error of about three percent and internal errors less than 100mas. The photometry data is available on their FTP site.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6639', 'gcn', 'GRB 070721', '2007-07-21T10:59:02.000Z', '{"measurements":{"dec":-28.546,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"2mass_distance_from_xrt":"2.5 arcseconds","bat_uncertainty":"3 arcmin","typical_xrt_uncertainty":"6 arcseconds","xrt_dec":-28.54928,"xrt_distance_from_bat":"40 arcseconds","xrt_ra":3.16355,"xrt_source_flux":"3.25e-10 cgs"},"ra":3.176,"redshift":null,"tables":[]},"authors":{"affiliations":["MSSL, UCL","GSFC","U Leicester","PSU","INAF-IASFPA"],"authors":["H. Ziaeepour","S. D. Barthelmy","A. P. Beardmore","D. N. Burrows","P. A. Evans","K. L. Page","E. Troja"],"institutions":["U Leicester","MSSL","INAF-IASFPA"],"universities":["UCL","PSU"]},"telescopes":{"facilities":["Malindi"],"instruments":[],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)","XRT"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-07-21T10:59:02.000Z","event":"GRB 070721","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6639\nSUBJECT: GRB 070721: Swift detection of a possible burst\nDATE: 07/07/21 10:59:02 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nH. Ziaeepour (UCL-MSSL), S. D. Barthelmy (GSFC),\nA. P. Beardmore (U Leicester), D. N. Burrows (PSU),\nP. A. Evans (U Leicester), K. L. Page (U Leicester) and\nE. Troja (INAF-IASFPA) report on behalf of the Swift Team:\n\nAt 10:00:56 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 070721 (trigger=285653).  Swift slewed immediately to the burst. \nThe BAT on-board calculated location is \nRA, Dec 3.176, -28.546 (J2000) with an uncertainty of 3 arcmin\n(radius, 90% containment, including systematic uncertainty). \nWe have very little further information at this time (lightcurve, etc)\nbecause there appears to be a problem with the messages. \n\nThe spacecraft slewed promptly and the XRT found a source\nat location \nRA(J2000) = 3.16355 degrees, \nDec(J2000) = -28.54928 degrees, \nwhich is 40 arcseconds from the BAT position. We do not have\nan  error estimate, but the typical uncertainty for on-board centroids\nis 6 arcseconds. The source flux was about 3.25e-10 cgs. At this point\nwe do not have enough data to be able to  tell whether this source is\nfading. We note that there is a bright 2MASS object at this position: \n2MASS 00123943-2832566 (2.5 arcseconds from the XRT position). \nWe are waiting for processing of  the downlinked Malindi data\nfor more details. \n\nAt this moment no UVOT data are available. We are waiting for the \nnext Malindi pass to download more data. \n\nWe note that while writing this Circular, Swift slewed to the next\ntrigger following this one. This is unusual and raises the\npossibility that this burst is not real. We will not be certain until\nthe Malindi data can be analyzed. \n\nBurst Advocate for this burst is H. Ziaeepour (hz AT mssl.ucl.ac.uk). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)\n\n[GCN OPS NOTE(24aug07): Per author''s request, the trigger time was corrected\nfrom 10:01:08 to 10:00:56. Acknowledgements to F. Marshall.]"}', 'The Swift Burst Alert Telescope (BAT) detected a possible gamma-ray burst (GRB 070721) at 10:00:56 UT with a calculated location of RA 3.176, Dec -28.546 (J2000) and an uncertainty of 3 arcmin. The XRT found a source at the same location with a flux of about 3.25e-10 cgs and a distance of 40 arcseconds from the BAT position. A bright 2MASS object is also present at this position. No UVOT data are available yet, and the Malindi data is being processed for more details. The Swift team notes that the spacecraft slewed to the next trigger following this one, raising the possibility that this burst is not real.', 0.7, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6638', 'gcn', 'GRB 070714B', '2007-07-19T13:55:47.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"2 sec","energy":"15-2000 keV","fluence":"3.7 (-0.6/+1.3) x 10^-6 erg/cm2","magnitude":null,"other_measurements":{"Epeak":"1120 (-380/+780) keV","alpha":"-0.86 +- 0.10"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":[],"authors":[],"institutions":[],"universities":[]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"takanori@milkyway.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Takanori Sakamoto"},"coordinates":{},"detectionTime":"2007-07-19T13:55:47.000Z","event":"GRB 070714B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6638\nSUBJECT: GRB 070714B: Swift/BAT and Suzaku/WAM joint spectral analysis\nDATE: 07/07/19 13:55:47 GMT\nFROM: Takanori Sakamoto at NASA/GSFC  <takanori@milkyway.gsfc.nasa.gov>\n\nM. Ohno, T. Uehara, T. Takahashi, Y. Fukazawa, C. Kira (Hiroshima U.),\nK. Yamaoka, Y. E. Nakagawa, S. Sugita (Aoyama Gakuin U.),\nY. Terada, T. Tamagawa (RIKEN), K. Morigami, N. Kodaka, K. Onda,\nM. Tashiro, M. Suzuki, Y. Urata, A. Endo (Saitama U.), T. Enoto,\nR. Miyawaki, K. Nakawaza, K. Makishima (Univ. of Tokyo), E. Sonoda,\nM.Yamauchi, S. Maeno, H. Tanaka, R. Hara (Univ. of Miyazaki),\nM. Kokubun, M. Suzuki, T. Takahashi (ISAS/JAXA), S. Hong (Nihon U.),\non behalf of the Suzaku-WAM team, \n\nT. Sakamoto (GSFC/ORAU), L. Barbier (GSFC), S. D. Barthelmy (GSFC), \nJ. Cummings (GSFC/UMBC), E. Fenimore (LANL), N. Gehrels (GSFC), \nH. Krimm (GSFC/USRA), C. Markwardt (GSFC/UMD), D. Palmer (LANL), \nA. Parsons (GSFC), G. Sato (GSFC/ISAS), M. Stamatikos (GSFC/ORAU), \nJ. Tueller (GSFC), T. Ukwatta (GWU)\non behalf of the Swift-BAT team, \n\nreport:\n\nWe performed the Swift/BAT, and Suzaku/WAM joint fit spectral \nanalysis of GRB 070714B (Swift-BAT trigger #284856; Racusin, et al., \nGCN Circ. 6620).  The time interval of the spectral data for each \ninstrument is chosen from T0(WAM) to T0(WAM)+2 sec where \nT0(WAM) is the trigger time of WAM at 04:59:29.247 UTC.  \nThe energy ranges which we used in the joint spectral analysis \nare 14-150 keV and 100-2000 keV for Swift/BAT and Suzaku/WAM \nrespectively.  The spectral data of two instruments are fit \nwith the spectral model multiplied by the constant factor to \ntake into account the systematic uncertainties in the response \nmatrices of each instrument.  \n\nThe spectrum is well fit with a power-law with exponential cutoff \nmodel (dN/dE ~ E^{alpha} * exp(-(2+alpha)*E/Epeak)).  The constant \nfactors of each instrument agree within 10%.  No systematic residual \nfrom the best fit model is seen in the spectral data of each instrument.  \nThe best fit spectral parameters are: alpha = -0.86 +- 0.10 and \nEpeak = 1120 (-380/+780) keV (chi2/dof = 64/69).  The energy fluence \nin the 15-2000 keV band calculated by a power-law with exponential \ncutoff model for this two-second interval is 3.7 (-0.6/+1.3) x 10^-6 erg/cm2 \n(assuming the constant factor of the BAT is fixed to 1). \n\nAll the quoted errors are at the 90% confidence level."}', 'Astronomers performed a joint spectral analysis of GRB 070714B using data from Swift/BAT and Suzaku/WAM. The gamma-ray burst, which occurred on July 7, 19, was found to be well-fit by a power-law with exponential cutoff model. The best-fit parameters were determined to be alpha = -0.86 ± 0.10 and Epeak = 1120 (-380/+780) keV. The energy fluence in the 15-2000 keV band was calculated to be 3.7 (-0.6/+1.3) x 10^-6 erg/cm2.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6637', 'gcn', 'GRB 070714B', '2007-07-19T13:37:25.000Z', '{"measurements":{"dec":null,"distance":null,"duration":2,"energy":{"lower_bound":50,"upper_bound":5000},"fluence":0.0000023,"magnitude":null,"other_measurements":{"flux_energy_range":"100 - 1000 keV","peak_duration":0.45,"peak_flux":2.8,"photon_index":1.3},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":[],"authors":[],"institutions":[],"universities":[]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"tashiro@phy.saitama-u.ac.jp","institution":"Saitama U/Swift","name":"Makoto Tashiro"},"coordinates":{},"detectionTime":"2007-07-19T13:37:25.000Z","event":"GRB 070714B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6637\nSUBJECT: GRB 070714B : Suzaku WAM observation of the prompt emission\nDATE: 07/07/19 13:37:25 GMT\nFROM: Makoto Tashiro at Saitama U/Swift  <tashiro@phy.saitama-u.ac.jp>\n\nN. Kodaka, M. Tashiro, Y. Urata, A. Endo, K. Onda, M. Suzuki,\nK. Morigami (Saitama U.),Y. Terada, T. Tamagawa (RIKEN), M. Ohno,\nT. Uehara, T. Takahashi, Y. Fukazawa, C. Kira (Hiroshima U.),\nK. Yamaoka, Y. E. Nakagawa, S. Sugita (Aoyama Gakuin U.), T. Enoto,\nR. Miyawaki, K. Nakawaza, K. Makishima (Univ. of Tokyo), E. Sonoda,\nM.Yamauchi, S. Maeno, H. Tanaka, R. Hara (Univ. of Miyazaki),\nM. Kokubun, M. Suzuki, T. Takahashi (ISAS/JAXA), S. Hong (Nihon U.),\non behalf of the Suzaku WAM team, report:\n\nThe short GRB 070714B (Swift/BAT trigger #284856; Racusin et al.,\nGCN 6620; Barbier et al., GCN 6623) triggered the Suzaku Wide-band \nAll-sky Monitor (WAM) which covers an energy range of 50 keV - 5 MeV\nat 04:59:29.247 UT (=T0).\nThe observed light curve with 1/64 sec resolution shows a multi-peaked\nstructure with a sharp strong peak at ~T0+0.45 sec. The duration (T90) \nwas about 2.0 sec.\nThe fluence in 100 - 1000 keV was (2.3 � 0.2)x10^-6 erg/cm^2, while the\n1-s peak flux measured from T0+0 to T0+1 sec was\n2.8 � 0.3 photons/cm^2/s in the same energy range.\n\nPreliminary result shows that the time-averaged spectrum from T0+0 to\nT0+2 sec is well fitted by a single power-law with a photon index\nof 1.3 � 0.2 (chi^2 / d.o.f. = 22/20).\n\nAll the quoted errors are at statistical 90% confidence level,\nin which the systematic uncertainties are not included.\n\nThe light curve data for this burst is available at:\nhttp://www.astro.isas.jaxa.jp/suzaku/HXD-WAM/WAM-GRB/grb/trig/grb_table.html"}', 'The short gamma-ray burst GRB 070714B, detected by Swift/BAT, triggered the Suzaku WAM monitor and was observed between 50 keV and 5 MeV. The light curve showed a multi-peaked structure with a strong peak at ~0.45 seconds after the trigger, and the duration was approximately 2 seconds. The fluence in the 100-1000 keV range was (2.3 ± 0.2)x10^-6 erg/cm^2, and the 1-second peak flux was 2.8 ± 0.3 photons/cm^2/s. Preliminary analysis suggests a single power-law fit with a photon index of 1.3 ± 0.2.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6636', 'gcn', 'GRB 070714A', '2007-07-17T13:29:12.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"trigger_number":284850,"trigger_time":"03:20:30.618 UT"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["NASA/GSFC"],"authors":["S.D. Barthelmy","D. Grupe","M. Chester","F. Marshall"],"institutions":["NASA/GSFC"],"universities":[]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://lheamail.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-07-17T13:29:12.000Z","event":"GRB 070714A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6636\nSUBJECT: GRB 070714A: Swift-BAT T_zero\nDATE: 07/07/17 13:29:12 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nS.D. Barthelmy (GSFC)\non behalf of the Swift-BAT team:\n\nIt has been noted by several people (D. Grupe, M. Chester, and F. Marshall)\nthat the T_zero trigger time for GRB 070714A (Grupe, et al., 6619;\nBarthelmy et al., 6622) is missing from the standard set of communications\non this burst.  Normally T_zero is published in the Notices and the\n\"first Swift Circular\" on the burst.  But because all the TDRSS messages\nwere lost due to a TDRSS outage, we dropped the ball on this in the later\ncircular.\n\nThe trigger time for GRB 070714A (trigger 284850) is 03:20:30.618 UT."}', 'Astronomical alert: GRB 070714A: Swift-BAT T_zero', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6635', 'gcn', 'GRB070714B', '2007-07-17T12:34:16.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"J":{"upper_limit":20.7},"K":21},"other_measurements":{"airmass":{"unit":null,"value":"higher than 2"}},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Brera Astronomical Observatory","CIBO collaboration"],"authors":["S. Covino","S. Piranomonte","P. D''Avanzo","L.A. Antonelli","F. de Luise","M. Pedani","N. Pinilla Alfonso"],"institutions":["CIBO collaboration"],"universities":["University of Milano-Bicocca","Brera Astronomical Observatory"]},"telescopes":{"facilities":["TNG"],"instruments":["NICS"],"observatories":["Brera Astronomical Observatory"],"telescopes":["TNG"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular.msfc?id=6630","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular.msfc?id=6620","https://gcn.gsfc.nasa.gov/gcn3/gcn3_search.msfc","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular.msfc?id=6623","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular.msfc?id=6621"],"basic_data":{"author":{"email":"stefano.covino@poste.it","institution":"Brera Astronomical Observatory","name":"Stefano Covino"},"coordinates":{},"detectionTime":"2007-07-17T12:34:16.000Z","event":"GRB070714B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6635\nSUBJECT: GRB070714B: TNG NIR observations\nDATE: 07/07/17 12:34:16 GMT\nFROM: Stefano Covino at Brera Astronomical Observatory  <stefano.covino@poste.it>\n\nS. Covino, S. Piranomonte, P. D''Avanzo, L.A. Antonelli, F. de Luise,  \nM. Pedani, N. Pinilla Alfonso report, on behalf of the CIBO  \ncollaboration:\n\nWe observed the field of the short/hard GRB070714B (Racusin et al.,  \nGCN 6620; Barbier et al., GCN 6623) on July 15 2007 at about 5 UT  \nwith the TNG equipped with NICS in the J and K bands. The  \nobservations were performed at high airmass (higher than 2).\n\nWe only marginally detected the afterglow identified by Melandri et  \nal. (GCN 6621) and Levan et al. (GCN 6630) in the K band at  \napproximately K~21. In the J band we could only derive a mild 3sigma  \nupper limit, J > 20.7.\n\nThis message may be cited."}', 'A team of astronomers led by Stefano Covino at Brera Astronomical Observatory reported observing the afterglow of GRB070714B using the TNG equipped with NICS in the J and K bands on July 15, 2007. They detected a faint afterglow in the K band with a magnitude of approximately K~21, but only set a 3σ upper limit of J > 20.7 in the J band. The observations were conducted at high airmass.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6634', 'gcn', 'GRB 070704', '2007-07-17T10:08:01.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"peak_flux":{"band":"100-1000 keV","unit":"photons/cm^2/s","value":"1.2 +/- 0.1"}},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Hiroshima U.","Aoyama Gakuin U.","Saitama U.","ISAS/JAXA","RIKEN"],"authors":["Masanori Ohno","C. Kira","M. Ohno","T. Uehara","T. Takahashi","Y. Fukazawa","K. Yamaoka","Y. E. Nakagawa","S. Sugita","M. Tashiro","Y. Urata","A. Endo","K. Onda","M. Suzuki","N. Kodaka","K. Morigami","T. Enoto","R. Miyawaki","K. Nakawaza","K. Makishima","S. Hong","M. Kokubun","M. Suzuki","T. Takahashi","E. Sonoda","M. Yamauchi","S. Maeno","H. Tanaka","R. Hara","T. Tamagawa","Y. Terada"],"institutions":["HEPL, Hiroshima-u.ac.jp","Aoyama Gakuin U.","Saitama U.","ISAS/JAXA"],"universities":["Hiroshima U.","Aoyama Gakuin U.","Saitama U.","Univ. of Tokyo","Nihon U.","Univ. of Miyazaki"]},"telescopes":{"facilities":[],"instruments":["Suzaku WAM"],"observatories":[],"telescopes":[]},"urls":["http://hepl.hiroshima-u.ac.jp"],"basic_data":{"author":{"email":"ohno@hirax7.hepl.hiroshima-u.ac.jp","institution":"Hiroshima U","name":"Masanori Ohno"},"coordinates":{},"detectionTime":"2007-07-17T10:08:01.000Z","event":"GRB 070704","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6634\nSUBJECT: Erratum : Suzaku WAM observation of GRB 070704\nDATE: 07/07/17 10:08:01 GMT\nFROM: Masanori Ohno at Hiroshima U  <ohno@hirax7.hepl.hiroshima-u.ac.jp>\n\nC. Kira, M. Ohno, T. Uehara, T. Takahashi, Y. Fukazawa (Hiroshima U.),\nK. Yamaoka, Y. E. Nakagawa, S. Sugita (Aoyama Gakuin U.),\nM. Tashiro, Y. Urata, A. Endo, K. Onda, M. Suzuki, N. Kodaka, K. Morigami (Saitama U.),\nT. Enoto, R. Miyawaki, K. Nakawaza, K. Makishima (Univ. of Tokyo),\nS. Hong (Nihon U.),\nM. Kokubun, M. Suzuki, T. Takahashi (ISAS/JAXA),\nE. Sonoda, M. Yamauchi, S. Maeno, H. Tanaka, R. Hara (Univ. of Miyazaki),\nT. Tamagawa, Y. Terada (RIKEN), \nand Suzaku WAM team report:\n\nThe Suzaku WAM preliminary result of GRB 070704 (Kira et al. GCN Circ. 6616) \ncontained a wrong value in a 1-s peak flux in the 100-1000 keV band.\nThe correct value is 1.2 +/- 0.1 photons/cm^2/s. \n\nWe apologize for this mistake."}', 'An erratum was issued for the Suzaku WAM observation of GRB 070704, correcting a mistake in the reported 1-second peak flux in the 100-1000 keV band. The correct value is 1.2 +/- 0.1 photons/cm^2/s.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6633', 'gcn', 'GRB 070714A', '2007-07-16T20:38:18.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":[20.19,20.63,19.69,19.55,19.71,19.03,18.96,18.49],"other_measurements":{},"ra":null,"redshift":null,"tables":[{"Exp":98.2,"Filter":"White FC","Magnitude":20.19,"Tstart":61,"Tstop":161},{"Exp":235,"Filter":"White","Magnitude":20.63,"Tstart":61,"Tstop":1641},{"Exp":855,"Filter":"v","Magnitude":19.69,"Tstart":44,"Tstop":1690},{"Exp":138,"Filter":"b","Magnitude":19.55,"Tstart":647,"Tstop":5955},{"Exp":274,"Filter":"u","Magnitude":19.71,"Tstart":622,"Tstop":5868},{"Exp":274,"Filter":"uvw1","Magnitude":19.03,"Tstart":598,"Tstop":5664},{"Exp":197,"Filter":"uvm2","Magnitude":18.96,"Tstart":5258,"Tstop":5458},{"Exp":77.8,"Filter":"uvw2","Magnitude":18.49,"Tstart":677,"Tstop":1666}]},"authors":{"affiliations":["Penn State University"],"authors":["M.M. Chester","D. Grupe"],"institutions":["Penn State"],"universities":["Penn State University"]},"telescopes":{"facilities":[],"instruments":["Swift/UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.jsp?id=6633"],"basic_data":{"author":{"email":"chester@astro.psu.edu","institution":"PSU","name":"Margaret Chester"},"coordinates":{},"detectionTime":"2007-07-16T20:38:18.000Z","event":"GRB 070714A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6633\nSUBJECT: GRB 070714A: Swift/UVOT Upper limits\nDATE: 07/07/16 20:38:18 GMT\nFROM: Margaret Chester at PSU  <chester@astro.psu.edu>\n\nM.M. Chester (PSU) and D. Grupe (PSU) report on the behalf of the\nSwift UVOT team:\n\nThe Swift/UVOT observed the field of GRB070714A (trigger=284850)\nstarting 2007-195-03:21:15, 44 s after the BAT trigger (Grupe et al.\n2007, GCN Circ. 6619). We do not find any new source in any of the UVOT\nobservations inside the refined XRT error circle (Grupe 2007, GCN Circ.\n6628).\n\nThe 3-sigma upper limits for detecting a source inside the XRT error\ncircle in the first finding chart (FC) exposure and the co-added frames\n(including the finding chart) are:\n\nFilter   Tstart   Tstop    Exp     Magnitude\n            (s)     (s)     (s)    (3-sigma UL)\nWhite FC    61     161      98.2     20.19\nWhite       61    1641     235       20.63\nv           44    1690     855       19.69\nb          647    5955     138       19.55\nu          622    5868     274       19.71\nuvw1       598    5664     274       19.03\nuvm2      5258    5458     197       18.96\nuvw2       677    1666      77.8     18.49\n\nThe values quoted above are not corrected for the expected Galactic\nextinction corresponding to a reddening of E_{B-V} = 0.186 mag in the\ndirection of the burst (Schlegel et al. 1998)."}', 'The Swift/UVOT team reports no detection of a new source inside the XRT error circle of GRB070714A, providing 3-sigma upper limits for magnitudes in various filters. The limits range from 18.49 in uvw2 to 20.71 in u.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6632', 'gcn', 'GRB 070714B', '2007-07-16T19:59:10.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"Galactic extinction":{"E_{B-V}":"0.14 mag"}},"ra":null,"redshift":null,"tables":[{"Exp(s)":98.2,"Filter":"White","Mag (3-sigma upper limit)":"> 20.4","T_end":170,"T_start":70},{"Exp(s)":393.4,"Filter":"v","Mag (3-sigma upper limit)":"> 19.6","T_end":577,"T_start":177},{"Exp(s)":58.1,"Filter":"b","Mag (3-sigma upper limit)":"> 19.2","T_end":1637,"T_start":657},{"Exp(s)":89.2,"Filter":"u","Mag (3-sigma upper limit)":"> 19.2","T_end":1766,"T_start":632},{"Exp(s)":97.3,"Filter":"uvw1","Mag (3-sigma upper limit)":"> 19.1","T_end":1750,"T_start":607},{"Exp(s)":77.8,"Filter":"uvw2","Mag (3-sigma upper limit)":"> 19.2","T_end":1676,"T_start":687}]},"authors":{"affiliations":["NASA/GSFC","PSU"],"authors":["W. Landsman","J. Racusin"],"institutions":["GSFC/SSAI","PSU"],"universities":["NASA/GSFC","PSU"]},"telescopes":{"facilities":[],"instruments":["Swift/UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"landsman@milkyway.gsfc.nasa.gov","institution":"GSFC/SSAI","name":"Wayne Landsman"},"coordinates":{},"detectionTime":"2007-07-16T19:59:10.000Z","event":"GRB 070714B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6632\nSUBJECT: GRB 070714B: Swift/UVOT Upper Limits\nDATE: 07/07/16 19:59:10 GMT\nFROM: Wayne Landsman at GSFC/SSAI  <landsman@milkyway.gsfc.nasa.gov>\n\nW. Landsman (NASA/GSFC) and J. Racusin (PSU) report on behalf of the \nSwift/UVOT team:\n\nThe Swift/UVOT observed the field of GRB 070714B starting 70 s after the \nBAT trigger (Racusin et al. GCN Circ.6620).   We do not find any source, \nin any of the UVOT observations, inside the refined XRT error circle \n(Racusin et al., GCN Circ. 6627), or at the location of the Liverpool \nsource (Melandri et al., GCN Circ. 6621).\n\nThe 3-sigma upper limits for detecting a source inside the refined XRT \nerror circle are:\n\nFilter    T_start     T_end    Exp(s)    Mag (3-sigma upper limit)\n\nWhite      70         170        98.2      > 20.4\nv         177         577       393.4      > 19.6\nb         657        1637        58.1      > 19.2\nu         632        1766        89.2      > 19.2\nuvw1      607        1750        97.3      > 19.1\nuvw2      687        1676        77.8      > 19.2\n\nThe values quoted above are not corrected for the expected Galactic \nextinction\ncorresponding to a reddening of E_{B-V} = 0.14 mag in the direction of the\nburst (Schlegel et al. 1998)."}', 'The Swift/UVOT team reported no detection of a source inside the refined XRT error circle or at the location of the Liverpool source for GRB 070714B. They provided 3-sigma upper limits for detecting a source in various UVOT filters, which have not been corrected for the expected Galactic extinction.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6631', 'gcn', 'GRB 070714B', '2007-07-16T18:48:06.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"spectral_lag_1":{"energy_range":"100-350 to 25-50 keV","uncertainty":4,"uncertainty_unit":"ms","unit":"ms","value":9},"spectral_lag_2":{"energy_range":"50-100 to 15-25 keV","uncertainty":7,"uncertainty_unit":"ms","unit":"ms","value":14}},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Stanford U","NASA/GSFC","GWU"],"authors":["J. Norris","S.D. Barthelmy","T. Ukwatta"],"institutions":["GSFC","GWU"],"universities":["Stanford U"]},"telescopes":{"facilities":["Swift-BAT"],"instruments":[],"observatories":[],"telescopes":["Swift-BAT"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-07-16T18:48:06.000Z","event":"GRB 070714B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6631\nSUBJECT: GRB 070714B: Swift-BAT spectral lag for the SHB\nDATE: 07/07/16 18:48:06 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nJ. Norris (Stanford U), S.D. Barthelmy (GSFC), T. Ukwatta (GWU)\non behalf of the Swift-BAT team:\n \nUsing the event-by-event data from Swift-BAT, the spectral lag\nfor GRB 070714B (Racusin, et al., 6620; Barbier, et al., 6623) is:\n     9 ms +- 4 ms   (100-350 to 25-50 keV)\n    14 ms +- 7 ms   ( 50-100 to 15-25 KeV)\nusing 4-msec binning (for the 2.9-sec interval covering the initial spike).\nThis is consistent with \"zero lag\" for short hard bursts."}', 'Astronomers using Swift-BAT data report the spectral lag for GRB 070714B, a short gamma-ray burst, is consistent with ''zero lag'' for short hard bursts, with measured values of 9 ms +- 4 ms (100-350 to 25-50 keV) and 14 ms +- 7 ms (50-100 to 15-25 KeV).', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6630', 'gcn', 'GRB 070714B', '2007-07-15T21:42:36.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":23.5,"other_measurements":{"observation_duration":"2700s","observation_start_time":"July 15 04:17 UT"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["U.of Leicester","Warwick","Oxford","MPI Heidelberg","STScI"],"authors":["A.J. Levan","N.R. Tanvir","D Bonfield","Alejo Martinez-Sansigre","J. Graham","A. Fruchter"],"institutions":["GCN","STScI"],"universities":["University of Leicester","University of Warwick","University of Oxford","Max Planck Institute Heidelberg","Space Telescope Science Institute"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["William Herschel Telescope"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"anl@star.le.ac.uk","institution":"U.of Leicester","name":"Andrew Levan"},"coordinates":{},"detectionTime":"2007-07-15T21:42:36.000Z","event":"GRB 070714B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6630\nSUBJECT: GRB 070714B: confirmation of optical afterglow\nDATE: 07/07/15 21:42:36 GMT\nFROM: Andrew Levan at U.of Leicester  <anl@star.le.ac.uk>\n\nA.J. Levan (Warwick), N.R. Tanvir (Leicester), D Bonfield (Oxford), Alejo \nMartinez-Sansigre (MPI Heidelberg), J. Graham, A. Fruchter (STScI) \nreport on behalf of a larger collaboration:\n\nWe imaged the field of GRB 070714B (Racusin et al. GCNC 6620) with the William \nHerschel Telescope (WHT), obtaining at total of 2700s of observations in the \nR-band, beginning on July 15 04:17 UT. At the position of the afterglow \ncandidate of Melandri (GCNC 6621), we detect an object with a magnitude of \nR~23.5 (relative to two USNO stars within the field). The observed fading \nconfirms the association with GRB 070714B. Further observations will be \nnecessary to determine if the current magnitude is significantly contaminated \nby an underlying host galaxy."}', 'Astronomers using the William Herschel Telescope have detected an optical afterglow of GRB 070714B with a magnitude of R~23.5. This confirmation strengthens the association of the afterglow with the gamma-ray burst.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-663', 'gcn', 'GRB 000424', '2000-05-03T23:21:58.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"unit":"R","value":22.8},"other_measurements":{},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Columbia U.","MDM Obs.","Ohio State U."],"authors":["R. Uglesich","N. Mirabal","J. P. Halpern","K. Vanlandingham","J. Noel-Storr","R. M. Wagner","P. Eskridge"],"institutions":["MDM Obs.","GCN"],"universities":["Columbia U.","Ohio State U."]},"telescopes":{"facilities":[],"instruments":[],"observatories":["MDM Obs."],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_message.cfm?id=663"],"basic_data":{"author":{"email":"rru@astro.columbia.edu","institution":"Columbia U./MDM Obs.","name":"Robert Uglesich"},"coordinates":{},"detectionTime":"2000-05-03T23:21:58.000Z","event":"GRB 000424","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 663\nSUBJECT: GRB 000424 Optical Observations\nDATE: 00/05/03 23:21:58 GMT\nFROM: Robert Uglesich at Columbia U./MDM Obs.  <rru@astro.columbia.edu>\n\nR. Uglesich, N. Mirabal, J. P. Halpern, K. Vanlandingham,\nJ. Noel-Storr (Columbia U.), R. M. Wagner, P. Eskridge \n(Ohio State U.) report on behalf of the MDM Observatory \nGRB follow-up team:\n \n\"Further analysis of previously reported observations \n(GCN #651) of the BeppoSAX WFC localization of GRB 000424 \n(Piro, GCN #644) using a sensitive image subtraction technique \nsets a 3-sigma limit of R > 22.8 on April 26.15 UT for any \nfading optical transient in the error circle. Magnitudes \nreported here are referenced to USNO-A2.0 catalog stars nearby.\"\n\nThis message may be cited."}', 'A team of astronomers using the MDM Observatory reported a 3-sigma limit of R > 22.8 for any fading optical transient associated with GRB 000424 on April 26, 2003, based on their analysis of previously reported observations.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6629', 'gcn', 'GRB 070616', '2007-07-15T16:06:28.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":21.6,"other_measurements":{"error_magnitudes":0.02,"fading_magnitudes":[0.064,0.023,0.041,0.001]},"ra":null,"redshift":null,"tables":[{"Ic limit":21.6,"date":"070715.00750","exp. time":"6 x 300 seconds","time (days)":28.32031}]},"authors":{"affiliations":["TLS Tautenburg"],"authors":["D. A. Kann, A. C. Wilson"],"institutions":["TLS Tautenburg"],"universities":["TLS Tautenburg"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Tautenburg 1.34m Schmidt telescope"]},"urls":["http://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.msf?is_gcn=1&is_notif_id=6629"],"basic_data":{"author":{"email":"kann@tls-tautenburg.de","institution":"TLS Tautenburg","name":"Alexander Kann"},"coordinates":{},"detectionTime":"2007-07-15T16:06:28.000Z","event":"GRB 070616","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6629\nSUBJECT: GRB 070616: No Evidence for I Band Afterglow\nDATE: 07/07/15 16:06:28 GMT\nFROM: Alexander Kann at TLS Tautenburg  <kann@tls-tautenburg.de>\n\nD. A. Kann & A. C. Wilson (TLS Tautenburg) report:\n\nWe reobserved the field of GRB 070616 (Starling et al., GCN 6542) with the \nTautenburg 1.34m Schmidt telescope. We obtained 6 x 300 second images in \nthe I band in good observing conditions but with a few passing clouds. \nUsing the same USNOB1.0 star as used by Kann et al. (GCN 6545), we \ndetermine the following limiting magnitude:\n\ndate            time (days)     exp. time       Ic limit\n070715.00750    28.32031        6 x 300         21.6\n\nUsing this star and three other unsaturated, isolated stars, we determine \ndifferential magnitudes between the star that is blended with the \nafterglow (de Pasquale et al., GCN 6557) and these stars at both epochs.\n\nWe find that between the two epochs the star has become fainter by 0.064, \n0.023, 0.041 and 0.001 magnitudes in comparison to the other four stars. \nThe typical errors are 0.02 magnitudes.\n\nWe therefore conclude that we detect no significant fading between epoch \none (star + possibly blended afterglow) and epoch two (star only), placing \na limit of Ic > 20 on the afterglow at the first epoch (Kann et al., GCN \n6545).\n\nThis message may be cited."}', 'The Tautenburg Observatory reported no evidence for an I-band afterglow of GRB 070616 based on observations with the 1.34m Schmidt telescope. The team determined a limiting magnitude of Ic > 21.6 for the afterglow at the first epoch.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6628', 'gcn', 'GRB 070714A', '2007-07-15T04:57:42.000Z', '{"measurements":{"dec":"+30 14 36.2","distance":null,"duration":2.3,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"absorption_column_density":924000000000000000000,"decay_slope":1.02,"exposure_time":2.3,"photon_spectra_index":1.68,"predicted_count_rate_24_hours":0.0015,"predicted_count_rate_48_hours":0.00073,"predicted_flux_24_hours":1.4e-13,"predicted_flux_48_hours":6.8e-14,"uncertainty_decay_slope":0.29,"uncertainty_photon_spectra_index":0.23,"unit_absorption_column_density":"cm^-2","unit_exposure_time":"ks","unit_predicted_count_rate_24_hours":"counts s^-1","unit_predicted_count_rate_48_hours":"counts s^-1","unit_predicted_flux_24_hours":"ergs s^-1 cm^-2","unit_predicted_flux_48_hours":"ergs s^-1 cm^-2"},"ra":"02 51 43.37","redshift":null,"tables":[]},"authors":{"affiliations":["PSU/Swift-XRT"],"authors":["D. Grupe"],"institutions":["Penn State University"],"universities":["Penn State University (PSU)"]},"telescopes":{"facilities":["Swift"],"instruments":["Swift XRT","UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"grupe@astro.psu.edu","institution":"PSU/Swift-XRT","name":"Dirk Grupe"},"coordinates":{"dec":2.8620472222222224},"detectionTime":"2007-07-15T04:57:42.000Z","event":"GRB 070714A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6628\nSUBJECT: GRB 070714A: Swift XRT refined analysis\nDATE: 07/07/15 04:57:42 GMT\nFROM: Dirk Grupe at PSU/Swift-XRT  <grupe@astro.psu.edu>\n\nD.Grupe (PSU) reports on behalf of the Swift/XRT team:\n\n\nI analyzed the first (and only) orbit of X-ray data of GRB 070714A (BAT \ntrigger\n284850; Grupe et al. GCN 6619) with a total exposure time of 2.3 ks.\nThe XRT began observing the field of GRB 070714A at 2007-07-14 03:21:25 UT,\n54.4 seconds after the BAT trigger.\nUsing 799 s of overlapping XRT Photon Counting (PC) mode and UVOT V-band\ndata, we find an astrometrically corrected X-ray position (using the \nXRT-UVOT\nalignment and matching UVOT field sources to the USNO-B1 catalogue): RA, \nDec =\n42.93073, 30.24339 which is equivalent to:\n\nRA (J2000):  02 51 43.37\nDec (J2000): +30 14 36.2\n\nwith an uncertainty of 2.0\"  (90% confidence radius).\n\n\nThe XRT PC mode light curve shows a fading afterglow with a decay slope of\n1.02+\\-0.29. The predicted count rate (flux) 24 hours after the burst is \n1.5e-3\ncounts s-1 (1.4e-13 ergs s-1 cm-2) and 7.3e-4 counts s-1 (6.8e-14 ergs s-1\ncm-2) at 48 hours after the trigger.\n\nThe X-ray spectrum can be fitted by a single absorbed power law with the\nabsorption column density in agreement with the Galactic value (NH=9.24e20\ncm-2; Dickey & Lockman 1990) and a Photon spectra index Gamma = \n1.68+\\-0.23.\n\n\nThis circular is an official product of the Swift XRT team."}', 'The Swift XRT team reported a refined analysis of GRB 070714A X-ray data, obtained 54.4 seconds after the gamma-ray burst trigger. The X-ray position was determined to be RA: 02 51 43.37, Dec: +30 14 36.2, with an uncertainty of 2.0". The XRT PC mode light curve showed a fading afterglow with a decay slope of 1.02±0.29. The predicted X-ray flux 24 hours after the burst was 1.4e-13 ergs s-1 cm-2, and 6.8e-14 ergs s-1 cm-2 at 48 hours. The X-ray spectrum was fitted by a single absorbed power law with an absorption column density in agreement with the Galactic value and a photon spectra index of 1.68±0.23.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6627', 'gcn', 'GRB070714B', '2007-07-15T03:33:26.000Z', '{"measurements":{"dec":"+28d 17'' 52.2\"","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":"03h 51m 22.29s","redshift":null,"tables":[{"slope":"2.49 +/- 0.18"},{"slope":"0.60 +/- 0.29","time":"413s +/- 50s"},{"slope":"1.73 +/- 0.11","time":"1187 +/- 270s"},{"column_density":"13 +/- 3 e20 cm^-2","flux_absorbed":"9.2e-10 erg cm^-2s^-1","flux_unabsorbed":"1.0e-9 erg cm^-2s^-1","galactic_column_density":"6.4e20 cm^-2","pc_flux_absorbed":"3.4e-12 ergs cm^-2 s^-1","pc_flux_unabsorbed":"3.7e-12 ergs cm^-2 s^-1","photon_index":"1.2 +/- 0.1"},{"predicted_count_rate":"2.7e-4 counts/s","predicted_flux_observed":"1.8e-13 ergs cm^-2 s^-1","predicted_flux_unabsorbed":"2.0e-13 ergs cm^-2 s^-1"}]},"authors":{"affiliations":["PSU","U. Leicester"],"authors":["J. Racusin","J. Kennea","C. Pagani","L. Vetere","P. Evans"],"institutions":["Swift XRT team"],"universities":["Penn State University","University of Leicester"]},"telescopes":{"facilities":[],"instruments":["Swift-XRT","UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"racusin@astro.psu.edu","institution":"PSU","name":"Judith Racusin"},"coordinates":{},"detectionTime":"2007-07-15T03:33:26.000Z","event":"GRB070714B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6627\nSUBJECT: GRB070714B: Swift-XRT refined analysis\nDATE: 07/07/15 03:33:26 GMT\nFROM: Judith Racusin at PSU  <racusin@astro.psu.edu>\n\nJ. Racusin, J. Kennea, C. Pagani, L. Vetere (PSU), and P. Evans (U.\nLeicester) report on behalf of the Swift/XRT team:\n\nWe have analyzed the first 15 ks of Swift XRT PC and WT data from GRB\n070714B (Racusin et al., GCN 6620).  Using 770 s of overlapping XRT Photon\nCounting mode and UVOT V-band data, we find an astrometrically corrected\nX-ray position (using the XRT-UVOT alignment and matching UVOT field\nsources to the USNO-B1 catalogue): RA, Dec = 57.84287, 28.29782 which is\nequivalent to:\n\nRA (J2000):  03h 51m 22.29s\nDec (J2000): +28d 17'' 52.2\"\n\nwith an uncertainty of 1.8 arcsec (90% confidence, radius).  This is 35\narcsec from the refined BAT position (Barbier et al., GCN 6623), and 1.4\narcsec from the Liverpool optical afterglow candidate (Melandri et al.,\nGCN 6621).\n\nThe XRT light curve shows a fading behavior with super-imposed small\nflaring.  The light curve can be fit with a power-law beginning with a\nsteep decay with a slope of 2.49 +/- 0.18 followed by a plateau beginning\nat 413s +/- 50s with a slope of 0.60 +/- 0.29 until another break at 1187\n+/- 270s with a decay of 1.73 +/- 0.11.\n\nThe X-ray PC and WT spectrum is well fit by an absorbed power law with a\nphoton index for 1.2 +/- 0.1 and a column density of 13 +/- 3 e20 cm^-2 in\nexcess of the galactic value (6.4e20 cm-2).  The absorbed (unabsorbed)\n0.3-10.0 keV flux of the WT spectrum is 9.2e-10 (1.0e-9) erg cm^-2s^-1 and\nthe flux of the PC spectrum is 3.4e-12 (3.7e-12) ergs cm^-2 s^-1.\n\nAssuming the source continues to decay at the same rate, we predict an XRT\ncount rate of 2.7e-4 counts/s at T0+24 hours, which corresponds to an\nobserved (unabsorbed) flux of 1.8e-13 (2.0e-13) ergs cm^-2 s^-1.\n\nThis circular is an official product of the Swift XRT team."}', 'Swift-XRT team reports updated analysis of GRB070714B, identifying an X-ray position with an uncertainty of 1.8 arcsec from the refined BAT position. The XRT light curve shows a complex decay behavior with multiple breaks and a power-law fit. The X-ray spectrum is well fit by an absorbed power law with a high column density. Predicted count rate and flux at T0+24 hours are provided.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6626', 'gcn', 'GRB 070707', '2007-07-15T00:42:06.000Z', '{"measurements":{"dec":null,"distance":null,"duration":11.1,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null,"tables":[{"end_time_after_trigger":516600,"error_initial_observed_count_rate":0.0013,"error_powerlaw_index":0.6,"exposure_time":11100,"initial_observed_count_rate":0.0066,"lower_error_0.3-10_kev_flux":1.4e-13,"observed_0.3-10_kev_flux":2.4e-13,"observed_count_rate_upper_limit":0.0011,"powerlaw_index":2.7,"start_time_after_trigger":325100,"unit_initial_observed_count_rate":"count/s","unit_observed_0.3-10_kev_flux":"ergs cm^-2 s^-1","unit_observed_count_rate_upper_limit":"count/s","upper_error_0.3-10_kev_flux":2e-13}]},"authors":{"affiliations":["U. Leicester","GSFC"],"authors":["A.P. Beardmore","A. Parsons"],"institutions":["GSFC"],"universities":["University of Leicester"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift-XRT"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"apb@star.le.ac.uk","institution":"U Leicester","name":"Andy Beardmore"},"coordinates":{},"detectionTime":"2007-07-15T00:42:06.000Z","event":"GRB 070707","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6626\nSUBJECT: GRB 070707: Swift-XRT follow-up observations\nDATE: 07/07/15 00:42:06 GMT\nFROM: Andy Beardmore at U Leicester  <apb@star.le.ac.uk>\n\nA.P. Beardmore (U. Leicester) and A. Parsons (GSFC) report on behalf of\nthe Swift-XRT team:\n\nThe Swift XRT obtained further follow-up observations of \nGRB 070707 (Beckmann et al., GCN 6606; Gotz et al., GCN 6607). In an\n11.1 ks exposure photon counting mode image taken from 325.1 ks to \n516.6 ks after the trigger, and using the same 10 pixel radius extraction\nregion as before, we find a 3 sigma upper limit to the observed count\nrate of 0.0011 count/s. When compared with the initial XRT detection\n(Beardmore et al., GCN 6610) of 0.0066 +/- 0.0013 count/s (where the\nerror bar is a 1 sigma estimate) we conclude the source has faded and\nthat it was the X-ray counterpart to the GRB.\n\nAn absorbed powerlaw fit to the photon energy distribution of the\nsource observed during the first XRT observation (from 31.8 ks to \n54.1 ks after the trigger), using Cash statistics and with the NH fixed\nat the (Dickey and Lockman) galactic value of 6e20cm^-2, gave a powerlaw\nindex of 2.7 +/- 0.6. The observed 0.3-10 keV flux was \n(2.4 +2.0 -1.4)e-13 ergs cm^-2 s^-1.\n\nThis circular is an official product of the Swift-XRT team."}', 'The Swift-XRT team reported follow-up observations of GRB 070707, finding that the source had faded since the initial detection. An upper limit of 0.0011 count/s was found for the observed count rate, compared to the initial rate of 0.0066 count/s. An absorbed powerlaw fit to the X-ray data from the first observation gave a powerlaw index of 2.7 +/- 0.6 and an observed 0.3-10 keV flux of (2.4 +2.0 -1.4)e-13 ergs cm^-2 s^-1.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6625', 'gcn', 'GRB 070714b', '2007-07-14T23:25:42.000Z', '{"measurements":{"dec":"+28:17:45.5","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"R":22.7},"other_measurements":{"J-K":0.5},"ra":"03:51:21.24","redshift":null,"tables":[]},"authors":{"affiliations":["UC Berkeley","LBL"],"authors":["J. S. Bloom","P. Nugent"],"institutions":["LBL"],"universities":["UC Berkeley"]},"telescopes":{"facilities":[],"instruments":["NEAT collaboration","Palomar-Quest Consortium"],"observatories":[],"telescopes":["Palomar Oschin Schmidt telescope"]},"urls":[],"basic_data":{"author":{"email":"jbloom@astron.berkeley.edu","institution":"UC Berkeley","name":"Josh Bloom"},"coordinates":{},"detectionTime":"2007-07-14T23:25:42.000Z","event":"GRB 070714b","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6625\nSUBJECT: GRB 070714b (\"Bastille\"): Optical Pre-Imaging  (Clarification)\nDATE: 07/07/14 23:25:42 GMT\nFROM: Josh Bloom at UC Berkeley  <jbloom@astron.berkeley.edu>\n\nJ. S. Bloom notes:\n\n\"We clarify that the imaging information reported in the circular GCN  \n6624 (Nugent & Bloom) refers to GRB 070714b (short-hard burst;  \nBarbier et al. 6623; trigger #284856) and not GRB 070714a (short and  \nXRF-like; Barthelmy et al. 6622; trigger #284850).  We apologize for  \nany confusion and thank S. Barthlemy for alerting us to the citation  \nerror in the previous circular.\n\nThe corrected circular should read:\n\nGRB 070714b (\"Bastille\"): Optical Pre-Imaging\n\nP. Nugent (LBL) and J. S. Bloom (UC Berkeley) report:\n\n\"We have created a stacked image through the co-addition of 8\nunfiltered images taken by the NEAT collaboration and 51 images in\nthe RG610 filter taken by the Palomar-Quest Consortium at the Palomar\nOschin Schmidt telescope (obtained from 2002-2006), of what is being\ncalled a short-hard burst (SHB) 070714B (Barbier et al.; GCN #6623).\nThe stacked image is significantly deeper than the DSS (3 sigma limit\nof R~22.7 mag). There is no source at the position of the proposed\ncounterpart (Melandri et al. GCN #6621). Since this Liverpool\nTelescope source was detected in twilight, it was likely seen near\nthe DSS limit (or brighter) and thus, while we cannot say for sure\n(since no magnitude was given in GCN #6621), the absence of a\nsimilarly bright source in our image suggests that the Melandri et\nal. source was indeed the afterglow.\n\nNote that the source @ position RA = 03:51:21.24, DEC = +28:17:45.5\nis in the 2MASS catalog and is blue (J - K = 0.5 mag).\n\nThis message may be cited.\""}', 'Astronomical alert: GRB 070714b ("Bastille"): Optical Pre-Imaging  (Clarification)', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6624', 'gcn', 'GRB 070714', '2007-07-14T22:47:19.000Z', '{"measurements":{"dec":"+28:17:45.5","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"R":22.7},"other_measurements":{"J-K":0.5},"ra":"03:51:21.24","redshift":null,"tables":[]},"authors":{"affiliations":["LBL","UC Berkeley"],"authors":["P. Nugent","J. S. Bloom"],"institutions":["NEAT collaboration","Palomar-Quest Consortium","Liverpool Telescope"],"universities":["University of California, Berkeley"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Palomar-Quest Consortium","Liverpool Telescope"],"telescopes":["Palomar Oschin Schmidt telescope"]},"urls":["http://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6622","http://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6621"],"basic_data":{"author":{"email":"jbloom@astron.berkeley.edu","institution":"UC Berkeley","name":"Josh Bloom"},"coordinates":{},"detectionTime":"2007-07-14T22:47:19.000Z","event":"GRB 070714","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6624\nSUBJECT: GRB 070714 (\"Bastille\"): Optical Pre-Imaging\nDATE: 07/07/14 22:47:19 GMT\nFROM: Josh Bloom at UC Berkeley  <jbloom@astron.berkeley.edu>\n\nP. Nugent (LBL) and J. S. Bloom (UC Berkeley) report:\n\nWe have created a stacked image through the co-addition of 8  \nunfiltered images taken by the NEAT collaboration and 51 images in  \nthe RG610 filter taken by the Palomar-Quest Consortium at the Palomar  \nOschin Schmidt telescope (obtained from 2002-2006), of what is being  \ncalled a short-hard burst (SHB) 070714A (Barbier et al.; GCN #6622).  \nThe stacked image is significantly deeper than the DSS (3 sigma limit  \nof R~22.7 mag). There is no source at the position of the proposed  \ncounterpart (Melandri et al. GCN #6621). Since this Liverpool  \nTelescope source was detected in twilight, it was likely seen near  \nthe DSS limit (or brighter) and thus, while we cannot say for sure  \n(since no magnitude was given in GCN #6621), the absence of a  \nsimilarly bright source in our image suggests that the Melandri et  \nal. source was indeed the afterglow.\n\nNote that the source @ position RA = 03:51:21.24, DEC = +28:17:45.5  \nis in the 2MASS catalog and is blue (J - K = 0.5 mag).\n\nThis message may be cited."}', 'Astronomical alert: GRB 070714 ("Bastille"): Optical Pre-Imaging', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6623', 'gcn', 'GRB 070714B', '2007-07-14T21:47:27.000Z', '{"measurements":{"dec":"28d 17'' 37\"","distance":null,"duration":"64 +- 5 sec","energy":null,"fluence":"7.2 +- 0.9 x 10^-7 erg/cm2","magnitude":null,"other_measurements":{"extended_emission_duration":"from T+20 sec to T+70 (and possibly T+100) sec","initial_spike_fluence":"5.1 +-0.3 x 10^-7 erg/cm2","initial_spike_photon_index":"0.99 +- 0.08","partial_coding":"93%","peak_photon_flux":"2.7 +- 0.2 ph/cm2/sec","time_averaged_spectrum_index":"1.36 +- 0.19"},"ra":"3h 51m 24.8s","redshift":null,"tables":[]},"authors":{"affiliations":["NASA/GSFC","UMBC","LANL","GSFC/UMD","ORAU","GSFC/ISAS","GWU"],"authors":["L. Barbier","S. D. Barthelmy","J. Cummings","E. Fenimore","N. Gehrels","H. Krimm","C. Markwardt","D. Palmer","A. Parsons","J. Racusin","T. Sakamoto","G. Sato","M. Stamatikos","J. Tueller","T. Ukwatta"],"institutions":["NASA/GSFC","UMBC","LANL","GSFC/UMD","ORAU","GSFC/ISAS","GWU"],"universities":["GSFC","UMBC","LANL","UMD","ORAU","ISAS","GWU"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"takanori@milkyway.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Takanori Sakamoto"},"coordinates":{},"detectionTime":"2007-07-14T21:47:27.000Z","event":"GRB 070714B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6623\nSUBJECT: GRB 070714B, Swift-BAT refined analysis of the short hard burst\nDATE: 07/07/14 21:47:27 GMT\nFROM: Takanori Sakamoto at NASA/GSFC  <takanori@milkyway.gsfc.nasa.gov>\n\nL. Barbier (GSFC), S. D. Barthelmy (GSFC), J. Cummings (GSFC/UMBC),\nE. Fenimore (LANL), N. Gehrels (GSFC), H. Krimm (GSFC/USRA),\nC. Markwardt (GSFC/UMD), D. Palmer (LANL), A. Parsons (GSFC),\nJ. Racusin (PSU), T. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS),\nM. Stamatikos (GSFC/ORAU), J. Tueller (GSFC), T. Ukwatta (GWU)\n(i.e. the Swift-BAT team):\n\nUsing the data set from T-120 to T+182 sec from recent telemetry downlinks,\nwe report further analysis of BAT GRB 070714B (trigger #284856)\n(Racusin, et al., GCN Circ. 6620).  The BAT ground-calculated position is\nRA, Dec = 57.853, 28.294 deg  which is\n   RA(J2000)  =  3h 51m 24.8s\n   Dec(J2000) = 28d 17'' 37\"\nwith an uncertainty of 1.4 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 93%.\n\nThe BAT mask-weighted light curve shows multiple short spikes starting from \nT-0.8 sec with a duration of 3 sec.  There is extended softer emission from \nT+20 sec to T+70 (and possibly T+100) sec.  T90 (15-350 keV) is 64 +- 5 sec \n(estimated error including systematics).  The light curve looks similar to \nprevious short bursts such as GRB 050724 with a short-hard initial episode \nfollowed by a softer extended episode, so we think it is likely that this \nburst is in the short category.\n\nThe time-averaged spectrum from T-0.8 to T+65.6 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n1.36 +- 0.19.  The fluence in the 15-150 keV band is 7.2 +- 0.9 x 10^-7 erg/cm2.\nThe 1-sec peak photon flux measured from T-0.39 sec in the 15-150 keV band\nis 2.7 +- 0.2 ph/cm2/sec.  Separating out the initial \"spike\" of emission\n(from T-0.8 to T+2 sec), the photon index in a simple power-law fit is\n0.99 +- 0.08.  The fluence in the 15-150 keV band of this part is\n5.1 +-0.3 x 10^-7 erg/cm2.  All the quoted errors are at the 90% confidence\nlevel."}', 'The Swift-BAT team reported a refined analysis of GRB 070714B, a short gamma-ray burst with a duration of approximately 64 seconds and a time-averaged power-law index of 1.36. The burst exhibited multiple short spikes and extended softer emission, similar to previous short bursts. The position of the burst was determined to be RA, Dec = 57.853, 28.294 deg with an uncertainty of 1.4 arcmin.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6622', 'gcn', 'GRB 070714A', '2007-07-14T19:38:35.000Z', '{"measurements":{"dec":"30.241 deg","distance":null,"duration":"2.0 +- 0.3 sec","energy":null,"fluence":"1.5 +- 0.2 x 10^-7 erg/cm2","magnitude":null,"other_measurements":{"1_sec_peak_photon_flux":"1.8 +- 0.2 ph/cm2/sec","fluence_ratio_25_50_kev_to_50_100_kev":"1.52","power_law_index":"2.6 +- 0.2"},"ra":"42.933 deg","redshift":null,"tables":[]},"authors":{"affiliations":["NASA/GSFC","UMBC","LANL","GSFC/USRA","GSFC/UMD","GSFC/ORAU","GSFC"],"authors":["S.D. Barthelmy","L. Barbier","J. Cummings","E. Fenimore","N. Gehrels","D. Grupe","H. Krimm","C. Markwardt","D. Palmer","A. Parsons","T. Sakamoto","G. Sato","M. Stamatikos","J. Tueller","T. Ukwatta"],"institutions":["NASA/GSFC","UMBC","LANL","GSFC/USRA","GSFC/ORAU","GWU"],"universities":["GSFC","UMBC","LANL","ISAS","ORAU","GWU"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-07-14T19:38:35.000Z","event":"GRB 070714A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6622\nSUBJECT: GRB 070714A, Swift-BAT refined analysis\nDATE: 07/07/14 19:38:35 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nS.D. Barthelmy (GSFC), L. Barbier (GSFC), J. Cummings (GSFC/UMBC),\nE. Fenimore (LANL), N. Gehrels (GSFC), D. Grupe (PSU),\nH. Krimm (GSFC/USRA), C. Markwardt (GSFC/UMD), D. Palmer (LANL),\nA. Parsons (GSFC), T. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS),\nM. Stamatikos (GSFC/ORAU), J. Tueller (GSFC), T. Ukwatta (GWU)\n(i.e. the Swift-BAT team):\n\nUsing the data set from T-240 to T+962 sec from recent telemetry downlinks,\nwe report further analysis of BAT GRB 070714A (trigger #284850)\n(Grupe, et al., GCN Circ. 6619).  The BAT ground-calculated position is\nRA, Dec = 42.933, 30.241 deg  which is\n   RA(J2000)  =  2h 51m 43.8s\n   Dec(J2000) = 30d 14'' 28\"\nwith an uncertainty of 1.3 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 96%.\n\nThe mask-weight lightcurve shows a single peak starting at T+0, peaking at\nT+0.7, and ending at T+2 sec, where the rise time is a little faster than\nthe decay.  T90 (15-350 keV) is 2.0 +- 0.3 sec (estimated error including\nsystematics).\n\nThe time-averaged spectrum from T-0.7 to T+2.3 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n2.6 +- 0.2.  The fluence in the 15-150 keV band is 1.5 +- 0.2 x 10^-7 erg/cm2.\nThe 1-sec peak photon flux measured from T+0.30 sec in the 15-150 keV band\nis 1.8 +- 0.2 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel.\n\nWe note that the fluence ratio in a simple power-law fit between the\n25-50 keV band and the 50-100 keV band is 1.52.  This fluence ratio is larger\nthan 1.32, which can be achieved in the Band function of alpha=-1.0, beta=-2.5,\nand Epeak=30 keV.  Thus, preliminary analysis shows that Epeak of the burst\nis very likely around or below 30 keV.  Therefore the burst can be classified\nas an X-ray flash."}', 'The Swift-BAT team has provided a refined analysis of GRB 070714A, reporting a position with an uncertainty of 1.3 arcmin, a single peaked light curve with a duration of 2.0 +- 0.3 sec, a time-averaged power-law spectrum with an index of 2.6 +- 0.2, and a fluence of 1.5 +- 0.2 x 10^-7 erg/cm2 in the 15-150 keV band. Preliminary analysis suggests that Epeak, the energy peak of the burst, is likely below 30 keV, classifying it as an X-ray flash.', 0.95, ARRAY[], NOW(), NOW());